def corridor_servo_command(info, args):
    """Parking-slot corridor controller using side lines instead of polygon-derived center."""
    metrics = corridor_metrics(info, args)
    angle_err = _shortest_angle_deg(info["axis_angle_px_deg"], args.pixel_target_angle_deg)
    abs_x = abs(metrics["corridor_x_err"])
    abs_angle = abs(angle_err)
    closeness = metrics["closeness"]

    if metrics["line_risk"]:
        return {
            "state": "LINE_RISK_%s" % (metrics["risk_side"] or "UNKNOWN"),
            "action": "STOP",
            "cmd": "STOP",
            "step": 0.0,
            "servo": SERVO_CENTER,
            "reason": "corridor_line_margin_too_small",
            "corridor": metrics,
            "binding": {
                "angle_err": round(angle_err, 3),
                "distance_cm": 0.0,
                "distance_reason": "line_risk_stop",
                "gear": 1,
                "gear_reason": "stopped",
            },
        }

    aligned_x = abs_x <= args.corridor_x_tolerance_px
    aligned_angle = abs_angle <= args.pixel_angle_tolerance_deg
    if closeness >= args.corridor_final_stop_closeness and aligned_x and aligned_angle:
        return {
            "state": "FINAL_STOP",
            "action": "STOP",
            "cmd": "STOP",
            "step": 0.0,
            "servo": SERVO_CENTER,
            "reason": "corridor_aligned_near",
            "corridor": metrics,
            "binding": {
                "angle_err": round(angle_err, 3),
                "distance_cm": 0.0,
                "distance_reason": "aligned_final_stop",
                "gear": 1,
                "gear_reason": "stopped",
            },
        }

    if closeness < args.corridor_approach_closeness:
        state = "APPROACH"
        step = args.corridor_approach_d_cm
        kx = args.corridor_kx
        max_offset = args.corridor_approach_max_steer_offset_deg
        distance_reason = "far_corridor_approach"
    elif not aligned_x or not aligned_angle:
        state = "ALIGN_CORRIDOR"
        step = args.corridor_align_d_cm
        kx = args.corridor_near_kx
        max_offset = args.corridor_align_max_steer_offset_deg
        distance_reason = "near_corridor_alignment"
    else:
        state = "ENTER_SLOT"
        step = args.corridor_enter_d_cm
        kx = args.corridor_near_kx
        max_offset = args.corridor_enter_max_steer_offset_deg
        distance_reason = "aligned_slot_entry"

    raw_offset = args.corridor_steer_sign * (kx * metrics["corridor_x_err"] + args.corridor_ka * angle_err)
    steer_offset = clamp(raw_offset, -max_offset, max_offset)
    servo = int(round(clamp(SERVO_CENTER + steer_offset * STEERING_SIGN, SERVO_MIN, SERVO_MAX)))
    step = round(clamp(step, args.corridor_min_command_abs_d_cm, args.pixel_max_command_abs_d_cm), 1)
    gear = 1

    if abs(servo - SERVO_CENTER) <= STEER_DEADZONE_DEG:
        cmd = center_arc_command(-step, gear)
        servo = SERVO_CENTER
        action = "ARC"
    else:
        cmd = "ARC D=%.1f STE=%d V=%d" % (-step, servo, gear)
        action = "ARC"

    return {
        "state": state,
        "action": action,
        "cmd": cmd,
        "step": step,
        "servo": servo,
        "steer_dir": 0.0 if servo == SERVO_CENTER else (1.0 if servo > SERVO_CENTER else -1.0),
        "reason": "corridor_x_error" if not aligned_x else ("corridor_angle_error" if not aligned_angle else "corridor_enter"),
        "corridor": metrics,
        "binding": {
            "corridor_x_err": metrics["corridor_x_err"],
            "angle_err": round(angle_err, 3),
            "raw_steer_offset": round(raw_offset, 3),
            "corridor_steer_sign": args.corridor_steer_sign,
            "steer_offset": round(servo - SERVO_CENTER, 3),
            "servo": servo,
            "distance_cm": step,
            "distance_reason": distance_reason,
            "closeness": closeness,
            "gear": gear,
            "gear_reason": "corridor_safety_limited",
            "max_steer_offset": max_offset,
        },
    }


def normalized_corridor_servo_command(info, args):
    """Scale-invariant corridor controller.

    The controller uses the detected slot width as its unit. This avoids tuning
    directly against one physical parking-box size: large and small valid slots
    produce comparable normalized x error and line-margin values.
    """
    metrics = corridor_metrics(info, args)
    angle_err = _shortest_angle_deg(info["axis_angle_px_deg"], args.pixel_target_angle_deg)
    x_norm = metrics["corridor_x_err_norm"]
    entry_norm = metrics["entry_x_err_norm"]
    margin_norm = metrics["min_margin_norm"]
    abs_x_norm = abs(x_norm)
    abs_angle = abs(angle_err)
    closeness = metrics["closeness"]

    norm_line_risk = margin_norm < args.normalized_min_margin
    if norm_line_risk:
        risk_side = "LEFT" if metrics["left_margin_norm"] < metrics["right_margin_norm"] else "RIGHT"
        return {
            "state": "NORM_LINE_RISK_%s" % risk_side,
            "action": "STOP",
            "cmd": "STOP",
            "step": 0.0,
            "servo": SERVO_CENTER,
            "reason": "normalized_line_margin_too_small",
            "corridor": metrics,
            "binding": {
                "corridor_x_err_norm": round(x_norm, 4),
                "entry_x_err_norm": round(entry_norm, 4),
                "min_margin_norm": round(margin_norm, 4),
                "angle_err": round(angle_err, 3),
                "distance_cm": 0.0,
                "distance_reason": "normalized_line_risk_stop",
                "gear": 1,
                "gear_reason": "stopped",
            },
        }

    aligned_x = abs_x_norm <= args.normalized_x_tolerance
    aligned_angle = abs_angle <= args.pixel_angle_tolerance_deg
    if closeness >= args.normalized_final_stop_closeness and aligned_x and aligned_angle:
        return {
            "state": "NORM_FINAL_STOP",
            "action": "STOP",
            "cmd": "STOP",
            "step": 0.0,
            "servo": SERVO_CENTER,
            "reason": "normalized_corridor_aligned_near",
            "corridor": metrics,
            "binding": {
                "corridor_x_err_norm": round(x_norm, 4),
                "entry_x_err_norm": round(entry_norm, 4),
                "min_margin_norm": round(margin_norm, 4),
                "angle_err": round(angle_err, 3),
                "distance_cm": 0.0,
                "distance_reason": "aligned_final_stop",
                "gear": 1,
                "gear_reason": "stopped",
            },
        }

    if closeness < args.normalized_approach_closeness:
        state = "NORM_APPROACH"
        step = args.normalized_approach_d_cm
        max_offset = args.normalized_approach_max_steer_offset_deg
        distance_reason = "normalized_far_approach"
    elif not aligned_x or not aligned_angle:
        state = "NORM_ALIGN_CORRIDOR"
        step = args.normalized_align_d_cm
        max_offset = args.normalized_align_max_steer_offset_deg
        distance_reason = "normalized_alignment"
    else:
        state = "NORM_ENTER_SLOT"
        step = args.normalized_enter_d_cm
        max_offset = args.normalized_enter_max_steer_offset_deg
        distance_reason = "normalized_enter"

    raw_offset = args.normalized_steer_sign * (
        args.normalized_kx * x_norm +
        args.normalized_entry_kx * entry_norm +
        args.normalized_ka * angle_err
    )
    if aligned_x and aligned_angle:
        raw_offset = 0.0
    steer_offset = clamp(raw_offset, -max_offset, max_offset)
    if (not aligned_x or not aligned_angle) and abs(steer_offset) > STEER_DEADZONE_DEG:
        min_offset = min(abs(max_offset), max(0.0, args.normalized_min_steer_offset_deg))
        if min_offset > 0.0 and abs(steer_offset) < min_offset:
            steer_offset = min_offset if steer_offset > 0 else -min_offset
    servo = int(round(clamp(SERVO_CENTER + steer_offset * STEERING_SIGN, SERVO_MIN, SERVO_MAX)))
    step = round(clamp(step, args.normalized_min_command_abs_d_cm, args.pixel_max_command_abs_d_cm), 1)
    gear = 1

    if abs(servo - SERVO_CENTER) <= STEER_DEADZONE_DEG:
        cmd = center_arc_command(-step, gear)
        servo = SERVO_CENTER
        action = "ARC"
    else:
        cmd = "ARC D=%.1f STE=%d V=%d" % (-step, servo, gear)
        action = "ARC"

    return {
        "state": state,
        "action": action,
        "cmd": cmd,
        "step": step,
        "servo": servo,
        "steer_dir": 0.0 if servo == SERVO_CENTER else (1.0 if servo > SERVO_CENTER else -1.0),
        "reason": "normalized_x_error" if not aligned_x else ("normalized_angle_error" if not aligned_angle else "normalized_enter"),
        "corridor": metrics,
        "binding": {
            "corridor_x_err_norm": round(x_norm, 4),
            "entry_x_err_norm": round(entry_norm, 4),
            "min_margin_norm": round(margin_norm, 4),
            "angle_err": round(angle_err, 3),
            "raw_steer_offset": round(raw_offset, 3),
            "min_steer_offset": round(args.normalized_min_steer_offset_deg, 3),
            "normalized_steer_sign": args.normalized_steer_sign,
            "steer_offset": round(servo - SERVO_CENTER, 3),
            "servo": servo,
            "distance_cm": step,
            "distance_reason": distance_reason,
            "closeness": closeness,
            "gear": gear,
            "gear_reason": "normalized_corridor_safety_limited",
            "max_steer_offset": max_offset,
            "slot_width_px": metrics["slot_width_px"],
        },
    }


def _path_cmd(kind, step_cm, servo=None, gear=GEAR):
    step_cm = round(float(step_cm), 1)
    if kind == "MOVE" or servo is None or abs(float(servo) - SERVO_CENTER) <= STEER_DEADZONE_DEG:
        return {
            "action": "ARC",
            "cmd": center_arc_command(-step_cm, gear),
            "step": step_cm,
            "servo": SERVO_CENTER,
            "straight_like": True,
        }
    servo = int(round(clamp(float(servo), SERVO_MIN, SERVO_MAX)))
    return {
        "action": "ARC",
        "cmd": "ARC D=%.1f STE=%d V=%d" % (-step_cm, servo, gear),
        "step": step_cm,
        "servo": servo,
    }


def _path_build_template(template_id, commands, reason):
    total_cm = round(sum(c["step"] for c in commands), 1)
    return {
        "template_id": template_id,
        "reason": reason,
        "total_cm": total_cm,
        "commands": commands,
    }


def _path_score_template(template, desired_offset, abs_offset, closeness, metrics, args):
    commands = template["commands"]
    steer_offsets = [
        c["servo"] - SERVO_CENTER
        for c in commands
        if c["action"] == "ARC" and abs(c["servo"] - SERVO_CENTER) > STEER_DEADZONE_DEG
    ]
    arc_count = len(steer_offsets)
    same_side_count = sum(1 for off in steer_offsets if off * desired_offset > 0.0)
    wrong_side_count = sum(1 for off in steer_offsets if off * desired_offset < 0.0)
    straight_only = arc_count == 0

    if abs_offset <= args.path_straight_offset_deg:
        side_cost = 0.0 if straight_only else 8.0 + 0.4 * arc_count
    elif straight_only:
        side_cost = abs_offset * args.path_straight_cost_gain
    elif same_side_count > 0 and wrong_side_count == 0:
        side_cost = max(0.0, abs_offset - max(abs(o) for o in steer_offsets)) * 0.15
    else:
        side_cost = args.path_wrong_side_penalty + abs_offset

    if abs_offset >= args.path_hard_offset_threshold_deg:
        target_arcs = 3
    elif abs_offset >= args.path_mid_offset_threshold_deg:
        target_arcs = 2
    elif abs_offset >= args.path_straight_offset_deg:
        target_arcs = 1
    else:
        target_arcs = 0
    arc_count_cost = abs(arc_count - target_arcs) * args.path_arc_count_penalty

    total_cm = template["total_cm"]
    target_total = args.path_near_total_cm if closeness >= args.path_near_closeness else args.path_far_total_cm
    distance_cost = abs(total_cm - target_total) * args.path_distance_cost_gain

    margin_norm = float(metrics["min_margin_norm"])
    margin_cost = 0.0
    if margin_norm < args.path_prefer_margin_norm:
        margin_cost = (args.path_prefer_margin_norm - margin_norm) * args.path_margin_cost_gain

    score = side_cost + arc_count_cost + distance_cost + margin_cost
    return {
        "cost": round(score, 3),
        "components": {
            "side_cost": round(side_cost, 3),
            "arc_count_cost": round(arc_count_cost, 3),
            "distance_cost": round(distance_cost, 3),
            "margin_cost": round(margin_cost, 3),
        },
        "arc_count": arc_count,
        "same_side_count": same_side_count,
        "wrong_side_count": wrong_side_count,
        "total_cm": total_cm,
    }


def path_template_planner_command(info, args):
    """Choose a short full-path template from one stable slot observation.

    This is deliberately more discrete than normalized_corridor_servo: it ranks
    whole command sequences, logs the selected path, then returns only the first
    command so the outer loop can re-observe and replan after every movement.
    """
    metrics = corridor_metrics(info, args)
    angle_err = _shortest_angle_deg(info["axis_angle_px_deg"], args.pixel_target_angle_deg)
    x_norm = float(metrics["corridor_x_err_norm"])
    entry_norm = float(metrics["entry_x_err_norm"])
    margin_norm = float(metrics["min_margin_norm"])
    closeness = float(metrics["closeness"])

    if margin_norm < args.path_template_min_margin_norm:
        return {
            "state": "PATH_LINE_RISK_%s" % (metrics["risk_side"] or "UNKNOWN"),
            "action": "STOP",
            "cmd": "STOP",
            "step": 0.0,
            "servo": SERVO_CENTER,
            "reason": "path_template_margin_too_small",
            "corridor": metrics,
            "binding": {
                "slot_x_err_norm": round(x_norm, 4),
                "slot_entry_x_err_norm": round(entry_norm, 4),
                "min_margin_norm": round(margin_norm, 4),
                "angle_err": round(angle_err, 3),
                "distance_cm": 0.0,
                "gear": GEAR,
                "gear_reason": "stopped",
            },
            "path_plan": {
                "selected_template_id": "STOP",
                "reason": "path_template_margin_too_small",
                "candidates": [],
                "commands": [],
            },
        }

    if (closeness >= args.path_final_stop_closeness and
        abs(x_norm) <= args.path_x_deadband_norm and
        abs(angle_err) <= args.path_heading_deadband_deg):
        return {
            "state": "PATH_FINAL_STOP",
            "action": "STOP",
            "cmd": "STOP",
            "step": 0.0,
            "servo": SERVO_CENTER,
            "reason": "path_template_aligned_near",
            "corridor": metrics,
            "binding": {
                "slot_x_err_norm": round(x_norm, 4),
                "slot_entry_x_err_norm": round(entry_norm, 4),
                "min_margin_norm": round(margin_norm, 4),
                "angle_err": round(angle_err, 3),
                "distance_cm": 0.0,
                "gear": GEAR,
                "gear_reason": "stopped",
            },
            "path_plan": {
                "selected_template_id": "STOP",
                "reason": "path_template_aligned_near",
                "candidates": [],
                "commands": [],
            },
        }

    step = round(clamp(args.path_step_cm, args.normalized_min_command_abs_d_cm,
                       args.pixel_max_command_abs_d_cm), 1)
    max_commands = max(1, int(args.path_max_commands))
    high_servo = int(round(clamp(args.path_arc_steer_high, SERVO_MIN, SERVO_MAX)))
    low_servo = int(round(clamp(args.path_arc_steer_low, SERVO_MIN, SERVO_MAX)))
    straight = [_path_cmd("MOVE", step) for _ in range(max_commands)]
    high2 = [_path_cmd("ARC", step, high_servo) for _ in range(min(2, max_commands))]
    low2 = [_path_cmd("ARC", step, low_servo) for _ in range(min(2, max_commands))]
    high3 = [_path_cmd("ARC", step, high_servo) for _ in range(min(3, max_commands))]
    low3 = [_path_cmd("ARC", step, low_servo) for _ in range(min(3, max_commands))]
    templates = [
        _path_build_template("straight_entry", straight, "straight_reverse_path"),
        _path_build_template("steer_high_then_straight",
                             high2 + [_path_cmd("MOVE", step) for _ in range(max(0, max_commands - len(high2)))],
                             "positive_servo_arc_then_straight"),
        _path_build_template("steer_low_then_straight",
                             low2 + [_path_cmd("MOVE", step) for _ in range(max(0, max_commands - len(low2)))],
                             "negative_servo_arc_then_straight"),
        _path_build_template("steer_high_hold",
                             high3 + [_path_cmd("MOVE", step) for _ in range(max(0, max_commands - len(high3)))],
                             "positive_servo_longer_arc"),
        _path_build_template("steer_low_hold",
                             low3 + [_path_cmd("MOVE", step) for _ in range(max(0, max_commands - len(low3)))],
                             "negative_servo_longer_arc"),
    ]

    desired_offset = args.path_steer_sign * (
        args.path_kx * x_norm +
        args.path_entry_kx * entry_norm +
        args.path_ka * angle_err
    )
    desired_offset = clamp(desired_offset, -args.path_max_steer_offset_deg,
                           args.path_max_steer_offset_deg)
    if abs(x_norm) <= args.path_x_deadband_norm and abs(angle_err) <= args.path_heading_deadband_deg:
        desired_offset = 0.0
    abs_offset = abs(desired_offset)

    candidates = []
    for template in templates:
        scoring = _path_score_template(template, desired_offset, abs_offset, closeness, metrics, args)
        row = dict(template)
        row.update(scoring)
        candidates.append(row)
    candidates.sort(key=lambda r: (r["cost"], r["template_id"]))
    selected = candidates[0]
    first = selected["commands"][0]
    action = first["action"]
    servo = first["servo"]
    state = "PATH_REVERSE_STRAIGHT" if abs(servo - SERVO_CENTER) <= STEER_DEADZONE_DEG else (
        "PATH_REVERSE_STEER_HIGH" if servo > SERVO_CENTER else "PATH_REVERSE_STEER_LOW")

    return {
        "state": state,
        "action": action,
        "cmd": first["cmd"],
        "step": first["step"],
        "servo": servo,
        "steer_dir": 0.0 if servo == SERVO_CENTER else (1.0 if servo > SERVO_CENTER else -1.0),
        "reason": "path_template_best_sequence",
        "corridor": metrics,
        "binding": {
            "slot_x_err_norm": round(x_norm, 4),
            "slot_entry_x_err_norm": round(entry_norm, 4),
            "min_margin_norm": round(margin_norm, 4),
            "angle_err": round(angle_err, 3),
            "desired_steer_offset": round(desired_offset, 3),
            "path_steer_sign": args.path_steer_sign,
            "distance_cm": first["step"],
            "distance_reason": selected["template_id"],
            "closeness": closeness,
            "gear": GEAR,
            "gear_reason": "path_template_safety_limited",
            "selected_cost": selected["cost"],
        },
        "path_plan": {
            "schema": "parking_path_template_plan.v1",
            "selected_template_id": selected["template_id"],
            "selected_cost": selected["cost"],
            "desired_steer_offset": round(desired_offset, 3),
            "commands": selected["commands"],
            "candidates": candidates,
        },
    }


def _parse_motion_command_for_action(cmd):
    fields = _parse_motion_command_fields(cmd)
    return fields["kind"], fields["abs_d_cm"], int(round(fields["servo"]))


def _parse_motion_command_fields(cmd):
    parts = str(cmd or "").split()
    kind = parts[0].upper() if parts else ""
    kv = {}
    for part in parts[1:]:
        if "=" in part:
            k, v = part.split("=", 1)
            kv[k.upper()] = v
    try:
        d = float(kv.get("D", "0"))
    except (TypeError, ValueError):
        d = 0.0
    try:
        servo = float(kv.get("STE", str(SERVO_CENTER))) if kind == "ARC" else float(SERVO_CENTER)
    except (TypeError, ValueError):
        servo = float(SERVO_CENTER)
    try:
        velocity = int(float(kv.get("V", str(GEAR))))
    except (TypeError, ValueError):
        velocity = int(GEAR)
    return {
        "kind": kind,
        "d_cm": d,
        "abs_d_cm": abs(d),
        "servo": servo,
        "velocity": velocity,
    }


def _format_signed_d_cm(value):
    return "%+.1f" % float(value)


def _motion_command_with_signed_distance(kind, signed_distance_cm, servo=SERVO_CENTER, velocity=GEAR):
    kind = str(kind or "").upper()
    d_text = _format_signed_d_cm(signed_distance_cm)
    if kind == "MOVE":
        return "MOVE D=%s V=%d" % (d_text, int(velocity))
    return "ARC D=%s STE=%d V=%d" % (d_text, int(round(float(servo))), int(velocity))


def kinematic_action_tier(action):
    return (
        (action.get("binding") or {}).get("tier") or
        (action.get("kinematic_lattice") or {}).get("mode") or
        ""
    )


def make_kinematic_motion_record(action, visual_state, progress_cm, steps_after, total_after, source):
    fields = _parse_motion_command_fields(action.get("cmd", ""))
    commanded_step = planner_to_float(action.get("step"), fields["abs_d_cm"])
    if commanded_step <= 0.0:
        commanded_step = fields["abs_d_cm"]
    now = time.time()
    return {
        "schema": "kinematic_lattice_last_motion.v1",
        "time_unix": now,
        "visual_time_unix": now,
        "source": source,
        "cmd": action.get("cmd"),
        "action": action.get("action"),
        "reason": action.get("reason"),
        "tier": kinematic_action_tier(action),
        "command_fields": fields,
        "servo": fields["servo"],
        "commanded_step_cm": round(abs(commanded_step), 3),
        "odom_progress_cm": None if progress_cm is None else round(abs(float(progress_cm)), 3),
        "visual_state": deepcopy_jsonable(visual_state or {}),
        "steps_after": steps_after,
        "total_cm_after": round(float(total_after), 3),
    }


def refresh_kinematic_motion_visual(last_motion, visual_state):
    if not last_motion:
        return last_motion
    updated = dict(last_motion)
    updated["visual_state"] = deepcopy_jsonable(visual_state or {})
    updated["visual_time_unix"] = time.time()
    return updated


def vision_reacquire_recovery_review(last_motion, args, attempts, lost_elapsed, max_age_sec=None):
    state = (last_motion or {}).get("visual_state") or {}
    fields = (last_motion or {}).get("command_fields") or _parse_motion_command_fields(
        (last_motion or {}).get("cmd", ""))
    now = time.time()
    motion_time = planner_to_float((last_motion or {}).get("time_unix"), now)
    visual_time = planner_to_float((last_motion or {}).get("visual_time_unix"), motion_time)
    age_sec = max(0.0, now - visual_time)
    max_attempts = max(0, int(planner_to_float(
        getattr(args, "vision_reacquire_recovery_max_attempts", 1), 1)))
    if max_age_sec is None:
        max_age = max(0.1, planner_to_float(
            getattr(args, "vision_reacquire_recovery_max_age_sec", 20.0), 20.0))
    else:
        max_age = max(0.1, planner_to_float(max_age_sec, 20.0))
    max_last_step = max(0.0, planner_to_float(
        getattr(args, "vision_reacquire_recovery_max_last_step_cm", 3.5), 3.5))
    max_command = max(0.0, planner_to_float(
        getattr(args, "vision_reacquire_recovery_command_cm", 3.0), 3.0))
    min_command = max(0.0, planner_to_float(
        getattr(args, "vision_reacquire_recovery_min_command_cm", 1.0), 1.0))
    min_margin = planner_to_float(
        getattr(args, "vision_reacquire_recovery_min_margin_px", 120.0), 120.0)
    min_conf = planner_to_float(
        getattr(args, "vision_reacquire_recovery_min_confidence", 0.40), 0.40)
    min_visible = planner_to_float(
        getattr(args, "vision_reacquire_recovery_min_visible_ratio", 0.05), 0.05)
    min_pose = planner_to_float(
        getattr(args, "vision_reacquire_recovery_min_pose_quality", 0.60), 0.60)
    last_abs_d = planner_to_float(fields.get("abs_d_cm"), 0.0)
    last_step = planner_to_float((last_motion or {}).get("commanded_step_cm"), last_abs_d)
    if last_step <= 0.0:
        last_step = last_abs_d
    recovery_distance = min(max_command, last_abs_d if last_abs_d > 0 else last_step)
    kind = str(fields.get("kind") or "").upper()
    if kind not in ("MOVE", "ARC"):
        kind = "ARC"
    command = _motion_command_with_signed_distance(
        kind,
        recovery_distance,
        fields.get("servo", SERVO_CENTER),
        fields.get("velocity", GEAR),
    )
    checks = {
        "enabled": bool(getattr(args, "vision_reacquire_recovery_enable", True)),
        "attempt_budget_ok": int(attempts or 0) < max_attempts,
        "last_motion_available": bool(last_motion),
        "last_motion_was_reverse": str(fields.get("kind") or "").upper() in ("MOVE", "ARC") and
        planner_to_float(fields.get("d_cm"), 0.0) < -0.1,
        "last_step_short_enough": last_step <= max_last_step,
        "recovery_command_large_enough": recovery_distance >= min_command,
        "last_visual_fresh": age_sec <= max_age,
        "last_visual_stable": bool(state.get("stable")) and bool(state.get("stable_enough")),
        "last_line_risk_clear": not planner_to_bool(state.get("line_risk")),
        "last_margin_ok": planner_to_float(state.get("min_margin_px")) >= min_margin,
        "last_confidence_ok": planner_to_float(state.get("confidence")) >= min_conf,
        "last_visible_ratio_ok": planner_to_float(state.get("slot_visible_ratio"), 0.0) >= min_visible,
        "last_pose_quality_ok": planner_to_float(state.get("pose_quality")) >= min_pose,
    }
    failed = [name for name, ok in checks.items() if not ok]
    action = {
        "state": "KINEMATIC_LATTICE_REACQUIRE_RECOVERY",
        "action": kind,
        "cmd": command,
        "step": round(recovery_distance, 3),
        "servo": planner_to_float(fields.get("servo"), SERVO_CENTER),
        "steer_dir": 0.0 if abs(planner_to_float(fields.get("servo"), SERVO_CENTER) - SERVO_CENTER) < 1e-6
        else (1.0 if planner_to_float(fields.get("servo"), SERVO_CENTER) > SERVO_CENTER else -1.0),
        "reason": "undo_last_short_step_to_reacquire_visual",
        "binding": {
            "action_id": "vision_reacquire_recovery",
            "tier": "vision_reacquire_recovery",
            "source_last_tier": (last_motion or {}).get("tier"),
        },
    }
    return {
        "schema": "kinematic_lattice_vision_reacquire_recovery_review.v1",
        "pass": not failed,
        "reason": "ok" if not failed else "blocked_" + failed[0],
        "failed_checks": failed,
        "checks": checks,
        "attempts_used": int(attempts or 0),
        "max_attempts": max_attempts,
        "lost_elapsed_sec": round(float(lost_elapsed), 3),
        "last_motion_age_sec": round(age_sec, 3),
        "last_motion": {
            "cmd": (last_motion or {}).get("cmd"),
            "tier": (last_motion or {}).get("tier"),
            "command_fields": fields,
            "commanded_step_cm": round(last_step, 3),
            "odom_progress_cm": (last_motion or {}).get("odom_progress_cm"),
            "motion_age_sec": round(max(0.0, now - motion_time), 3),
            "visual_age_sec": round(age_sec, 3),
        },
        "metrics": {
            "min_margin_px": round(planner_to_float(state.get("min_margin_px")), 3),
            "confidence": round(planner_to_float(state.get("confidence")), 4),
            "slot_visible_ratio": round(planner_to_float(state.get("slot_visible_ratio"), 0.0), 6),
            "pose_quality": round(planner_to_float(state.get("pose_quality")), 3),
        },
        "recovery_action": action,
        "candidate_cmd": command,
        "commanded_step_cm": round(recovery_distance, 3),
    }


def read_vision_reacquire_token(path):
    if not path:
        return None
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except (OSError, ValueError):
        return None


def write_vision_reacquire_token(args, last_motion, reason, log_write=True):
    if not getattr(args, "vision_reacquire_token_enable", True):
        return {"enabled": False, "reason": "disabled"}
    path = getattr(args, "vision_reacquire_token", "")
    if not path:
        return {"enabled": False, "reason": "empty_path"}
    fields = (last_motion or {}).get("command_fields") or _parse_motion_command_fields(
        (last_motion or {}).get("cmd", ""))
    if not last_motion or planner_to_float(fields.get("d_cm"), 0.0) >= -0.1:
        return {"enabled": True, "written": False, "reason": "last_motion_not_reverse"}
    token = {
        "schema": "parking_vision_reacquire_token.v1",
        "time_unix": time.time(),
        "consumed": False,
        "reason": reason,
        "source_log_jsonl": getattr(args, "log_jsonl", ""),
        "last_motion": deepcopy_jsonable(last_motion),
    }
    event = {
        "event": "vision_reacquire_token_write",
        "path": path,
        "reason": reason,
        "candidate_cmd": (last_motion or {}).get("cmd"),
        "tier": (last_motion or {}).get("tier"),
        "written": False,
        "send_to_stm32": False,
        "motion_enabled": False,
        "actuator_control_allowed": False,
    }
    try:
        parent = os.path.dirname(path)
        if parent:
            os.makedirs(parent, exist_ok=True)
        tmp = "%s.tmp" % path
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(token, f, ensure_ascii=False, separators=(",", ":"))
            f.write("\n")
        os.replace(tmp, path)
        event["written"] = True
    except OSError as exc:
        event["error"] = str(exc)
    if log_write:
        log_event(getattr(args, "log_jsonl", ""), event)
    return event


def consume_vision_reacquire_token(args, token, reason, details=None):
    path = getattr(args, "vision_reacquire_token", "")
    event = {
        "event": "vision_reacquire_token_consume",
        "path": path,
        "reason": reason,
        "consumed": False,
        "send_to_stm32": False,
        "motion_enabled": False,
        "actuator_control_allowed": False,
    }
    if not path or not token:
        event["error"] = "missing_path_or_token"
        log_event(getattr(args, "log_jsonl", ""), event)
        return event
    updated = deepcopy_jsonable(token)
    updated["consumed"] = True
    updated["consumed_unix"] = time.time()
    updated["consume_reason"] = reason
    updated["consume_details"] = deepcopy_jsonable(details or {})
    try:
        tmp = "%s.tmp" % path
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(updated, f, ensure_ascii=False, separators=(",", ":"))
            f.write("\n")
        os.replace(tmp, path)
        event["consumed"] = True
    except OSError as exc:
        event["error"] = str(exc)
    log_event(getattr(args, "log_jsonl", ""), event)
    return event


def vision_reacquire_startup_token_review(args, attempts, lost_elapsed):
    path = getattr(args, "vision_reacquire_token", "")
    token = read_vision_reacquire_token(path)
    now = time.time()
    token_age = max(0.0, now - planner_to_float((token or {}).get("time_unix"), now))
    max_age = planner_to_float(getattr(args, "vision_reacquire_token_max_age_sec", 1800.0), 1800.0)
    checks = {
        "enabled": bool(getattr(args, "vision_reacquire_startup_enable", True)),
        "token_path_configured": bool(path),
        "token_available": bool(token),
        "schema_ok": (token or {}).get("schema") == "parking_vision_reacquire_token.v1",
        "not_consumed": not bool((token or {}).get("consumed", False)),
        "token_fresh": token_age <= max_age,
    }
    base_failed = [name for name, ok in checks.items() if not ok]
    recovery_review = {
        "schema": "kinematic_lattice_vision_reacquire_recovery_review.v1",
        "pass": False,
        "reason": "token_base_checks_failed",
        "failed_checks": base_failed,
    }
    if not base_failed:
        recovery_review = vision_reacquire_recovery_review(
            (token or {}).get("last_motion"),
            args,
            attempts,
            lost_elapsed,
            max_age_sec=max_age,
        )
    failed = list(base_failed)
    if not recovery_review.get("pass"):
        failed.append("recovery_review_pass")
    return {
        "schema": "kinematic_lattice_startup_vision_reacquire_token_review.v1",
        "pass": not failed,
        "reason": "ok" if not failed else "blocked_" + failed[0],
        "failed_checks": failed,
        "checks": checks,
        "token_path": path,
        "token_age_sec": round(token_age, 3),
        "token_max_age_sec": round(max_age, 3),
        "token": token if token and not base_failed else None,
        "recovery_review": recovery_review,
        "candidate_cmd": recovery_review.get("candidate_cmd"),
        "recovery_action": recovery_review.get("recovery_action"),
    }


def primitive_probe_command(_info, args):
    """Execute one operator-specified safe primitive after target stability."""
    cmd = parse_policy_actions(args.primitive_command, args.primitive_max_command_abs_d_cm)[0]
    kind, step, servo = _parse_motion_command_for_action(cmd)
    corridor = corridor_metrics(_info, args) if _info is not None else None
    return {
        "state": "PRIMITIVE_PROBE",
        "action": kind,
        "cmd": cmd,
        "step": round(step, 1),
        "servo": servo,
        "steer_dir": 0.0 if servo == SERVO_CENTER else (1.0 if servo > SERVO_CENTER else -1.0),
        "reason": "fixed_calibration_primitive",
        "corridor": corridor,
        "binding": {
            "distance_cm": round(step, 1),
            "distance_reason": "fixed_calibration_primitive",
            "servo": servo,
            "gear": GEAR,
            "gear_reason": "primitive_probe_safety_limited",
        },
    }


def execute_logged_motion(action, args, pose_fuser=None):
    cmd = action["cmd"]
    step = planner_to_float(action.get("step"))
    st = read_stat()
    imu_pre_review = stm32_stat_imu_review(st, require_ok=motion_requires_imu_ok(args))
    if not imu_pre_review.get("ok"):
        blocked = {
            "event": "stm32_motion_blocked_by_imu",
            "candidate_cmd": cmd,
            "phase": getattr(args, "_current_motion_phase", ""),
            "imu_review": imu_pre_review,
            "stat_before": st.get("raw", ""),
            "send_to_stm32": False,
            "motion_enabled": False,
            "actuator_control_allowed": False,
        }
        log_event(args.log_jsonl, blocked)
        setattr(args, "_last_execute_logged_motion_result", {
            "candidate_cmd": cmd,
            "blocked_before_send": True,
            "reason": imu_pre_review.get("reason", "imu_fault_before_motion"),
            "stat_before": st.get("raw", ""),
            "stat_after": "",
            "motion_response": "",
            "motion_events": [],
            "imu_before_review": imu_pre_review,
            "odom_progress_cm": None,
        })
        raise RuntimeError("imu_fault_before_motion: %s" % imu_pre_review.get("raw", ""))
    anchor = {"yaw": st["yaw"] if st["yaw"] is not None else 0.0}
    pwm_before = query_pwm_stat() if args.log_stm32_detail else ""
    pre_servo_resp = ""
    pwm_after_pre_servo = ""
    telemetry_on_resp = ""
    telemetry_off_resp = ""
    pre_servo_resp, pwm_after_pre_servo = prepare_steering_for_motion(action, args)
    if args.motion_telemetry:
        telemetry_on_resp = send_cmd("TEL ON", read_sec=2.0).strip()
    motion_resp = send_motion(cmd, args, read_sec=args.move_read_sec, reason="execute_logged_motion").strip()
    if args.motion_telemetry:
        telemetry_off_resp = send_cmd("TEL OFF", read_sec=2.0).strip()
    pre_servo_events = parse_stm32_events(pre_servo_resp)
    telemetry_on_events = parse_stm32_events(telemetry_on_resp)
    motion_events = parse_stm32_events(motion_resp)
    telemetry_off_events = parse_stm32_events(telemetry_off_resp)
    fusion_motion_trace = []
    fusion_motion_final = None
    if pose_fuser is not None:
        try:
            for ev in motion_events:
                if ev.get("type") == "tlm":
                    fusion_motion_final = pose_fuser.ingest_tlm(ev)
                    fusion_motion_trace.append(fusion_motion_final)
        except Exception as exc:
            fusion_motion_trace.append({"schema": "fused_pose_error.v1", "error": str(exc)})
    pwm_after = query_pwm_stat() if args.log_stm32_detail else ""
    st_after = read_stat()
    odom_progress_cm = None
    if st_after.get("d") is not None:
        odom_progress_cm = abs(float(st_after["d"]))
    if (st.get("d") is not None and st_after.get("d") is not None and
        abs(float(st_after["d"])) < abs(float(st["d"]))):
        odom_progress_cm = abs(float(st_after["d"]))
    log_event(args.log_jsonl, {
        "event": "stm32_motion_result",
        "candidate_cmd": cmd,
        "pre_steer_settle_sec": args.pre_steer_settle_sec,
        "pre_servo_response": pre_servo_resp,
        "pre_servo_events": pre_servo_events,
        "telemetry_on_response": telemetry_on_resp,
        "telemetry_on_events": telemetry_on_events,
        "motion_response": motion_resp,
        "motion_events": motion_events,
        "telemetry_off_response": telemetry_off_resp,
        "telemetry_off_events": telemetry_off_events,
        "fusion_motion_trace": fusion_motion_trace,
        "fusion_motion_final": fusion_motion_final,
        "stat_before": st.get("raw", ""),
        "pwm_before": pwm_before,
        "pwm_after_pre_servo": pwm_after_pre_servo,
        "pwm_after": pwm_after,
        "stat_after": st_after.get("raw", ""),
        "commanded_step_cm": round(step, 3),
        "odom_progress_cm": None if odom_progress_cm is None else round(odom_progress_cm, 3),
        "odom_d_before_cm": st.get("d"),
        "odom_d_after_cm": st_after.get("d"),
        "final_blind_token": None,
        "counter_steer_result": None,
    })
    setattr(args, "_last_execute_logged_motion_result", {
        "candidate_cmd": cmd,
        "pre_servo_response": pre_servo_resp,
        "pre_servo_events": pre_servo_events,
        "telemetry_on_response": telemetry_on_resp,
        "telemetry_on_events": telemetry_on_events,
        "motion_response": motion_resp,
        "motion_events": motion_events,
        "telemetry_off_response": telemetry_off_resp,
        "telemetry_off_events": telemetry_off_events,
        "stat_before": st.get("raw", ""),
        "stat_after": st_after.get("raw", ""),
        "imu_before_review": imu_pre_review,
        "imu_after_review": stm32_stat_imu_review(st_after, require_ok=motion_requires_imu_ok(args)),
        "commanded_step_cm": round(step, 3),
        "odom_progress_cm": None if odom_progress_cm is None else round(odom_progress_cm, 3),
        "odom_d_before_cm": st.get("d"),
        "odom_d_after_cm": st_after.get("d"),
    })
    return st, st_after, motion_events


