def planner_state_x_sign(value):
    if value > 3.0:
        return "+"
    if value < -3.0:
        return "-"
    return "0"


def planner_state_x_bin(value):
    v = abs(value)
    if v < 40.0:
        return "0-40"
    if v < 120.0:
        return "40-120"
    return "120+"


def planner_state_heading_bin(value):
    if value < -8.0:
        return "-8-"
    if value < 0.0:
        return "-8-0"
    if value <= 8.0:
        return "0-8"
    return "8+"


def planner_bucket_for_state(state):
    return {
        "phase": state.get("phase_hint", "unknown"),
        "x_err_sign": planner_state_x_sign(planner_to_float(state.get("slot_x_err_px"))),
        "x_err_bin": planner_state_x_bin(planner_to_float(state.get("slot_x_err_px"))),
        "heading_bin": planner_state_heading_bin(planner_to_float(state.get("slot_heading_err_deg"))),
    }


def planner_response_delta(record):
    return record.get("mean_delta") or record.get("delta") or {}


def planner_select_response_record(action_id, state, responses):
    records = [r for r in responses.get("records", []) if r.get("action_id") == action_id]
    if not records:
        return None, "prior"
    if responses.get("schema") != "parking_action_response_model.v2":
        return records[0], "measured"
    bucket = planner_bucket_for_state(state)
    exact = [r for r in records if r.get("bucket") == bucket]
    if exact:
        exact.sort(key=lambda r: planner_to_float(r.get("confidence")), reverse=True)
        return exact[0], "measured"
    same_sign = [
        r for r in records
        if (r.get("bucket") or {}).get("phase") == bucket.get("phase")
        and (r.get("bucket") or {}).get("x_err_sign") == bucket.get("x_err_sign")
    ]
    if same_sign:
        same_sign.sort(key=lambda r: planner_to_float(r.get("confidence")), reverse=True)
        neighbor = dict(same_sign[0])
        neighbor["confidence"] = round(planner_to_float(neighbor.get("confidence")) * 0.5, 3)
        neighbor["bucket_match"] = "same_phase_sign_neighbor"
        return neighbor, "measured_neighbor"
    records.sort(key=lambda r: planner_to_float(r.get("confidence")), reverse=True)
    fallback = dict(records[0])
    fallback["confidence"] = round(planner_to_float(fallback.get("confidence")) * 0.25, 3)
    fallback["bucket_match"] = "action_only_neighbor"
    return fallback, "measured_neighbor"


def planner_predicted_state(state, action, measured):
    source = measured or action
    delta = planner_response_delta(source) if measured else action.get("prior_delta")
    confidence = planner_to_float(source.get("confidence") if measured else action.get("prior_confidence"), 0.0)
    origin = measured.get("_origin", "measured") if measured else "prior"
    pred = dict(state)
    delta = delta or {}
    for key in [
        "slot_y_dist_cm",
        "slot_x_err_px",
        "slot_lateral_cm",
        "slot_heading_err_deg",
        "min_margin_px",
    ]:
        pred[key] = planner_to_float(pred.get(key)) + planner_to_float(delta.get(key), 0.0)
    pred["line_risk"] = pred["min_margin_px"] < 34.0
    return pred, confidence, origin


def planner_cost_state(pred, action, current, library, confidence, origin):
    scoring = library.get("scoring", {})
    target = scoring.get("target", {})
    weights = scoring.get("weights", {})

    slot_x_abs = abs(planner_to_float(pred.get("slot_x_err_px")) - planner_to_float(target.get("slot_x_err_px")))
    heading_abs = abs(planner_to_float(pred.get("slot_heading_err_deg")) - planner_to_float(target.get("slot_heading_err_deg")))
    lateral_abs = abs(planner_to_float(pred.get("slot_lateral_cm")) - planner_to_float(target.get("slot_lateral_cm")))
    min_margin = planner_to_float(pred.get("min_margin_px"))
    margin_shortfall = max(0.0, planner_to_float(target.get("min_margin_px"), 90.0) - min_margin)
    progress = max(0.0, planner_to_float(current.get("slot_y_dist_cm")) - planner_to_float(pred.get("slot_y_dist_cm")))
    phase_mismatch = 0.0 if current.get("phase_hint") in action.get("allowed_phases", []) else 1.0
    line_risk = 1.0 if pred.get("line_risk") else 0.0
    low_confidence = max(0.0, 1.0 - confidence)
    uncalibrated = 0.0 if origin.startswith("measured") else 1.0
    large_steer = abs(planner_to_float(action.get("servo"), SERVO_CENTER) - SERVO_CENTER) / 45.0

    parts = {
        "slot_x_err_abs": slot_x_abs * planner_to_float(weights.get("slot_x_err_abs"), 1.0),
        "slot_heading_err_abs": heading_abs * planner_to_float(weights.get("slot_heading_err_abs"), 4.0),
        "slot_lateral_abs": lateral_abs * planner_to_float(weights.get("slot_lateral_abs"), 8.0),
        "progress_bonus": -progress * planner_to_float(weights.get("progress"), 0.35),
        "min_margin_shortfall": margin_shortfall * planner_to_float(weights.get("min_margin_shortfall"), 2.5),
        "line_risk": line_risk * planner_to_float(weights.get("line_risk"), 1000.0),
        "phase_mismatch": phase_mismatch * planner_to_float(weights.get("phase_mismatch"), 25.0),
        "low_confidence": low_confidence * planner_to_float(weights.get("low_confidence"), 20.0),
        "uncalibrated": uncalibrated * planner_to_float(weights.get("uncalibrated"), 15.0),
        "large_steer": large_steer * planner_to_float(weights.get("large_steer"), 3.0),
    }
    return round(sum(parts.values()), 3), {k: round(v, 3) for k, v in parts.items()}


def planner_hard_block_reasons(action, state, pred, origin, response_verdict, real_motion, criteria):
    reasons = []
    if state.get("phase_hint") not in action.get("allowed_phases", []):
        reasons.append("phase_mismatch")
    x_err = planner_to_float(state.get("slot_x_err_px"))
    servo = planner_to_float(action.get("servo"), SERVO_CENTER)
    kind = str(action.get("kind") or "")
    if kind == "reverse_arc" and abs(x_err) > 3.0 and servo != SERVO_CENTER:
        if x_err > 0.0 and servo < SERVO_CENTER:
            reasons.append("wrong_lateral_correction_direction")
        elif x_err < 0.0 and servo > SERVO_CENTER:
            reasons.append("wrong_lateral_correction_direction")
    abort = (criteria or {}).get("abort", {})
    min_margin_floor = planner_to_float(abort.get("min_margin_px_floor"), 40.0)
    recovery = planner_edge_recovery_context(state, criteria)
    pred_margin = planner_to_float(pred.get("min_margin_px"))
    if recovery.get("active"):
        if pred.get("line_risk") or pred_margin < planner_to_float(recovery.get("predicted_min_margin_px")):
            reasons.append("predicted_line_risk")
        margin_gain = pred_margin - planner_to_float(state.get("min_margin_px"))
        if margin_gain < planner_to_float(recovery.get("min_margin_gain_px")):
            reasons.append("edge_recovery_margin_not_improved")
        if recovery.get("require_x_improve"):
            cur_x_abs = abs(planner_to_float(state.get("slot_x_err_px")))
            pred_x_abs = abs(planner_to_float(pred.get("slot_x_err_px")))
            if pred_x_abs >= cur_x_abs:
                reasons.append("edge_recovery_x_not_improved")
    elif pred.get("line_risk") or pred_margin < min_margin_floor:
        reasons.append("predicted_line_risk")
    if real_motion:
        if action.get("requires_measured") and origin != "measured":
            reasons.append("no_exact_measured_response")
        if response_verdict == "worsened":
            reasons.append("measured_worsened")
    return reasons


def planner_score_actions(state, library, responses, real_motion=False, criteria=None):
    ranked = []
    recovery = planner_edge_recovery_context(state, criteria)
    for action in library.get("actions", []):
        measured, origin = planner_select_response_record(action.get("id"), state, responses)
        if measured:
            measured = dict(measured)
            measured["_origin"] = origin
        pred, confidence, origin = planner_predicted_state(state, action, measured)
        response_verdict = measured.get("dominant_verdict") or measured.get("verdict") if measured else None
        cost, parts = planner_cost_state(pred, action, state, library, confidence, origin)
        block_reasons = planner_hard_block_reasons(
            action, state, pred, origin, response_verdict, real_motion, criteria)
        ranked.append({
            "id": action.get("id"),
            "action_id": action.get("id"),
            "command": action.get("command"),
            "origin": origin,
            "confidence": round(confidence, 3),
            "response_bucket": measured.get("bucket") if measured else None,
            "response_match": measured.get("bucket_match", "exact") if measured else "prior",
            "response_verdict": response_verdict,
            "score": cost,
            "cost": cost,
            "cost_parts": parts,
            "hard_blocked": bool(block_reasons),
            "block_reasons": block_reasons,
            "edge_recovery": recovery,
            "predicted": {
                "slot_y_dist_cm": round(pred["slot_y_dist_cm"], 3),
                "slot_x_err_px": round(pred["slot_x_err_px"], 3),
                "slot_lateral_cm": round(pred["slot_lateral_cm"], 3),
                "slot_heading_err_deg": round(pred["slot_heading_err_deg"], 3),
                "min_margin_px": round(pred["min_margin_px"], 3),
                "line_risk": bool(pred["line_risk"]),
            },
            "notes": action.get("notes", ""),
        })
    ranked.sort(key=lambda item: (1 if item.get("hard_blocked") else 0, item["score"]))
    return ranked


def planner_servo_dir_from_command(command):
    try:
        kind, _step, servo = _parse_motion_command_for_action(command)
    except (ValueError, IndexError):
        return 0.0
    if kind != "ARC" or servo == SERVO_CENTER:
        return 0.0
    return 1.0 if servo > SERVO_CENTER else -1.0


def planner_apply_switch_penalty(ranking, last_action_id, penalty):
    if not last_action_id or penalty <= 0:
        return ranking
    last_item = None
    for item in ranking:
        if item.get("action_id") == last_action_id:
            last_item = item
            break
    if not last_item:
        return ranking
    last_dir = planner_servo_dir_from_command(last_item.get("command", ""))
    out = []
    for item in ranking:
        adjusted = dict(item)
        cur_dir = planner_servo_dir_from_command(item.get("command", ""))
        switch_penalty = 0.0
        if last_dir != 0.0 and cur_dir != 0.0 and cur_dir != last_dir:
            switch_penalty = penalty
        adjusted["switch_penalty"] = round(switch_penalty, 3)
        adjusted["score"] = round(planner_to_float(adjusted.get("score")) + switch_penalty, 3)
        adjusted["cost"] = adjusted["score"]
        out.append(adjusted)
    out.sort(key=lambda item: (1 if item.get("hard_blocked") else 0, item["score"]))
    return out


def planner_relax_prior_lateral_recovery_blocks(ranking, state, args):
    if not args.replanner_allow_prior_lateral_recovery:
        return ranking
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    cur_lat_abs = abs(planner_to_float(state.get("slot_lateral_cm")))
    if y_dist > args.replanner_prior_lateral_recovery_max_y_dist_cm:
        return ranking
    if cur_lat_abs < args.replanner_prior_lateral_recovery_min_lateral_cm:
        return ranking
    out = []
    for item in ranking:
        adjusted = dict(item)
        reasons = list(adjusted.get("block_reasons") or [])
        predicted = adjusted.get("predicted") or {}
        pred_lat_abs = abs(planner_to_float(predicted.get("slot_lateral_cm")))
        pred_margin = planner_to_float(predicted.get("min_margin_px"))
        gain = cur_lat_abs - pred_lat_abs
        eligible = (
            adjusted.get("action_id") not in ("WAIT", "STOP") and
            "no_exact_measured_response" in reasons and
            "phase_mismatch" not in reasons and
            "measured_worsened" not in reasons and
            not bool(predicted.get("line_risk")) and
            pred_margin >= args.replanner_prior_lateral_recovery_min_margin_px and
            gain >= args.replanner_prior_lateral_recovery_min_gain_cm and
            pred_lat_abs <= args.replanner_prior_lateral_recovery_max_predicted_lateral_cm
        )
        if eligible:
            reasons = [r for r in reasons if r != "no_exact_measured_response"]
            bonus = args.replanner_prior_lateral_recovery_score_bonus
            adjusted["block_reasons"] = reasons
            adjusted["hard_blocked"] = bool(reasons)
            adjusted["score"] = round(planner_to_float(adjusted.get("score")) - bonus, 3)
            adjusted["cost"] = adjusted["score"]
            parts = dict(adjusted.get("cost_parts") or {})
            parts["prior_lateral_recovery_bonus"] = round(-bonus, 3)
            adjusted["cost_parts"] = parts
            adjusted["prior_lateral_recovery"] = {
                "active": True,
                "reason": "predicted_terminal_lateral_recovery",
                "current_lateral_abs_cm": round(cur_lat_abs, 3),
                "predicted_lateral_abs_cm": round(pred_lat_abs, 3),
                "predicted_lateral_gain_cm": round(gain, 3),
                "slot_y_dist_cm": round(y_dist, 3),
                "predicted_min_margin_px": round(pred_margin, 2),
                "score_bonus": round(bonus, 3),
            }
        else:
            adjusted["prior_lateral_recovery"] = {"active": False}
        out.append(adjusted)
    out.sort(key=lambda item: (1 if item.get("hard_blocked") else 0, item["score"]))
    return out


def planner_promote_visible_lateral_recovery(ranking, state, args):
    if not args.replanner_allow_visible_lateral_recovery:
        return ranking
    terminal_guard = planner_terminal_large_heading_guard(state, args)
    if terminal_guard.get("active"):
        return [
            {
                **item,
                "visible_lateral_recovery": {
                    "active": False,
                    "reason": "terminal_large_heading_guard",
                    "guard": terminal_guard,
                },
            }
            for item in ranking
        ]
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    cur_lat_abs = abs(planner_to_float(state.get("slot_lateral_cm")))
    phase = state.get("phase_hint")
    if phase not in ("approach_entry", "align_in_corridor", "straighten_or_enter"):
        return ranking
    if y_dist > args.replanner_visible_lateral_recovery_max_y_dist_cm:
        return ranking
    if cur_lat_abs < args.replanner_visible_lateral_recovery_min_lateral_cm:
        return ranking
    out = []
    for item in ranking:
        adjusted = dict(item)
        reasons = list(adjusted.get("block_reasons") or [])
        command = adjusted.get("command", "")
        predicted = adjusted.get("predicted") or {}
        try:
            kind, _step, servo = _parse_motion_command_for_action(command)
        except (ValueError, IndexError):
            kind, servo = "", SERVO_CENTER
        pred_lat_abs = abs(planner_to_float(predicted.get("slot_lateral_cm")))
        pred_margin = planner_to_float(predicted.get("min_margin_px"))
        gain = cur_lat_abs - pred_lat_abs
        eligible = (
            kind == "ARC" and
            servo != SERVO_CENTER and
            "wrong_lateral_correction_direction" not in reasons and
            "phase_mismatch" not in reasons and
            not bool(predicted.get("line_risk")) and
            pred_margin >= args.replanner_visible_lateral_recovery_min_margin_px and
            gain >= args.replanner_visible_lateral_recovery_min_gain_cm
        )
        if eligible:
            removable = {"no_exact_measured_response", "measured_worsened"}
            removed = [r for r in reasons if r in removable]
            reasons = [r for r in reasons if r not in removable]
            gain_bonus = max(0.0, gain - args.replanner_visible_lateral_recovery_min_gain_cm)
            bonus = args.replanner_visible_lateral_recovery_score_bonus + (
                gain_bonus * args.replanner_visible_lateral_recovery_gain_bonus_per_cm)
            adjusted["block_reasons"] = reasons
            adjusted["hard_blocked"] = bool(reasons)
            adjusted["score"] = round(planner_to_float(adjusted.get("score")) - bonus, 3)
            adjusted["cost"] = adjusted["score"]
            parts = dict(adjusted.get("cost_parts") or {})
            parts["visible_lateral_recovery_bonus"] = round(-bonus, 3)
            adjusted["cost_parts"] = parts
            adjusted["visible_lateral_recovery"] = {
                "active": True,
                "reason": "predicted_visible_lateral_recovery",
                "removed_block_reasons": removed,
                "current_lateral_abs_cm": round(cur_lat_abs, 3),
                "predicted_lateral_abs_cm": round(pred_lat_abs, 3),
                "predicted_lateral_gain_cm": round(gain, 3),
                "slot_y_dist_cm": round(y_dist, 3),
                "predicted_min_margin_px": round(pred_margin, 2),
                "score_bonus": round(bonus, 3),
            }
        else:
            adjusted["visible_lateral_recovery"] = {"active": False}
        out.append(adjusted)
    out.sort(key=lambda item: (1 if item.get("hard_blocked") else 0, item["score"]))
    return out


def planner_terminal_large_heading_guard(state, args):
    enabled = bool(getattr(args, "replanner_terminal_large_heading_stop", True))
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    heading_abs = abs(planner_to_float(state.get("slot_heading_err_deg")))
    max_y = planner_to_float(
        getattr(args, "replanner_terminal_large_heading_max_y_dist_cm", 25.0), 25.0)
    heading_limit = planner_to_float(
        getattr(args, "replanner_terminal_large_heading_deg", 18.0), 18.0)
    min_visible = planner_to_float(
        getattr(args, "replanner_terminal_heading_min_visible_ratio", TERMINAL_HEADING_MIN_VISIBLE_RATIO),
        TERMINAL_HEADING_MIN_VISIBLE_RATIO,
    )
    partial_y = planner_to_float(
        getattr(args, "replanner_terminal_heading_partial_y_dist_cm", TERMINAL_HEADING_PARTIAL_Y_DIST_CM),
        TERMINAL_HEADING_PARTIAL_Y_DIST_CM,
    )
    visible_ratio_known = state.get("slot_visible_ratio") is not None
    visible_ratio = planner_to_float(state.get("slot_visible_ratio"), 1.0)
    reasons_raw = state.get("slot_completeness_reasons") or []
    if isinstance(reasons_raw, str):
        completeness_reasons = [reasons_raw]
    else:
        completeness_reasons = list(reasons_raw)
    near_border = "near_image_border" in completeness_reasons
    low_visible = visible_ratio_known and visible_ratio < min_visible
    can_refresh = planner_to_bool(state.get("slot_completeness_can_refresh_geometry", True))
    entry_visible = planner_to_bool(state.get("entry_edge_visible", True))
    partial_observation = bool(
        y_dist <= partial_y and (
            low_visible or
            near_border or
            not can_refresh or
            not entry_visible
        )
    )
    checks = {
        "enabled": enabled,
        "near_terminal": y_dist <= max_y,
        "heading_large": heading_abs >= heading_limit,
        "terminal_heading_geometry_reliable": not partial_observation,
    }
    base_active = bool(enabled and checks["near_terminal"] and checks["heading_large"])
    return {
        "active": bool(base_active and not partial_observation),
        "reason": "partial_terminal_geometry_suppressed" if base_active and partial_observation else "terminal_large_heading_stop",
        "checks": checks,
        "base_active": base_active,
        "suppressed": bool(base_active and partial_observation),
        "partial_geometry": {
            "active": partial_observation,
            "visible_ratio_known": bool(visible_ratio_known),
            "visible_ratio": round(visible_ratio, 6),
            "min_visible_ratio": round(min_visible, 6),
            "low_visible_ratio": bool(low_visible),
            "near_image_border": bool(near_border),
            "entry_edge_visible": bool(entry_visible),
            "can_refresh_geometry": bool(can_refresh),
            "slot_completeness_status": state.get("slot_completeness_status"),
            "slot_completeness_reasons": sorted(set(completeness_reasons)),
            "partial_y_dist_cm": round(partial_y, 3),
        },
        "slot_y_dist_cm": round(y_dist, 3),
        "slot_heading_abs_deg": round(heading_abs, 3),
        "max_y_dist_cm": round(max_y, 3),
        "heading_limit_deg": round(heading_limit, 3),
    }


def planner_library_with_terminal_countersteer(library, state, args):
    if not args.replanner_allow_terminal_countersteer:
        return library
    if state.get("phase_hint") != "straighten_or_enter":
        return library
    lateral_abs = abs(planner_to_float(state.get("slot_lateral_cm")))
    heading_abs = abs(planner_to_float(state.get("slot_heading_err_deg")))
    if (lateral_abs < args.replanner_terminal_countersteer_min_lateral_cm and
        heading_abs < args.replanner_terminal_countersteer_min_heading_deg):
        return library
    allow_ids = set(
        item.strip() for item in args.replanner_terminal_countersteer_action_ids.split(",")
        if item.strip())
    patched = json.loads(json.dumps(library))
    for action in patched.get("actions", []):
        if action.get("id") not in allow_ids:
            continue
        phases = list(action.get("allowed_phases") or [])
        if "straighten_or_enter" not in phases:
            phases.append("straighten_or_enter")
        action["allowed_phases"] = phases
        action["terminal_countersteer_candidate"] = True
    return patched


def planner_chosen_from_ranked(item, reason):
    command = item.get("command", "")
    try:
        kind, step, servo = _parse_motion_command_for_action(command)
    except (ValueError, IndexError):
        kind, step, servo = "WAIT", 0.0, int(SERVO_CENTER)
    return {
        "id": item.get("action_id"),
        "action_id": item.get("action_id"),
        "command": command,
        "action": kind,
        "step": round(step, 1),
        "servo": servo,
        "reason": reason,
        "score": item.get("score"),
        "origin": item.get("origin"),
        "confidence": item.get("confidence"),
        "hard_blocked": bool(item.get("hard_blocked")),
        "block_reasons": item.get("block_reasons", []),
    }


def planner_synthetic_choice(action_id, command, reason):
    return {
        "id": action_id,
        "action_id": action_id,
        "command": command,
        "action": action_id,
        "step": 0.0,
        "servo": int(SERVO_CENTER),
        "reason": reason,
        "score": None,
        "origin": "gate",
        "confidence": None,
        "hard_blocked": False,
        "block_reasons": [],
    }


def action_replanner_command_from_state(planner_state, stable, args, library, responses, criteria,
                                        real_motion=False, last_action_id=None):
    planner_state = dict(planner_state or {})
    planner_state["stable"] = bool(stable)
    planner_state["stable_enough"] = bool(planner_state.get("stable_enough", stable))
    recovery = planner_edge_recovery_context(planner_state, criteria)
    scoring_library = planner_library_with_terminal_countersteer(library, planner_state, args)
    ranking = planner_score_actions(planner_state, scoring_library, responses, real_motion, criteria)
    ranking = planner_promote_visible_lateral_recovery(ranking, planner_state, args)
    ranking = planner_relax_prior_lateral_recovery_blocks(ranking, planner_state, args)
    ranking = planner_apply_switch_penalty(ranking, last_action_id, args.replanner_switch_penalty)
    gates = {
        "stable": bool(stable),
        "stable_enough": bool(planner_state.get("stable_enough")),
        "line_risk": bool(planner_state.get("line_risk")),
        "line_margin_ok": bool(planner_state.get("line_margin_ok")),
        "edge_recovery": recovery,
        "terminal_large_heading_guard": planner_terminal_large_heading_guard(planner_state, args),
        "real_motion": bool(real_motion),
    }
    if not stable or not planner_state.get("stable_enough"):
        chosen = planner_synthetic_choice("WAIT", "WAIT", "wait_unstable")
    elif planner_state.get("line_risk"):
        chosen = planner_synthetic_choice("STOP", "STOP", "line_risk")
    elif gates["terminal_large_heading_guard"].get("active"):
        chosen = planner_synthetic_choice("STOP", "STOP", "terminal_large_heading")
    else:
        eligible = [item for item in ranking if not item.get("hard_blocked")]
        if not eligible:
            chosen = planner_synthetic_choice("STOP", "STOP", "none_eligible")
        else:
            best = eligible[0]
            chosen = planner_chosen_from_ranked(
                best,
                "edge_recovery_action" if recovery.get("active") else "best_ranked_action")
            if last_action_id:
                best_visible_recovery = bool((best.get("visible_lateral_recovery") or {}).get("active"))
                previous = None
                for item in eligible:
                    if item.get("action_id") == last_action_id:
                        previous = item
                        break
                previous_visible_recovery = bool((previous or {}).get("visible_lateral_recovery", {}).get("active"))
                if (previous and not (best_visible_recovery and not previous_visible_recovery)
                    and planner_to_float(previous.get("score")) <= planner_to_float(best.get("score")) + args.replanner_hold_margin):
                    chosen = planner_chosen_from_ranked(previous, "hold_hysteresis")
    action = {
        "state": "ACTION_REPLANNER",
        "action": chosen["action"],
        "cmd": chosen["command"],
        "step": chosen["step"],
        "servo": chosen["servo"],
        "steer_dir": planner_servo_dir_from_command(chosen["command"]),
        "reason": chosen["reason"],
        "binding": {
            "action_id": chosen["action_id"],
            "score": chosen["score"],
            "origin": chosen["origin"],
            "confidence": chosen["confidence"],
        },
        "replanner": {
            "pre_state": planner_state,
            "ranking": ranking,
            "chosen": chosen,
            "gates": gates,
        },
    }
    return action


def action_replanner_command(slot_state, stable, args, library, responses, criteria,
                             real_motion=False, last_action_id=None):
    return action_replanner_command_from_state(
        planner_flatten_slot_state(slot_state, stable),
        stable,
        args,
        library,
        responses,
        criteria,
        real_motion=real_motion,
        last_action_id=last_action_id,
    )


def kinematic_lattice_command_from_state(planner_state, stable, args, chassis_kinematics,
                                         criteria, real_motion=False):
    """Measured-kinematics replanner.

    The normal profile remains conservative.  The small_car_fast/fast_loop
    profile treats non-fatal visual imperfections as cautious short-step
    conditions; it still executes only one primitive and relies on
    stop/observe/replan instead of long blind or fixed sequences.
    """
    planner_state = dict(planner_state or {})
    planner_state["stable"] = bool(stable)
    planner_state["stable_enough"] = bool(planner_state.get("stable_enough", stable))
    planner_state["low_conf_cautious_streak"] = int(getattr(args, "_lattice_low_conf_cautious_streak", 0) or 0)
    lattice_profile = str(getattr(args, "lattice_safety_profile", "standard") or "standard").strip().lower()
    fast_lattice = lattice_profile in FAST_LATTICE_PROFILES

    def lattice_profile_value(attr, standard_default, fast_default=None):
        value = getattr(args, attr, None)
        if fast_lattice and (value is None or value == standard_default):
            return fast_default if fast_default is not None else standard_default
        return standard_default if value is None else value

    if plan_kinematic_lattice is None or lattice_controller_action_from_plan is None:
        plan = {
            "schema": "parking_kinematic_lattice_plan.v1",
            "strategy": "kinematic_lattice_replanner",
            "status": "module_unavailable",
            "chosen": {
                "action_id": "STOP",
                "command": "STOP",
                "reason": "parking_kinematic_lattice_module_unavailable",
            },
            "pre_state": planner_state,
            "candidates": [],
        }
    else:
        plan = plan_kinematic_lattice(
            planner_state,
            chassis_kinematics or {},
            criteria or {},
            {
                "safety_profile": lattice_profile,
                "lookahead_depth": getattr(args, "lattice_lookahead_depth", 2),
                "visual_quality": {
                    "safety_profile": lattice_profile,
                    "min_confidence": lattice_profile_value("lattice_min_confidence", 0.75, 0.40),
                    "min_visible_ratio": lattice_profile_value("lattice_min_visible_ratio", 0.18, 0.04),
                    "require_can_refresh_geometry": False if fast_lattice else True,
                    "require_reliable_geometry": False if fast_lattice else True,
                    "require_corridor_sample_reliable": False if fast_lattice else True,
                    "cautious": {
                        "enable": getattr(args, "lattice_cautious_enable", True),
                        "min_confidence": lattice_profile_value("lattice_cautious_min_confidence", 0.85, 0.40),
                        "min_visible_ratio": lattice_profile_value("lattice_cautious_min_visible_ratio", 0.08, 0.04),
                        "min_margin_px": lattice_profile_value("lattice_cautious_min_margin_px", 90.0, 80.0),
                        "min_pose_quality": lattice_profile_value("lattice_cautious_min_pose_quality", 0.70, 0.45),
                        "min_y_dist_cm": lattice_profile_value("lattice_cautious_min_y_dist_cm", 18.0, 0.0),
                        "max_y_dist_cm": lattice_profile_value("lattice_cautious_max_y_dist_cm", 90.0, 120.0),
                        "max_abs_lateral_cm": lattice_profile_value("lattice_cautious_max_abs_lateral_cm", 18.0, 26.0),
                        "max_abs_heading_deg": lattice_profile_value("lattice_cautious_max_abs_heading_deg", 32.0, 40.0),
                        "max_abs_x_err_px": lattice_profile_value("lattice_cautious_max_abs_x_err_px", 90.0, 130.0),
                        "max_corridor_extrapolation_px": lattice_profile_value("lattice_cautious_max_corridor_extrapolation_px", 320.0, 9999.0),
                        "max_distance_cm": lattice_profile_value("lattice_cautious_max_distance_cm", 3.0, 2.0),
                        "lookahead_depth": getattr(args, "lattice_cautious_lookahead_depth", 1),
                        "allow_suspect_topology": lattice_profile_value("lattice_cautious_allow_suspect_topology", True, True),
                        "require_entry_edge_visible": lattice_profile_value("lattice_cautious_require_entry_edge_visible", True, False),
                        "require_geometry_planning_allowed": lattice_profile_value("lattice_cautious_require_geometry_planning_allowed", True, False),
                    },
                    "terminal_cautious": {
                        "enable": getattr(args, "lattice_terminal_cautious_enable", True),
                        "min_confidence": lattice_profile_value("lattice_terminal_cautious_min_confidence", 0.85, 0.35),
                        "min_visible_ratio": lattice_profile_value("lattice_terminal_cautious_min_visible_ratio", 0.05, 0.03),
                        "min_margin_px": lattice_profile_value("lattice_terminal_cautious_min_margin_px", 80.0, 70.0),
                        "min_pose_quality": lattice_profile_value("lattice_terminal_cautious_min_pose_quality", 0.65, 0.40),
                        "min_y_dist_cm": lattice_profile_value("lattice_terminal_cautious_min_y_dist_cm", 8.0, 0.0),
                        "max_y_dist_cm": lattice_profile_value("lattice_terminal_cautious_max_y_dist_cm", 22.0, 35.0),
                        "max_abs_lateral_cm": lattice_profile_value("lattice_terminal_cautious_max_abs_lateral_cm", 8.0, 14.0),
                        "max_abs_heading_deg": lattice_profile_value("lattice_terminal_cautious_max_abs_heading_deg", 14.0, 28.0),
                        "max_abs_x_err_px": lattice_profile_value("lattice_terminal_cautious_max_abs_x_err_px", 55.0, 95.0),
                        "max_corridor_extrapolation_px": lattice_profile_value("lattice_terminal_cautious_max_corridor_extrapolation_px", 260.0, 9999.0),
                        "max_distance_cm": lattice_profile_value("lattice_terminal_cautious_max_distance_cm", 2.5, 1.5),
                        "lookahead_depth": getattr(args, "lattice_terminal_cautious_lookahead_depth", 1),
                        "allow_suspect_topology": lattice_profile_value("lattice_terminal_cautious_allow_suspect_topology", True, True),
                        "require_entry_edge_visible": lattice_profile_value("lattice_terminal_cautious_require_entry_edge_visible", False, False),
                        "require_geometry_planning_allowed": lattice_profile_value("lattice_terminal_cautious_require_geometry_planning_allowed", True, False),
                    },
                    "low_conf_cautious": {
                        "enable": getattr(args, "lattice_low_conf_cautious_enable", True),
                        "min_confidence": lattice_profile_value("lattice_low_conf_cautious_min_confidence", 0.50, 0.35),
                        "min_visible_ratio": lattice_profile_value("lattice_low_conf_cautious_min_visible_ratio", 0.18, 0.035),
                        "min_margin_px": lattice_profile_value("lattice_low_conf_cautious_min_margin_px", 140.0, 90.0),
                        "min_pose_quality": lattice_profile_value("lattice_low_conf_cautious_min_pose_quality", 0.65, 0.40),
                        "min_y_dist_cm": lattice_profile_value("lattice_low_conf_cautious_min_y_dist_cm", 18.0, 0.0),
                        "max_y_dist_cm": lattice_profile_value("lattice_low_conf_cautious_max_y_dist_cm", 70.0, 120.0),
                        "max_abs_lateral_cm": lattice_profile_value("lattice_low_conf_cautious_max_abs_lateral_cm", 12.0, 24.0),
                        "max_abs_heading_deg": lattice_profile_value("lattice_low_conf_cautious_max_abs_heading_deg", 28.0, 38.0),
                        "max_abs_x_err_px": lattice_profile_value("lattice_low_conf_cautious_max_abs_x_err_px", 60.0, 120.0),
                        "max_corridor_extrapolation_px": lattice_profile_value("lattice_low_conf_cautious_max_corridor_extrapolation_px", 160.0, 9999.0),
                        "max_distance_cm": lattice_profile_value("lattice_low_conf_cautious_max_distance_cm", 2.0, 2.0),
                        "lookahead_depth": getattr(args, "lattice_low_conf_cautious_lookahead_depth", 1),
                        "max_consecutive_steps": lattice_profile_value("lattice_low_conf_cautious_max_consecutive_steps", 1, 999),
                        "allow_suspect_topology": lattice_profile_value("lattice_low_conf_cautious_allow_suspect_topology", False, True),
                        "require_entry_edge_visible": lattice_profile_value("lattice_low_conf_cautious_require_entry_edge_visible", False, False),
                        "require_geometry_planning_allowed": lattice_profile_value("lattice_low_conf_cautious_require_geometry_planning_allowed", True, False),
                        "require_corridor_sample_reliable": lattice_profile_value("lattice_low_conf_cautious_require_corridor_sample_reliable", True, False),
                        "allow_mask_polygon_cleanup": fast_lattice,
                    },
                },
            },
        )
    action = lattice_controller_action_from_plan(plan) if lattice_controller_action_from_plan is not None else {
        "state": "KINEMATIC_LATTICE_REPLANNER",
        "action": "STOP",
        "cmd": "STOP",
        "step": 0.0,
        "servo": SERVO_CENTER,
        "reason": "parking_kinematic_lattice_module_unavailable",
        "binding": {"action_id": "STOP", "status": "module_unavailable"},
        "kinematic_lattice": plan,
    }
    action["real_motion"] = bool(real_motion)
    return action


def planner_rel_state_from_flat_state(state, required_stable_frames=3):
    state = dict(state or {})
    stable_frames = int(planner_to_float(
        state.get("stable_frames"), planner_to_float(state.get("required_stable_frames"), required_stable_frames)))
    required = max(1, int(planner_to_float(state.get("required_stable_frames"), required_stable_frames)))
    min_margin = planner_to_float(state.get("min_margin_px"))
    line_risk = bool(state.get("line_risk"))
    return {
        "schema": "slot_relative_state.v1",
        "confidence": planner_to_float(state.get("confidence"), 1.0),
        "stable_frames": stable_frames,
        "required_stable_frames": required,
        "pose_quality": planner_to_float(state.get("pose_quality"), 1.0),
        "phase_hint": state.get("phase_hint") or "align_in_corridor",
        "visibility": {
            "slot_visible_ratio": planner_to_float(state.get("slot_visible_ratio"), 0.0),
            "entry_edge_visible": planner_to_bool(state.get("entry_edge_visible")),
        },
        "vision": {
            "slot_visible_ratio": planner_to_float(state.get("slot_visible_ratio"), 0.0),
            "entry_edge_visible": planner_to_bool(state.get("entry_edge_visible")),
            "spike_suppression_applied": planner_to_bool(state.get("spike_suppression_applied", False)),
            "quad_fit_input_source": state.get("quad_fit_input_source"),
            "source": state.get("belief_source") or state.get("source") or "planner_state",
        },
        "completeness": {
            "status": state.get("slot_completeness_status") or "belief",
            "can_refresh_geometry": planner_to_bool(state.get("slot_completeness_can_refresh_geometry")),
            "reasons": list(state.get("slot_completeness_reasons") or []),
        },
        "geometry": {
            "geometry_reliable": planner_to_bool(state.get("geometry_reliable", True)),
            "quad_topology_valid": planner_to_bool(state.get("quad_topology_valid", True)),
            "quad_topology_status": state.get("quad_topology_status"),
            "quad_topology_reasons": list(state.get("quad_topology_reasons") or []),
            "raw_geometry_rejected_for_hard_gate": planner_to_bool(
                state.get("raw_geometry_rejected_for_hard_gate", False)),
            "spike_suppression_applied": planner_to_bool(state.get("spike_suppression_applied", False)),
            "quad_fit_input_source": state.get("quad_fit_input_source"),
            "geometry_action": state.get("geometry_action"),
        },
        "image": {
            "slot_heading_err_deg": planner_to_float(state.get("slot_heading_err_deg")),
            "closeness": planner_to_float(state.get("closeness")),
        },
        "corridor": {
            "slot_x_err_px": planner_to_float(state.get("slot_x_err_px")),
            "slot_entry_x_err_px": planner_to_float(state.get("slot_entry_x_err_px")),
            "left_margin_px": planner_to_float(state.get("left_margin_px")),
            "right_margin_px": planner_to_float(state.get("right_margin_px")),
            "min_margin_px": min_margin,
            "line_risk": line_risk,
        },
        "ground_estimate": {
            "slot_y_dist_cm": planner_to_float(state.get("slot_y_dist_cm")),
            "slot_lateral_cm": planner_to_float(state.get("slot_lateral_cm")),
            "slot_axis_heading_deg": planner_to_float(state.get("slot_heading_err_deg")),
        },
        "gates": {
            "stable_enough": bool(state.get("stable_enough", True)),
            "line_margin_ok": bool(state.get("line_margin_ok", min_margin >= 60.0)),
            "heading_ok": bool(state.get("heading_ok", True)),
            "lateral_ok": bool(state.get("lateral_ok", True)),
            "slot_geometry_complete": planner_to_bool(state.get("slot_completeness_can_refresh_geometry")),
            "slot_geometry_usable_visibility": True,
            "geometry_reliable": planner_to_bool(state.get("geometry_reliable", True)),
            "quad_topology_valid": planner_to_bool(state.get("quad_topology_valid", True)),
        },
    }


def replanner_belief_visual_trusted(flat_state):
    state = flat_state or {}
    status = state.get("slot_completeness_status")
    return bool(
        state.get("stable_enough") and
        state.get("line_margin_ok") and
        not state.get("line_risk") and
        not state.get("spike_suppression_applied") and
        planner_to_bool(state.get("slot_completeness_can_refresh_geometry")) and
        planner_to_bool(state.get("geometry_reliable", True)) and
        planner_to_bool(state.get("quad_topology_valid", True)) and
        (status in (None, "complete", "trusted"))
    )


def replanner_belief_from_state(state, source, steps, total_cm):
    belief = deepcopy_jsonable(state or {})
    belief["schema"] = "parking_replanner_belief_state.v1"
    belief["belief_source"] = source
    belief["belief_steps"] = int(steps)
    belief["belief_total_cm"] = round(float(total_cm), 3)
    belief["belief_time_unix"] = time.time()
    belief["stable"] = True
    belief["stable_enough"] = True
    belief["stable_frames"] = max(
        int(planner_to_float(belief.get("stable_frames"), 0)),
        int(planner_to_float(belief.get("required_stable_frames"), 3)),
    )
    return belief


def replanner_belief_review(belief, args, steps, total_cm):
    state = belief or {}
    age_sec = time.time() - planner_to_float(state.get("belief_time_unix"), time.time())
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    min_margin = planner_to_float(state.get("min_margin_px"))
    carry_cm = max(0.0, float(total_cm) - planner_to_float(state.get("belief_total_cm"), float(total_cm)))
    checks = {
        "enabled": bool(getattr(args, "replanner_belief_blind_enable", True)),
        "exists": bool(belief),
        "fresh": age_sec <= planner_to_float(getattr(args, "replanner_belief_max_age_sec", 20.0), 20.0),
        "carry_ok": carry_cm <= planner_to_float(getattr(args, "replanner_belief_max_carry_cm", 45.0), 45.0),
        "distance_ok": y_dist <= planner_to_float(getattr(args, "replanner_belief_max_y_dist_cm", 60.0), 60.0),
        "margin_ok": min_margin >= planner_to_float(getattr(args, "replanner_belief_min_margin_px", 80.0), 80.0),
        "line_risk_clear": not bool(state.get("line_risk")),
        "steps_monotonic": int(steps) >= int(planner_to_float(state.get("belief_steps"), 0)),
    }
    return {
        "schema": "parking_replanner_belief_review.v1",
        "pass": all(checks.values()),
        "checks": checks,
        "metrics": {
            "age_sec": round(age_sec, 3),
            "carry_cm": round(carry_cm, 3),
            "slot_y_dist_cm": round(y_dist, 3),
            "min_margin_px": round(min_margin, 3),
        },
        "belief_source": state.get("belief_source"),
    }


def terminal_unreliable_vision_review(state, args, terminal_zone=None, source=None):
    """Classify whether terminal slot-x pixels are reliable enough to hard-gate."""
    state = state or {}
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    terminal_y = planner_to_float(
        getattr(args, "replanner_belief_terminal_stop_y_dist_cm", 12.0), 12.0)
    active = bool(y_dist <= terminal_y if terminal_zone is None else terminal_zone)
    visible_ratio_known = state.get("slot_visible_ratio") is not None
    visible_ratio = planner_to_float(state.get("slot_visible_ratio"), 0.0)
    visible_min = planner_to_float(
        getattr(args, "terminal_unreliable_vision_visible_ratio_min", 0.28), 0.28)
    status = state.get("slot_completeness_status") or "unknown"
    can_refresh = planner_to_bool(state.get("slot_completeness_can_refresh_geometry"))
    geometry_reliable = planner_to_bool(state.get("geometry_reliable", True))
    quad_topology_valid = planner_to_bool(state.get("quad_topology_valid", True))
    belief_source = (
        source
        or state.get("belief_source")
        or ("predicted_post_action" if state.get("precomputed_from_action_id") else None)
        or state.get("source")
        or "unknown"
    )
    status_reliable = status in ("complete", "trusted")
    low_visible = (not visible_ratio_known) or visible_ratio < visible_min
    visual_reliable = bool(status_reliable and can_refresh and geometry_reliable and quad_topology_valid and not low_visible)
    predicted_source = bool(
        belief_source == "predicted_post_action" or state.get("precomputed_from_action_id"))
    unreliable = bool(
        active and
        not visual_reliable and
        (
            (not can_refresh) or (not status_reliable) or low_visible or
            predicted_source or (not geometry_reliable) or (not quad_topology_valid)
        )
    )
    ignore_enabled = bool(getattr(args, "terminal_unreliable_vision_ignore_slot_x_px", True))
    ignored_slot_x = bool(ignore_enabled and unreliable)
    return {
        "schema": "parking_terminal_unreliable_vision_review.v1",
        "terminal_zone": active,
        "terminal_vision_reliable": bool(visual_reliable),
        "terminal_vision_unreliable": unreliable,
        "ignored_terminal_slot_x_err_px": ignored_slot_x,
        "x_ok_source": (
            "ignored_unreliable_terminal_vision" if ignored_slot_x else "slot_x_err_px_gate"),
        "checks": {
            "ignore_slot_x_enabled": ignore_enabled,
            "terminal_zone": active,
            "visual_reliable": bool(visual_reliable),
            "low_visible_ratio": bool(low_visible),
            "status_reliable": bool(status_reliable),
            "can_refresh_geometry": bool(can_refresh),
            "geometry_reliable": bool(geometry_reliable),
            "quad_topology_valid": bool(quad_topology_valid),
            "predicted_source": bool(predicted_source),
        },
        "metrics": {
            "slot_visible_ratio": round(visible_ratio, 6),
            "slot_visible_ratio_known": bool(visible_ratio_known),
            "slot_completeness_status": status,
            "can_refresh_geometry": bool(can_refresh),
            "geometry_reliable": bool(geometry_reliable),
            "quad_topology_valid": bool(quad_topology_valid),
            "quad_topology_status": state.get("quad_topology_status"),
            "quad_topology_reasons": list(state.get("quad_topology_reasons") or []),
            "belief_source": belief_source,
            "slot_completeness_reasons": list(state.get("slot_completeness_reasons") or []),
            "slot_y_dist_cm": round(y_dist, 3),
        },
        "thresholds": {
            "terminal_y_dist_cm": terminal_y,
            "visible_ratio_min": visible_min,
            "unreliable_max_lateral_cm": planner_to_float(
                getattr(args, "terminal_unreliable_vision_max_lateral_cm", 5.0), 5.0),
            "unreliable_max_heading_deg": planner_to_float(
                getattr(args, "terminal_unreliable_vision_max_heading_deg", 4.0), 4.0),
            "unreliable_min_margin_px": planner_to_float(
                getattr(args, "terminal_unreliable_vision_min_margin_px", 120.0), 120.0),
        },
    }


def replanner_belief_terminal_review(belief, args):
    state = belief or {}
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    x_err = abs(planner_to_float(state.get("slot_x_err_px")))
    heading = abs(planner_to_float(state.get("slot_heading_err_deg")))
    lateral = abs(planner_to_float(state.get("slot_lateral_cm")))
    min_margin = planner_to_float(state.get("min_margin_px"))
    terminal_y = planner_to_float(
        getattr(args, "replanner_belief_terminal_stop_y_dist_cm", 12.0), 12.0)
    active = y_dist <= terminal_y
    vision_review = terminal_unreliable_vision_review(
        state, args, terminal_zone=active, source=state.get("belief_source"))
    ignore_slot_x = bool(vision_review.get("ignored_terminal_slot_x_err_px"))
    max_x_err = planner_to_float(
        getattr(args, "replanner_belief_terminal_max_x_err_px", 16.0), 16.0)
    max_heading = planner_to_float(
        getattr(args, "replanner_belief_terminal_max_heading_deg", 3.0), 3.0)
    max_lateral = planner_to_float(
        getattr(args, "replanner_belief_terminal_max_lateral_cm", 1.5), 1.5)
    min_margin_gate = planner_to_float(
        getattr(args, "replanner_belief_min_margin_px", 80.0), 80.0)
    if ignore_slot_x:
        max_heading = planner_to_float(
            getattr(args, "terminal_unreliable_vision_max_heading_deg", 4.0), 4.0)
        max_lateral = planner_to_float(
            getattr(args, "terminal_unreliable_vision_max_lateral_cm", 5.0), 5.0)
        min_margin_gate = planner_to_float(
            getattr(args, "terminal_unreliable_vision_min_margin_px", 120.0), 120.0)
    heading_ok_source = "heading_err_gate"
    raw_max_heading = max_heading
    predicted_heading_relaxed = False
    if (
        ignore_slot_x and
        bool(vision_review.get("terminal_vision_unreliable")) and
        bool((vision_review.get("checks") or {}).get("predicted_source")) and
        bool(getattr(args, "terminal_unreliable_vision_relax_predicted_heading", True))
    ):
        hard_heading = planner_to_float(
            getattr(args, "terminal_unreliable_vision_hard_heading_deg", 18.0), 18.0)
        max_heading = max(max_heading, hard_heading)
        predicted_heading_relaxed = True
        heading_ok_source = "relaxed_unreliable_predicted_heading"
    checks = {
        "terminal_zone": active,
        "x_ok": True if ignore_slot_x else x_err <= max_x_err,
        "heading_ok": heading <= max_heading,
        "lateral_ok": lateral <= max_lateral,
        "margin_ok": min_margin >= min_margin_gate,
        "line_risk_clear": not bool(state.get("line_risk")),
    }
    pose_ok = all(value for key, value in checks.items() if key != "terminal_zone")
    return {
        "schema": "parking_replanner_belief_terminal_review.v1",
        "active": active,
        "pass": (not active) or pose_ok,
        "pose_ok": pose_ok,
        "checks": checks,
        "metrics": {
            "slot_y_dist_cm": round(y_dist, 3),
            "slot_x_err_px_abs": round(x_err, 3),
            "raw_slot_x_err_px_abs": round(x_err, 3),
            "slot_heading_err_deg_abs": round(heading, 3),
            "slot_lateral_cm_abs": round(lateral, 3),
            "min_margin_px": round(min_margin, 3),
            "terminal_vision_reliable": bool(vision_review.get("terminal_vision_reliable")),
            "ignored_terminal_slot_x_err_px": ignore_slot_x,
            "x_ok_source": vision_review.get("x_ok_source"),
            "raw_slot_heading_err_deg_abs": round(heading, 3),
            "predicted_heading_relaxed": bool(predicted_heading_relaxed),
            "heading_ok_source": heading_ok_source,
        },
        "thresholds": {
            "terminal_y_dist_cm": terminal_y,
            "max_x_err_px": max_x_err,
            "max_heading_deg": max_heading,
            "raw_max_heading_deg": raw_max_heading,
            "max_lateral_cm": max_lateral,
            "min_margin_px": min_margin_gate,
        },
        "terminal_vision": vision_review,
    }


def replanner_lateral_recovery_context(action, current_lat_abs, args):
    replanner = action.get("replanner") or {}
    chosen = replanner.get("chosen") or {}
    action_id = chosen.get("action_id")
    if not args.replanner_allow_lateral_recovery:
        return {"active": False, "reason": "disabled"}
    if action.get("action") != "ARC":
        return {"active": False, "reason": "not_arc"}
    if not action_id or action_id in ("WAIT", "STOP"):
        return {"active": False, "reason": "no_action_id"}
    selected = None
    for item in replanner.get("ranking") or []:
        if item.get("action_id") == action_id:
            selected = item
            break
    if not selected:
        return {"active": False, "reason": "missing_ranked_action"}
    predicted = selected.get("predicted") or {}
    pred_lat = planner_to_float(predicted.get("slot_lateral_cm"), None)
    pred_margin = planner_to_float(predicted.get("min_margin_px"), 0.0)
    pred_line_risk = bool(predicted.get("line_risk"))
    if pred_lat is None:
        return {"active": False, "reason": "missing_predicted_lateral"}
    predicted_gain = abs(current_lat_abs) - abs(pred_lat)
    checks = {
        "predicted_lateral_improves": predicted_gain >= args.replanner_lateral_recovery_min_gain_cm,
        "predicted_margin_ok": pred_margin >= args.replanner_lateral_recovery_min_margin_px,
        "predicted_line_safe": not pred_line_risk,
        "chosen_not_blocked": not bool(selected.get("hard_blocked")),
    }
    return {
        "active": all(checks.values()),
        "reason": "predicted_lateral_recovery" if all(checks.values()) else "checks_failed",
        "checks": checks,
        "current_lateral_abs_cm": round(abs(current_lat_abs), 3),
        "predicted_lateral_abs_cm": round(abs(pred_lat), 3),
        "predicted_lateral_gain_cm": round(predicted_gain, 3),
        "predicted_min_margin_px": round(pred_margin, 2),
        "action_id": action_id,
    }


def lateral_divergence_context_from_state(rel_state, cur_lat_abs):
    corridor = rel_state.get("corridor") or {}
    ground = rel_state.get("ground_estimate") or {}
    return {
        "lateral_abs_cm": round(abs(float(cur_lat_abs)), 3),
        "slot_x_err_abs_px": round(abs(planner_to_float(corridor.get("slot_x_err_px"))), 3),
        "slot_entry_x_err_abs_px": round(abs(planner_to_float(corridor.get("slot_entry_x_err_px"))), 3),
        "slot_y_dist_cm": round(planner_to_float(ground.get("slot_y_dist_cm")), 3),
    }


def lateral_divergence_review(rel_state, best_lat_abs, best_context, cur_lat_abs, args):
    vision = rel_state.get("vision") or {}
    completeness = rel_state.get("completeness") or {}
    corridor = rel_state.get("corridor") or {}
    ground = rel_state.get("ground_estimate") or {}
    gates = rel_state.get("gates") or {}
    reasons = set(completeness.get("reasons") or [])
    visible_ratio = planner_to_float(vision.get("slot_visible_ratio"), 0.0)
    slot_y_dist = planner_to_float(ground.get("slot_y_dist_cm"), 999.0)
    slot_x_abs = abs(planner_to_float(corridor.get("slot_x_err_px")))
    slot_entry_x_abs = abs(planner_to_float(corridor.get("slot_entry_x_err_px")))
    min_visible = max(0.0, float(getattr(args, "lateral_divergence_min_visible_ratio", LATERAL_DIV_MIN_VISIBLE_RATIO)))
    partial_y = max(0.0, float(getattr(args, "lateral_divergence_partial_y_dist_cm", LATERAL_DIV_PARTIAL_Y_DIST_CM)))
    x_growth_min = max(0.0, float(getattr(args, "lateral_divergence_x_err_growth_px", LATERAL_DIV_X_ERR_GROWTH_PX)))
    raw_diverged = best_lat_abs is not None and abs(cur_lat_abs) > abs(best_lat_abs) + LATERAL_DIV_CM
    near_border = "near_image_border" in reasons
    low_visible = visible_ratio > 0.0 and visible_ratio < min_visible
    close_partial_slot = slot_y_dist <= partial_y and (near_border or low_visible)
    can_refresh = bool(completeness.get(
        "can_refresh_geometry",
        completeness.get("status") == "complete",
    ))
    stable_frames = int(planner_to_float(rel_state.get("stable_frames"), 0))
    required_stable = max(1, int(planner_to_float(rel_state.get("required_stable_frames"), 1)))
    stable_enough = stable_frames >= required_stable and bool(gates.get("stable_enough", True))
    line_risk = bool(corridor.get("line_risk"))
    geometry_reliable = bool(
        can_refresh
        and stable_enough
        and not line_risk
        and not near_border
        and visible_ratio >= min_visible
    )
    best_slot_x_abs = None
    best_slot_entry_x_abs = None
    if isinstance(best_context, dict):
        best_slot_x_abs = best_context.get("slot_x_err_abs_px")
        best_slot_entry_x_abs = best_context.get("slot_entry_x_err_abs_px")
    pixel_confirms = True
    pixel_growth = None
    entry_pixel_growth = None
    if best_slot_x_abs is not None:
        pixel_growth = slot_x_abs - planner_to_float(best_slot_x_abs)
        pixel_confirms = pixel_growth >= x_growth_min
    if best_slot_entry_x_abs is not None:
        entry_pixel_growth = slot_entry_x_abs - planner_to_float(best_slot_entry_x_abs)
        pixel_confirms = pixel_confirms or entry_pixel_growth >= x_growth_min
    stop_eligible = bool(raw_diverged and geometry_reliable and pixel_confirms)
    if raw_diverged and not geometry_reliable:
        reason = "defer_unreliable_geometry"
    elif raw_diverged and not pixel_confirms:
        reason = "defer_without_pixel_confirmation"
    elif stop_eligible:
        reason = "confirmed_lateral_divergence"
    else:
        reason = "no_divergence"
    return {
        "schema": "lateral_divergence_review.v1",
        "raw_diverged": bool(raw_diverged),
        "stop_eligible": stop_eligible,
        "reason": reason,
        "can_update_best": bool(geometry_reliable),
        "best_lateral_abs_cm": None if best_lat_abs is None else round(abs(best_lat_abs), 3),
        "current_lateral_abs_cm": round(abs(cur_lat_abs), 3),
        "current_slot_x_err_abs_px": round(slot_x_abs, 3),
        "current_slot_entry_x_err_abs_px": round(slot_entry_x_abs, 3),
        "best_slot_x_err_abs_px": None if best_slot_x_abs is None else round(planner_to_float(best_slot_x_abs), 3),
        "best_slot_entry_x_err_abs_px": None if best_slot_entry_x_abs is None else round(planner_to_float(best_slot_entry_x_abs), 3),
        "slot_x_err_growth_px": None if pixel_growth is None else round(pixel_growth, 3),
        "slot_entry_x_err_growth_px": None if entry_pixel_growth is None else round(entry_pixel_growth, 3),
        "pixel_confirms": bool(pixel_confirms),
        "geometry_reliable": bool(geometry_reliable),
        "close_partial_slot": bool(close_partial_slot),
        "near_image_border": bool(near_border),
        "low_visible_ratio": bool(low_visible),
        "visible_ratio": round(visible_ratio, 6),
        "min_visible_ratio": round(min_visible, 6),
        "slot_y_dist_cm": round(slot_y_dist, 3),
        "partial_y_dist_cm": round(partial_y, 3),
        "stable_enough": bool(stable_enough),
        "can_refresh_geometry": bool(can_refresh),
        "line_risk": bool(line_risk),
        "completeness_status": completeness.get("status"),
        "completeness_reasons": sorted(reasons),
    }


def log_event(log_file, event):
    if not log_file:
        return
    event = dict(event)
    event.setdefault("time_unix", time.time())
    with open(log_file, "a", encoding="utf-8") as f:
        f.write(json.dumps(event, ensure_ascii=False, separators=(",", ":")) + "\n")


def step_timing_start(label="step"):
    now = time.perf_counter()
    return {
        "schema": "parking_step_timing.v1",
        "label": label,
        "_t0": now,
        "_last": now,
        "segments": [],
    }


def step_timing_mark(timer, name, **extra):
    if not timer:
        return
    now = time.perf_counter()
    segment = {
        "name": name,
        "dt_ms": round((now - timer.get("_last", now)) * 1000.0, 3),
        "elapsed_ms": round((now - timer.get("_t0", now)) * 1000.0, 3),
    }
    if extra:
        segment.update(extra)
    timer.setdefault("segments", []).append(segment)
    timer["_last"] = now


def step_timing_finish(timer):
    if not timer:
        return None
    now = time.perf_counter()
    out = {
        "schema": timer.get("schema", "parking_step_timing.v1"),
        "label": timer.get("label", "step"),
        "total_ms": round((now - timer.get("_t0", now)) * 1000.0, 3),
        "segments": list(timer.get("segments", [])),
    }
    return out


def load_chassis_kinematics(path):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except OSError:
        return {"schema": "missing", "steer_curvature": []}


def kinematics_row_for_ste(kinematics, ste):
    for row in (kinematics or {}).get("steer_curvature", []):
        try:
            if int(round(float(row.get("ste")))) == int(round(float(ste))):
                return row
        except (TypeError, ValueError):
            continue
    return None


def stat_yaw_from_text(text):
    for ev in parse_stm32_events(text or ""):
        if ev.get("type") == "stat" and ev.get("yaw") is not None:
            return planner_to_float(ev.get("yaw"))
    return None


def stat_d_from_text(text):
    for ev in parse_stm32_events(text or ""):
        if ev.get("type") == "stat" and ev.get("d") is not None:
            return abs(planner_to_float(ev.get("d")))
    return None


def angle_delta_deg(delta):
    if wrap_degrees is not None:
        return wrap_degrees(delta)
    while delta > 180.0:
        delta -= 360.0
    while delta <= -180.0:
        delta += 360.0
    return delta


DIY_FAST_ODOM_STE_CANDIDATES = (120, 105, 100, 75, 60)


def _diy_round_pose(pose):
    if not pose:
        return None
    return {
        "y_dist_cm": round(planner_to_float(pose.get("y_dist_cm")), 3),
        "lateral_cm": round(planner_to_float(pose.get("lateral_cm")), 3),
        "heading_deg": round(planner_to_float(pose.get("heading_deg")), 3),
    }


def _diy_finite(value):
    try:
        v = float(value)
    except (TypeError, ValueError):
        return False
    return math.isfinite(v)


def diy_fast_odom_pose_from_flat(flat):
    flat = flat or {}
    y_dist = planner_to_float(flat.get("slot_y_dist_cm"), None)
    lateral = planner_to_float(flat.get("slot_lateral_cm"), None)
    heading = planner_to_float(flat.get("slot_heading_err_deg"), None)
    if not (_diy_finite(y_dist) and _diy_finite(lateral) and _diy_finite(heading)):
        return None
    return {
        "y_dist_cm": float(y_dist),
        "lateral_cm": float(lateral),
        "heading_deg": angle_delta_deg(float(heading)),
    }


def diy_fast_odom_observation_from_info(info, args, filt=None):
    if info is None or "target_selection_wait" in info:
        return None
    stable = False
    metrics = {}
    fused = info
    if filt is not None:
        try:
            stable, metrics = filt.add(info, observing_static=True)
            fused = filt.fused() if stable else info
        except Exception as exc:
            metrics = {"stable": False, "error": str(exc)}
            stable = False
            fused = info
    rel_state = slot_relative_state(fused, args, metrics)
    flat = planner_flatten_slot_state(rel_state, stable, {
        "raw_detection_count": int(planner_to_float(fused.get("raw_detection_count"), 0)),
        "raw_detection_index": fused.get("raw_detection_index"),
        "raw_detection_id": fused.get("raw_detection_id"),
        "mask_polygon_point_count": int(planner_to_float(fused.get("mask_polygon_point_count"), 0)),
        "slot_polygon_px": deepcopy_jsonable(fused.get("mask_polygon_px") or []),
        "fresh_visual": True,
    })
    return {
        "info": fused,
        "stable": bool(stable),
        "stability": metrics,
        "rel_state": rel_state,
        "flat": flat,
        "pose": diy_fast_odom_pose_from_flat(flat),
        "candidate": summarize_slot_candidate(fused, args),
    }


def diy_fast_odom_has_mask(flat):
    flat = flat or {}
    if int(planner_to_float(flat.get("mask_polygon_point_count"), 0)) >= 3:
        return True
    for key in ("slot_polygon_px", "mask_polygon_px", "mask_polygon"):
        if len(flat.get(key) or []) >= 3:
            return True
    return False


def diy_fast_odom_initial_lock_review(observation, args):
    flat = (observation or {}).get("flat") or {}
    pose = (observation or {}).get("pose")
    confidence = planner_to_float(flat.get("confidence"), 0.0)
    min_margin = planner_to_float(flat.get("min_margin_px"), None)
    y_dist = None if pose is None else pose.get("y_dist_cm")
    checks = {
        "fresh_visual": observation is not None,
        "detection_count": int(planner_to_float(flat.get("raw_detection_count"), 0)) >= 1,
        "mask_polygon": diy_fast_odom_has_mask(flat),
        "confidence": confidence >= args.diy_min_initial_confidence,
        "line_risk_clear": not planner_to_bool(flat.get("line_risk")),
        "slot_y_dist_reasonable": _diy_finite(y_dist) and 0.0 <= float(y_dist) <= 120.0,
        "ground_slot_solver_available": str(flat.get("solver_status") or "complete") != "rejected",
    }
    failed = [name for name, ok in checks.items() if not ok]
    return {
        "schema": "diy_fast_odom_initial_lock_review.v1",
        "pass": not failed,
        "reason": "ok" if not failed else "blocked_" + failed[0],
        "failed_checks": failed,
        "checks": checks,
        "confidence": round(confidence, 4),
        "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
        "min_margin_used_for_lock": False,
        "min_margin_hard_stop_disabled": True,
        "pose": pose,
        "visual_state": flat,
    }


def diy_fast_odom_visual_review(observation, current_pose, args):
    if observation is None:
        return {
            "schema": "diy_fast_odom_visual_review.v1",
            "tier": "none",
            "reason": "no_fresh_yolo",
            "visual_available": False,
            "correction_used": False,
        }
    flat = observation.get("flat") or {}
    visual_pose = observation.get("pose")
    confidence = planner_to_float(flat.get("confidence"), 0.0)
    min_margin = planner_to_float(flat.get("min_margin_px"), None)
    has_mask = diy_fast_odom_has_mask(flat)
    trusted_for_safety = bool(has_mask and confidence >= args.diy_min_correction_confidence)
    line_risk = planner_to_bool(flat.get("line_risk"))
    if trusted_for_safety and line_risk:
        return {
            "schema": "diy_fast_odom_visual_review.v1",
            "tier": "danger",
            "reason": "line_risk_true",
            "visual_available": True,
            "trusted_for_safety": True,
            "confidence": round(confidence, 4),
            "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
            "min_margin_used_for_stop": False,
            "min_margin_hard_stop_disabled": True,
            "visual_state": flat,
            "visual_pose": visual_pose,
        }
    correction_checks = {
        "mask_polygon": has_mask,
        "confidence": confidence >= args.diy_min_correction_confidence,
        "line_risk_clear": not line_risk,
        "visual_pose": visual_pose is not None,
        "ground_slot_solver_available": str(flat.get("solver_status") or "complete") != "rejected",
    }
    pose_delta = None
    if current_pose is not None and visual_pose is not None:
        pose_delta = {
            "y_dist_cm": visual_pose["y_dist_cm"] - current_pose["y_dist_cm"],
            "lateral_cm": visual_pose["lateral_cm"] - current_pose["lateral_cm"],
            "heading_deg": angle_delta_deg(visual_pose["heading_deg"] - current_pose["heading_deg"]),
        }
        # H1 fast path relies primarily on odom/IMU after lock; fresh vision is
        # a weak correction signal.  Do not reject the entire correction path
        # for moderate post-motion pose jumps caused by partial masks.  Keep
        # the check, but make the H1 profile medium-loose and log the exact
        # limits used.
        default_pose_delta_y = 28.0 if diy_path_profile_is_h1_fast10(args) else 20.0
        default_pose_delta_lateral = 16.0 if diy_path_profile_is_h1_fast10(args) else 12.0
        default_pose_delta_heading = 28.0 if diy_path_profile_is_h1_fast10(args) else 20.0
        max_pose_delta_y = planner_to_float(
            getattr(args, "diy_path_visual_correction_pose_delta_y_cm", default_pose_delta_y),
            default_pose_delta_y)
        max_pose_delta_lateral = planner_to_float(
            getattr(args, "diy_path_visual_correction_pose_delta_lateral_cm", default_pose_delta_lateral),
            default_pose_delta_lateral)
        max_pose_delta_heading = planner_to_float(
            getattr(args, "diy_path_visual_correction_pose_delta_heading_deg", default_pose_delta_heading),
            default_pose_delta_heading)
        correction_checks["pose_delta_reasonable"] = (
            abs(pose_delta["y_dist_cm"]) <= float(max_pose_delta_y) and
            abs(pose_delta["lateral_cm"]) <= float(max_pose_delta_lateral) and
            abs(pose_delta["heading_deg"]) <= float(max_pose_delta_heading)
        )
        correction_checks["pose_delta_limits"] = {
            "y_dist_cm": round(float(max_pose_delta_y), 3),
            "lateral_cm": round(float(max_pose_delta_lateral), 3),
            "heading_deg": round(float(max_pose_delta_heading), 3),
        }
    failed = [name for name, ok in correction_checks.items() if not ok and name != "pose_delta_limits"]
    if not failed:
        return {
            "schema": "diy_fast_odom_visual_review.v1",
            "tier": "correction",
            "reason": "low_weight_visual_correction",
            "visual_available": True,
            "trusted_for_safety": trusted_for_safety,
            "confidence": round(confidence, 4),
            "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
            "min_margin_used_for_stop": False,
            "min_margin_used_for_correction": False,
            "min_margin_hard_stop_disabled": True,
            "pose_delta": None if pose_delta is None else {
                "y_dist_cm": round(pose_delta["y_dist_cm"], 3),
                "lateral_cm": round(pose_delta["lateral_cm"], 3),
                "heading_deg": round(pose_delta["heading_deg"], 3),
            },
            "visual_state": flat,
            "visual_pose": visual_pose,
        }
    return {
        "schema": "diy_fast_odom_visual_review.v1",
        "tier": "ignore",
        "reason": "visual_not_reliable_for_correction",
        "failed_checks": failed,
        "checks": correction_checks,
        "visual_available": True,
        "trusted_for_safety": trusted_for_safety,
        "confidence": round(confidence, 4),
        "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
        "min_margin_used_for_stop": False,
        "min_margin_used_for_correction": False,
        "min_margin_hard_stop_disabled": True,
        "pose_delta": None if pose_delta is None else {
            "y_dist_cm": round(pose_delta["y_dist_cm"], 3),
            "lateral_cm": round(pose_delta["lateral_cm"], 3),
            "heading_deg": round(pose_delta["heading_deg"], 3),
        },
        "visual_state": flat,
        "visual_pose": visual_pose,
    }


def diy_fast_odom_fuse_pose(odom_pose, visual_pose, alpha):
    alpha = clamp(float(alpha), 0.0, 1.0)
    return {
        "y_dist_cm": (1.0 - alpha) * odom_pose["y_dist_cm"] + alpha * visual_pose["y_dist_cm"],
        "lateral_cm": (1.0 - alpha) * odom_pose["lateral_cm"] + alpha * visual_pose["lateral_cm"],
        "heading_deg": angle_delta_deg(
            odom_pose["heading_deg"] +
            alpha * angle_delta_deg(visual_pose["heading_deg"] - odom_pose["heading_deg"])
        ),
    }


def diy_fast_odom_expected_progress(command_abs_cm, kinematics):
    arc_deadband = planner_to_float((kinematics or {}).get("arc_deadband_cm"), DEADBAND_CM)
    coast = planner_to_float((kinematics or {}).get("coast_after_done_cm"), 0.0)
    return max(0.0, float(command_abs_cm) - arc_deadband + coast)


def diy_fast_odom_deg_per_cm_for_ste(kinematics, ste):
    row = kinematics_row_for_ste(kinematics, ste)
    if row is not None:
        return planner_to_float(row.get("deg_per_cm"), 0.0), row, False
    center = int(round(planner_to_float((kinematics or {}).get("servo_center_trim_ste"), SERVO_CENTER)))
    if int(round(float(ste))) == center:
        return 0.0, {"ste": center, "deg_per_cm": 0.0, "source": "servo_center_trim_ste"}, False
    return 0.0, None, True


def diy_fast_odom_integrate_pose_legacy_yaw_delta_frame(pose, progress_cm, yaw_delta_deg):
    """Legacy pose update kept for diagnostics only.

    This rotates the whole slot-relative vector by the measured yaw delta.
    In practice that makes lateral change scale with the current y distance
    (large y * small yaw), so blind lateral can look much better than the car
    actually moved.  The active path below uses the vehicle heading during the
    measured odom step instead.
    """
    progress = max(0.0, planner_to_float(progress_cm, 0.0))
    yaw_delta = angle_delta_deg(planner_to_float(yaw_delta_deg, 0.0))
    dpsi = math.radians(yaw_delta)
    qx = pose["y_dist_cm"] - progress * math.cos(dpsi / 2.0)
    qy = pose["lateral_cm"] - progress * math.sin(dpsi / 2.0)
    c, s = math.cos(-dpsi), math.sin(-dpsi)
    return {
        "y_dist_cm": c * qx - s * qy,
        "lateral_cm": s * qx + c * qy,
        "heading_deg": angle_delta_deg(pose["heading_deg"] + yaw_delta),
    }


def diy_fast_odom_integrate_pose(pose, progress_cm, yaw_delta_deg):
    """Integrate one measured reverse step in the slot frame.

    Inputs are board feedback, not command intent:
    - ``progress_cm`` comes from STM32 odom/DONE D after the action.
    - ``yaw_delta_deg`` comes from IMU yaw after-before.

    The old blind update used only yaw_delta to rotate the whole current
    slot-vector; that can create a large artificial lateral correction while
    the car is still far from the slot.  The correct small-car dead-reckon
    update translates along the vehicle's current heading over the measured
    step, using midpoint heading for a short arc, then applies yaw_delta to
    heading.
    """
    progress = max(0.0, planner_to_float(progress_cm, 0.0))
    yaw_delta = angle_delta_deg(planner_to_float(yaw_delta_deg, 0.0))
    heading0 = angle_delta_deg(planner_to_float(pose.get("heading_deg"), 0.0))
    heading_mid = angle_delta_deg(heading0 + 0.5 * yaw_delta)
    theta = math.radians(heading_mid)
    return {
        "y_dist_cm": pose["y_dist_cm"] - progress * math.cos(theta),
        "lateral_cm": pose["lateral_cm"] + progress * math.sin(theta),
        "heading_deg": angle_delta_deg(heading0 + yaw_delta),
    }


def diy_fast_odom_action_from_ste(ste, command_abs_cm):
    cmd = "ARC D=-%.1f STE=%d V=%d" % (round(float(command_abs_cm), 1), int(round(float(ste))), GEAR)
    kind, step, servo = _parse_motion_command_for_action(cmd)
    return {
        "state": "DIY_FAST_ODOM_REVERSE_STEP",
        "action": kind,
        "cmd": cmd,
        "step": round(step, 3),
        "servo": servo,
        "steer_dir": 0.0 if servo == SERVO_CENTER else (1.0 if servo > SERVO_CENTER else -1.0),
        "reason": "diy_fast_odom_template_candidate",
        "binding": {
            "distance_cm": round(step, 3),
            "distance_reason": "diy_4cm_odom_template",
            "servo": servo,
            "gear": GEAR,
            "gear_reason": "diy_fast_odom_short_step",
        },
    }


def diy_fast_odom_score_prediction(pred_pose, progress_cm, args):
    danger_penalty = 0.0
    if pred_pose["y_dist_cm"] < -5.0:
        danger_penalty += 1000.0
    if abs(pred_pose["lateral_cm"]) > max(24.0, args.diy_lateral_tol_cm * 3.0):
        danger_penalty += 120.0
    if abs(pred_pose["heading_deg"]) > max(45.0, args.diy_heading_tol_deg * 4.0):
        danger_penalty += 120.0
    score = (
        abs(pred_pose["lateral_cm"]) * 3.0 +
        abs(pred_pose["heading_deg"]) * 2.5 +
        abs(pred_pose["y_dist_cm"] - args.diy_target_y_dist_cm) * 1.2 -
        progress_cm * 2.0 +
        danger_penalty
    )
    return score, danger_penalty


def diy_fast_odom_select_action(pose, state, args, kinematics):
    command_abs_cm = max(0.0, float(args.diy_step_cm))
    candidates = []
    for ste in DIY_FAST_ODOM_STE_CANDIDATES:
        action = diy_fast_odom_action_from_ste(ste, command_abs_cm)
        deg_per_cm, row, missing_kinematics = diy_fast_odom_deg_per_cm_for_ste(kinematics, ste)
        expected_progress = diy_fast_odom_expected_progress(command_abs_cm, kinematics)
        yaw_delta = deg_per_cm * expected_progress
        pred_pose = diy_fast_odom_integrate_pose(pose, expected_progress, yaw_delta)
        score, danger_penalty = diy_fast_odom_score_prediction(pred_pose, expected_progress, args)
        hard_block = bool(
            command_abs_cm <= 0.0 or
            missing_kinematics or
            state.get("total_reverse_cm", 0.0) + expected_progress > args.diy_max_total_cm or
            pred_pose["y_dist_cm"] < -8.0 or
            abs(pred_pose["heading_deg"]) > 70.0 or
            abs(pred_pose["lateral_cm"]) > 40.0
        )
        row_out = {
            "ste": int(ste),
            "cmd": action["cmd"],
            "action": action,
            "expected_progress_cm": round(expected_progress, 3),
            "deg_per_cm": round(deg_per_cm, 6),
            "predicted_yaw_delta_deg": round(yaw_delta, 3),
            "predicted_pose": _diy_round_pose(pred_pose),
            "score": round(score, 3),
            "danger_penalty": round(danger_penalty, 3),
            "hard_block": hard_block,
            "block_reason": "missing_kinematics" if missing_kinematics else (
                "hard_safety_projection" if hard_block else "ok"
            ),
            "kinematics_row": deepcopy_jsonable(row) if row is not None else None,
        }
        candidates.append(row_out)
    valid = [row for row in candidates if not row["hard_block"]]
    valid.sort(key=lambda row: (row["score"], abs(row["ste"] - int(round(SERVO_CENTER)))))
    chosen = valid[0] if valid else None
    return {
        "schema": "diy_fast_odom_action_selection.v1",
        "candidates": candidates,
        "chosen": chosen,
        "chosen_action": None if chosen is None else chosen["action"],
        "reason": "ok" if chosen is not None else "no_safe_candidate",
    }


def diy_fast_odom_stop_review(state, args):
    pose = state.get("pose") or {}
    checks = {
        "parked": bool(
            pose and
            pose.get("y_dist_cm", 999.0) <= args.diy_target_y_dist_cm and
            abs(pose.get("lateral_cm", 999.0)) <= args.diy_lateral_tol_cm and
            abs(pose.get("heading_deg", 999.0)) <= args.diy_heading_tol_deg
        ),
        "visionless_budget_exceeded": int(state.get("visionless_steps", 0)) > args.diy_max_visionless_steps,
        "odom_no_progress": int(state.get("no_progress_count", 0)) >= args.diy_odom_no_progress_stop_count,
        "max_total_cm": float(state.get("total_reverse_cm", 0.0)) > args.diy_max_total_cm,
        "max_steps": int(state.get("steps", 0)) >= args.diy_max_steps,
    }
    reason = "continue"
    stop_now = False
    success = False
    if checks["parked"]:
        stop_now = True
        success = True
        reason = "parked"
    elif checks["visionless_budget_exceeded"]:
        stop_now = True
        reason = "visionless_budget_exceeded"
    elif checks["odom_no_progress"]:
        stop_now = True
        reason = "odom_no_progress"
    elif checks["max_total_cm"]:
        stop_now = True
        reason = "max_total_cm_exceeded"
    elif checks["max_steps"]:
        stop_now = True
        reason = "max_steps_reached"
    return {
        "schema": "diy_fast_odom_stop_review.v1",
        "stop": stop_now,
        "success": success,
        "reason": reason,
        "checks": checks,
        "pose": _diy_round_pose(pose),
        "steps": int(state.get("steps", 0)),
        "total_reverse_cm": round(float(state.get("total_reverse_cm", 0.0)), 3),
        "total_forward_shuffle_cm": round(float(state.get("total_forward_shuffle_cm", 0.0)), 3),
        "terminal_shuffle_count": int(state.get("terminal_shuffle_count", 0)),
        "terminal_shuffle_last_kind": state.get("terminal_shuffle_last_kind"),
        "visionless_steps": int(state.get("visionless_steps", 0)),
        "no_progress_count": int(state.get("no_progress_count", 0)),
        "final_strong_turn_used_count": int(state.get("final_strong_turn_used_count", 0)),
    }


def diy_fast_odom_motion_result(action, st, st_after, motion_events, args):
    last = getattr(args, "_last_execute_logged_motion_result", {}) or {}
    motion_text = last.get("motion_response", "")
    pre_servo_text = last.get("pre_servo_response", "")
    events = list(motion_events or last.get("motion_events") or [])
    err_events = [ev for ev in events if ev.get("type") == "err"]
    ack_seen = any(ev.get("type") == "ack" for ev in events)
    done_seen = any(
        ev.get("type") == "done" and str(ev.get("cmd", "")).upper() in ("MOVE", "ARC")
        for ev in events
    )
    guard_stop = "GUARD_STOP" in str(motion_text)
    button_stop = (
        "BUTTON_STOP" in str(motion_text).upper() or
        "GUARD_STOP reason=button_stop" in str(motion_text) or
        any(
            ev.get("type") == "err" and str(ev.get("code", "")).upper() == "BUTTON_STOP"
            for ev in events
        )
    )
    pre_servo_ok = (not pre_servo_text) or stm32_response_ok(pre_servo_text)
    stat_yaw_ok = st_after.get("yaw") is not None
    require_imu_ok = motion_requires_imu_ok(args)
    imu_before_review = last.get("imu_before_review") or stm32_stat_imu_review(st, require_ok=require_imu_ok)
    imu_after_review = last.get("imu_after_review") or stm32_stat_imu_review(st_after, require_ok=require_imu_ok)
    imu_before_ok = bool(imu_before_review.get("ok"))
    imu_after_ok = bool(imu_after_review.get("ok"))
    odom_progress_cm = None
    if st_after.get("d") is not None:
        candidate_progress = abs(float(st_after["d"]))
        if 0.0 <= candidate_progress <= max(1.0, planner_to_float(action.get("step"), 0.0) * 1.8):
            odom_progress_cm = candidate_progress
    if odom_progress_cm is None:
        for ev in events:
            if ev.get("type") == "done" and ev.get("d") is not None:
                candidate_progress = abs(planner_to_float(ev.get("d"), 0.0))
                if 0.0 <= candidate_progress <= max(1.0, planner_to_float(action.get("step"), 0.0) * 1.8):
                    odom_progress_cm = candidate_progress
                    break
    yaw_delta = None
    if st.get("yaw") is not None and st_after.get("yaw") is not None:
        yaw_delta = angle_delta_deg(float(st_after["yaw"]) - float(st["yaw"]))
    done_or_raw_ok = done_seen or (not events and stm32_response_ok(motion_text))
    min_guard_progress_cm = max(0.0, planner_to_float(getattr(args, "motion_min_progress_cm", 0.4), 0.4))
    guard_stop_overridden = bool(
        guard_stop and done_seen and not err_events and
        odom_progress_cm is not None and
        odom_progress_cm >= min_guard_progress_cm
    )
    guard_stop_blocking = bool(guard_stop and not guard_stop_overridden)
    ok = bool(
        done_or_raw_ok and pre_servo_ok and not err_events and not guard_stop_blocking and
        stat_yaw_ok and odom_progress_cm is not None and
        ((not require_imu_ok) or (imu_before_ok and imu_after_ok))
    )
    if ok:
        reason = "ok"
    elif button_stop:
        reason = "button_stop"
    elif require_imu_ok and not imu_before_ok:
        reason = "imu_fault_before_motion"
    elif require_imu_ok and not imu_after_ok:
        reason = "imu_fault_after_motion"
    elif guard_stop_blocking:
        reason = "guard_stop"
    else:
        reason = "stm32_command_failed"
    return {
        "schema": "diy_fast_odom_stm32_result.v1",
        "ok": ok,
        "reason": reason,
        "ack_seen": ack_seen,
        "done_seen": done_seen,
        "err_events": err_events,
        "guard_stop": guard_stop,
        "button_stop": button_stop,
        "guard_stop_overridden": guard_stop_overridden,
        "guard_stop_blocking": guard_stop_blocking,
        "min_guard_progress_cm": round(min_guard_progress_cm, 3),
        "pre_servo_ok": pre_servo_ok,
        "stat_yaw_ok": stat_yaw_ok,
        "require_imu_ok": bool(require_imu_ok),
        "imu_before_review": imu_before_review,
        "imu_after_review": imu_after_review,
        "odom_progress_cm": None if odom_progress_cm is None else round(odom_progress_cm, 3),
        "yaw_delta_deg": None if yaw_delta is None else round(yaw_delta, 3),
        "stat_before": st.get("raw", ""),
        "stat_after": st_after.get("raw", ""),
        "motion_response": motion_text,
        "motion_events": events,
    }


def diy_fast_odom_log_stop(args, state, reason, review=None, extra=None):
    event = {
        "event": "diy_fast_odom_stop",
        "phase": state.get("phase"),
        "reason": reason,
        "state": {
            "pose": _diy_round_pose(state.get("pose")),
            "locked_pose": _diy_round_pose(state.get("locked_pose")),
            "steps": int(state.get("steps", 0)),
            "visionless_steps": int(state.get("visionless_steps", 0)),
            "no_progress_count": int(state.get("no_progress_count", 0)),
            "total_reverse_cm": round(float(state.get("total_reverse_cm", 0.0)), 3),
            "total_forward_recovery_cm": round(float(state.get("total_forward_recovery_cm", 0.0)), 3),
            "last_yaw_deg": state.get("last_yaw_deg"),
        },
        "stop_review": review,
        "send_to_stm32": False,
        "motion_enabled": False,
        "actuator_control_allowed": False,
    }
    if extra:
        event.update(extra)
    log_event(args.log_jsonl, event)
    return event


def diy_fast_odom_acquire_info(sock, wait_sec, args):
    """Read one fresh YOLO/mask slot without target-selector stability hard gates."""
    end = time.time() + max(0.0, float(wait_sec))
    while True:
        raw = recv_latest(sock)
        if raw is not None:
            infos = slot_infos_from_udp(
                raw,
                getattr(args, "slot_class_names", DEFAULT_SLOT_CLASS_NAMES),
                completeness_args=args,
            )
            if infos:
                return max(infos, key=lambda item: float(item.get("confidence", 0.0)))
        if time.time() >= end:
            return None
        time.sleep(0.02)


def run_diy_fast_odom_parking(args, sock, filt, chassis_kinematics, pose_fuser,
                              no_motion, armed, deadline):
    del pose_fuser  # shadow-only fusion is not part of this odom-template mainline.
    state = {
        "phase": "WAIT_INITIAL_SLOT",
        "pose": None,
        "locked_pose": None,
        "total_reverse_cm": 0.0,
        "total_forward_recovery_cm": 0.0,
        "visionless_steps": 0,
        "no_progress_count": 0,
        "last_yaw_deg": None,
        "previous_heading_deg": None,
        "steps": 0,
    }
    print("  diy_fast_odom=ON step_cm=%.1f max_steps=%d max_total_cm=%.1f max_visionless=%d" % (
        args.diy_step_cm,
        args.diy_max_steps,
        args.diy_max_total_cm,
        args.diy_max_visionless_steps,
    ), flush=True)
    while True:
        if deadline is not None and time.time() >= deadline:
            review = diy_fast_odom_stop_review(state, args)
            diy_fast_odom_log_stop(args, state, "duration_elapsed", review)
            print("STOP=DIY_FAST_ODOM_DURATION elapsed.", flush=True)
            if not no_motion:
                stop()
            return 0

        loop_timing = step_timing_start("diy_fast_odom_loop")
        wait_sec = args.target_wait_sec
        if deadline is not None:
            wait_sec = max(0.0, min(wait_sec, deadline - time.time()))
        info = diy_fast_odom_acquire_info(sock, wait_sec, args)
        step_timing_mark(loop_timing, "udp_acquire", got_info=bool(info))
        observation = diy_fast_odom_observation_from_info(info, args, filt) if info is not None else None
        step_timing_mark(loop_timing, "visual_review_prepare", visual_available=bool(observation))

        if state["phase"] == "WAIT_INITIAL_SLOT":
            lock_review = diy_fast_odom_initial_lock_review(observation, args)
            if not lock_review.get("pass"):
                log_event(args.log_jsonl, {
                    "event": "diy_fast_odom_wait_initial",
                    "phase": state["phase"],
                    "reason": lock_review.get("reason"),
                    "lock_review": lock_review,
                    "visual_available": observation is not None,
                    "send_to_stm32": False,
                    "motion_enabled": False,
                    "actuator_control_allowed": False,
                    "step_timing": step_timing_finish(loop_timing),
                })
                print("WAIT=DIY_FAST_ODOM_INITIAL %s." % lock_review.get("reason"), flush=True)
                time.sleep(args.settle_sec)
                continue
            st = {"yaw": 0.0, "raw": ""}
            if not no_motion:
                st = read_stat()
                if st.get("yaw") is None:
                    diy_fast_odom_log_stop(args, state, "stm32_stat_yaw_missing_on_lock", lock_review)
                    print("STOP=DIY_FAST_ODOM_STAT_YAW_MISSING.", flush=True)
                    stop()
                    return 8
            state["pose"] = dict(lock_review["pose"])
            state["locked_pose"] = dict(lock_review["pose"])
            state["last_yaw_deg"] = st.get("yaw")
            state["phase"] = "FAST_TEMPLATE_LOOP"
            log_event(args.log_jsonl, {
                "event": "diy_fast_odom_lock",
                "phase": "LOCK_SLOT_POSE",
                "lock_review": lock_review,
                "locked_pose": _diy_round_pose(state["locked_pose"]),
                "initial_stat": st.get("raw", ""),
                "last_yaw_deg": state["last_yaw_deg"],
                "visual_candidate": None if observation is None else observation.get("candidate"),
                "send_to_stm32": False,
                "motion_enabled": False,
                "actuator_control_allowed": False,
                "step_timing": step_timing_finish(loop_timing),
            })
            print("DIY_FAST_ODOM_LOCK y=%.1f lat=%.1f head=%.1f conf=%.2f." % (
                state["pose"]["y_dist_cm"],
                state["pose"]["lateral_cm"],
                state["pose"]["heading_deg"],
                lock_review.get("confidence", 0.0),
            ), flush=True)
            time.sleep(args.settle_sec)
            continue

        pose_before_visual = dict(state["pose"])
        visual_review = diy_fast_odom_visual_review(observation, state["pose"], args)
        correction_used = False
        if visual_review.get("tier") == "danger":
            review = diy_fast_odom_stop_review(state, args)
            diy_fast_odom_log_stop(args, state, visual_review.get("reason"), review, {
                "visual_review": visual_review,
                "step_timing": step_timing_finish(loop_timing),
            })
            print("STOP=DIY_FAST_ODOM_VISUAL_DANGER %s." % visual_review.get("reason"), flush=True)
            if not no_motion:
                stop()
            return 0
        if visual_review.get("tier") == "correction":
            state["pose"] = diy_fast_odom_fuse_pose(
                state["pose"],
                visual_review["visual_pose"],
                args.diy_visual_correction_alpha,
            )
            state["visionless_steps"] = 0
            correction_used = True
        else:
            state["visionless_steps"] += 1

        stop_review = diy_fast_odom_stop_review(state, args)
        if stop_review.get("stop"):
            diy_fast_odom_log_stop(args, state, stop_review.get("reason"), stop_review, {
                "visual_review": visual_review,
                "pose_before_visual": _diy_round_pose(pose_before_visual),
                "pose_after_visual": _diy_round_pose(state["pose"]),
                "visual_correction_used": correction_used,
                "step_timing": step_timing_finish(loop_timing),
            })
            print("STOP=DIY_FAST_ODOM_%s." % str(stop_review.get("reason", "STOP")).upper(), flush=True)
            if not no_motion:
                stop()
            return 0

        selection = diy_fast_odom_select_action(state["pose"], state, args, chassis_kinematics)
        action = selection.get("chosen_action")
        if action is None:
            review = diy_fast_odom_stop_review(state, args)
            diy_fast_odom_log_stop(args, state, "no_safe_candidate", review, {
                "visual_review": visual_review,
                "action_selection": selection,
                "step_timing": step_timing_finish(loop_timing),
            })
            print("STOP=DIY_FAST_ODOM_NO_SAFE_CANDIDATE.", flush=True)
            if not no_motion:
                stop()
            return 0

        pose_before_motion = dict(state["pose"])
        chosen = selection["chosen"]
        motion_result = None
        if no_motion:
            progress_cm = planner_to_float(chosen.get("expected_progress_cm"), 0.0)
            yaw_delta = planner_to_float(chosen.get("predicted_yaw_delta_deg"), 0.0)
            state["pose"] = diy_fast_odom_integrate_pose(state["pose"], progress_cm, yaw_delta)
            motion_result = {
                "schema": "diy_fast_odom_stm32_result.v1",
                "ok": True,
                "simulated": True,
                "reason": "dry_run_simulated",
                "odom_progress_cm": round(progress_cm, 3),
                "yaw_delta_deg": round(yaw_delta, 3),
                "candidate_cmd": action["cmd"],
            }
            print("DIY_FAST_ODOM -> %s [no-motion simulated]" % action["cmd"], flush=True)
        else:
            if not armed:
                review = diy_fast_odom_stop_review(state, args)
                diy_fast_odom_log_stop(args, state, "not_armed", review, {
                    "candidate_cmd": action["cmd"],
                    "step_timing": step_timing_finish(loop_timing),
                })
                print("STOP=DIY_FAST_ODOM_NOT_ARMED.", flush=True)
                return 7
            print("DIY_FAST_ODOM -> %s" % action["cmd"], flush=True)
            try:
                st, st_after, motion_events = execute_logged_motion(action, args, pose_fuser=None)
            finally:
                stop()
            motion_result = diy_fast_odom_motion_result(action, st, st_after, motion_events, args)
            if not motion_result.get("ok"):
                log_event(args.log_jsonl, {
                    "event": "diy_fast_odom_step",
                    "phase": state.get("phase"),
                    "locked_pose": _diy_round_pose(state.get("locked_pose")),
                    "estimated_pose_before": _diy_round_pose(pose_before_motion),
                    "estimated_pose_after": _diy_round_pose(state.get("pose")),
                    "visual_available": observation is not None,
                    "visual_review": visual_review,
                    "visual_correction_used": correction_used,
                    "candidate_actions": selection.get("candidates"),
                    "chosen_action": chosen,
                    "stm32_result": motion_result,
                    "stop_review": {"stop": True, "reason": motion_result.get("reason")},
                    "send_to_stm32": True,
                    "motion_enabled": True,
                    "actuator_control_allowed": True,
                    "step_timing": step_timing_finish(loop_timing),
                })
                diy_fast_odom_log_stop(args, state, motion_result.get("reason"), None, {
                    "stm32_result": motion_result,
                    "candidate_cmd": action["cmd"],
                })
                print("STOP=DIY_FAST_ODOM_STM32_COMMAND_FAILED.", flush=True)
                return 8
            progress_cm = planner_to_float(motion_result.get("odom_progress_cm"), 0.0)
            yaw_delta = planner_to_float(motion_result.get("yaw_delta_deg"), 0.0)
            state["pose"] = diy_fast_odom_integrate_pose(state["pose"], progress_cm, yaw_delta)
            state["last_yaw_deg"] = st_after.get("yaw")

        if progress_cm < 0.5:
            state["no_progress_count"] += 1
        else:
            state["no_progress_count"] = 0
        state["total_reverse_cm"] += max(0.0, progress_cm)
        state["steps"] += 1
        stop_review_after = diy_fast_odom_stop_review(state, args)
        log_event(args.log_jsonl, {
            "event": "diy_fast_odom_step",
            "phase": state.get("phase"),
            "locked_pose": _diy_round_pose(state.get("locked_pose")),
            "estimated_pose_before": _diy_round_pose(pose_before_motion),
            "estimated_pose_after": _diy_round_pose(state.get("pose")),
            "pose_before_visual": _diy_round_pose(pose_before_visual),
            "pose_after_visual": _diy_round_pose(state.get("pose")),
            "visual_available": observation is not None,
            "visual_review": visual_review,
            "visual_correction_used": correction_used,
            "candidate_actions": selection.get("candidates"),
            "chosen_action": chosen,
            "stm32_result": motion_result,
            "stop_review": stop_review_after,
            "steps": state["steps"],
            "total_reverse_cm": round(state["total_reverse_cm"], 3),
            "visionless_steps": state["visionless_steps"],
            "no_progress_count": state["no_progress_count"],
            "final_strong_turn_used_count": state.get("final_strong_turn_used_count", 0),
            "send_to_stm32": bool(not no_motion),
            "motion_enabled": bool(not no_motion),
            "actuator_control_allowed": bool(not no_motion),
            "step_timing": step_timing_finish(loop_timing),
        })
        print("DIY_FAST_ODOM_STEP %d progress=%.2f yaw_delta=%.2f pose y=%.1f lat=%.1f head=%.1f." % (
            state["steps"],
            progress_cm,
            yaw_delta,
            state["pose"]["y_dist_cm"],
            state["pose"]["lateral_cm"],
            state["pose"]["heading_deg"],
        ), flush=True)

        if stop_review_after.get("stop"):
            diy_fast_odom_log_stop(args, state, stop_review_after.get("reason"), stop_review_after)
            print("STOP=DIY_FAST_ODOM_%s." % str(stop_review_after.get("reason", "STOP")).upper(), flush=True)
            if not no_motion:
                stop()
            return 0

        if no_motion:
            time.sleep(args.settle_sec)
        else:
            post_motion_perception_reset(sock, filt, None, args, "diy_fast_odom_step")


def diy_path_pose_from_flat(flat):
    return diy_fast_odom_pose_from_flat(flat)


def _diy_path_reason_list(value):
    if value is None:
        return []
    if isinstance(value, (list, tuple, set)):
        out = []
        for item in value:
            out.extend(_diy_path_reason_list(item))
        return out
    if isinstance(value, dict):
        return [str(k) for k, v in value.items() if v]
    text = str(value).strip()
    if not text:
        return []
    if "," in text:
        return [part.strip() for part in text.split(",") if part.strip()]
    return [text]


def _diy_path_bool(value, default=False):
    if value is None or value == "":
        return bool(default)
    return planner_to_bool(value)


def _diy_path_round_float(value, digits=3):
    v = planner_to_float(value, None)
    if not _diy_finite(v):
        return None
    return round(float(v), int(digits))


def diy_path_initial_quad_truth_review(flat, pose, args):
    flat = flat or {}
    enabled = bool(getattr(args, "diy_path_initial_quad_truth_gate", True))
    pose = pose or {}
    confidence = planner_to_float(flat.get("confidence"), 0.0)
    all_reasons = sorted(set(
        _diy_path_reason_list(flat.get("slot_completeness_reasons")) +
        _diy_path_reason_list(flat.get("quad_fit_reasons")) +
        _diy_path_reason_list(flat.get("quad_topology_reasons"))
    ))
    reason_set = set(all_reasons)
    quad_fit_status = str(flat.get("quad_fit_status") or "").strip()
    quad_topology_status = str(flat.get("quad_topology_status") or "").strip()
    visible_ratio = planner_to_float(flat.get("slot_visible_ratio"), None)
    lateral_cm = planner_to_float(pose.get("lateral_cm"), None)
    raw = {
        "quad_fit_status": quad_fit_status or None,
        "quad_fit_source": flat.get("quad_fit_source"),
        "quad_fit_reasons": _diy_path_reason_list(flat.get("quad_fit_reasons")),
        "quad_fit_score": _diy_path_round_float(flat.get("quad_fit_score")),
        "quad_fit_input_source": flat.get("quad_fit_input_source"),
        "quad_topology_valid": _diy_path_bool(flat.get("quad_topology_valid"), True),
        "quad_topology_status": quad_topology_status or None,
        "quad_topology_reasons": _diy_path_reason_list(flat.get("quad_topology_reasons")),
        "entry_edge_visible": _diy_path_bool(flat.get("entry_edge_visible"), True),
        "entrance_reliable": _diy_path_bool(flat.get("entrance_reliable"), True),
        "side_edges_reliable": _diy_path_bool(flat.get("side_edges_reliable"), True),
        "slot_visible_ratio": _diy_path_round_float(visible_ratio, 6),
        "slot_completeness_status": flat.get("slot_completeness_status"),
        "slot_completeness_reasons": _diy_path_reason_list(flat.get("slot_completeness_reasons")),
        "slot_y_dist_cm": _diy_path_round_float(pose.get("y_dist_cm")),
        "lateral_cm": _diy_path_round_float(lateral_cm),
        "heading_deg": _diy_path_round_float(pose.get("heading_deg")),
        "min_margin_px": _diy_path_round_float(flat.get("min_margin_px")),
        "confidence": _diy_path_round_float(confidence, 4),
        "mask_polygon_point_count": int(planner_to_float(flat.get("mask_polygon_point_count"), 0)),
        "all_reasons": all_reasons,
    }
    if not enabled:
        return {
            "schema": "diy_path_initial_quad_truth_review.v1",
            "enabled": False,
            "pass": True,
            "checks": {},
            "failed_checks": [],
            "reject_reason": "disabled",
            "lock_target_type": "gate_disabled",
            "raw": raw,
        }

    max_lateral = planner_to_float(getattr(args, "diy_path_initial_max_abs_lateral_cm", 25.0), 25.0)
    min_visible = planner_to_float(getattr(args, "diy_path_initial_min_visible_ratio", 0.10), 0.10)
    partial_or_worse = quad_fit_status != "complete"
    topology_valid = bool(raw["quad_topology_valid"]) and quad_topology_status == "valid"
    entry_reliable = bool(raw["entry_edge_visible"]) and bool(raw["entrance_reliable"])
    near_border = "near_image_border" in reason_set
    hard_shape_reasons = {
        "entrance_unreliable",
        "side_edges_unreliable",
        "missing_entry_edge",
    }
    soft_shape_reasons = {
        "opposite_width_mismatch",
        "angle_not_rectangular",
    }
    shape_suspect = bool(reason_set.intersection(hard_shape_reasons))
    # H1/ground-plane solver mode: a low visible ratio is common when the car is
    # near/inside the slot and the mask is clipped by the camera view.  Keep it
    # as diagnostic data only; do not use it as an initial hard reject and do
    # not let it make the mask look "line-like" by itself.
    visible_ratio_low = (not _diy_finite(visible_ratio)) or float(visible_ratio) < float(min_visible)
    visible_ratio_hard_gate_disabled = True
    lateral_out = (not _diy_finite(lateral_cm)) or abs(float(lateral_cm)) > float(max_lateral)
    line_like_combo = bool(
        (not bool(raw["entrance_reliable"]) and quad_fit_status == "partial_usable") or
        (lateral_out and quad_topology_status != "valid") or
        (not bool(raw["entry_edge_visible"]) and "entrance_unreliable" in reason_set)
    )
    checks = {
        "initial_line_like_or_pseudo_quad": not (
            bool(getattr(args, "diy_path_initial_reject_line_like_mask", True)) and line_like_combo
        ),
        "initial_quad_not_complete": not (
            bool(getattr(args, "diy_path_initial_reject_partial_quad", True)) and partial_or_worse
        ),
        "initial_quad_topology_not_valid": not (
            bool(getattr(args, "diy_path_initial_require_quad_topology_valid", True)) and not topology_valid
        ),
        "initial_entry_edge_unreliable": not (
            bool(getattr(args, "diy_path_initial_require_entry_edge", True)) and not entry_reliable
        ),
        "initial_quad_near_image_border": not (
            bool(getattr(args, "diy_path_initial_reject_near_border", True)) and near_border
        ),
        "initial_quad_shape_suspect": not (
            bool(getattr(args, "diy_path_initial_reject_entrance_unreliable", True)) and shape_suspect
        ),
        "initial_visible_ratio_too_low": True,
        "initial_lateral_out_of_box": not lateral_out,
    }
    failed = [name for name, ok in checks.items() if not ok]

    # H1/DIY small-car mode: the current mask model can output a visually
    # excellent slot polygon while legacy topology/completeness checks still
    # mark it suspect because the sampled corridor/entry edge is outside the
    # visible camera area.  Do not let those legacy soft-shape diagnostics
    # block the first-frame lock when the mask is high-confidence, the solver
    # produced a finite pose, and the only failures are geometric/topology
    # review checks.  Keep the real hard stops in diy_path_initial_lock_review:
    # no mask, low confidence, line_risk, rejected ground solver, invalid pose.
    trust_standard_mask = bool(getattr(args, "diy_path_initial_trust_standard_mask", False))
    trust_conf = planner_to_float(
        getattr(args, "diy_path_initial_trust_mask_confidence", 0.85), 0.85)
    mask_point_count = int(raw.get("mask_polygon_point_count") or 0)
    y_dist_cm = planner_to_float(pose.get("y_dist_cm"), None)
    heading_deg = planner_to_float(pose.get("heading_deg"), None)
    soft_quad_failures = {
        "initial_quad_not_complete",
        "initial_quad_topology_not_valid",
        "initial_entry_edge_unreliable",
        "initial_quad_near_image_border",
        "initial_quad_shape_suspect",
        "initial_visible_ratio_too_low",
    }
    trust_mask_pose_ok = bool(
        _diy_finite(y_dist_cm) and 0.0 <= float(y_dist_cm) <= 120.0 and
        _diy_finite(lateral_cm) and abs(float(lateral_cm)) <= float(max_lateral) and
        _diy_finite(heading_deg) and abs(float(heading_deg)) <= 60.0
    )
    # Medium initial gate for the H1/DIY path profile.
    #
    # The previous relaxation only accepted a very high-confidence mask
    # (default 0.85).  In the live tabletop scene YOLO can produce a stable
    # mask with confidence around 0.65~0.75, complete ground solver output and
    # good pose, while the legacy quad topology checker still reports
    # ``initial_quad_topology_not_valid`` because the mask edge is locally
    # irregular.  Treat those topology/entry/near-border shape checks as
    # medium-confidence soft gates, but still fail closed on no mask, rejected
    # solver, invalid pose, line-like pseudo quads, partial/rejected quad fits,
    # or excessive lateral offset.
    medium_gate_value = getattr(args, "diy_path_initial_medium_gate_enable", None)
    medium_gate_enabled = (
        bool(diy_path_profile_is_h1_fast10(args)) if medium_gate_value is None
        else bool(medium_gate_value)
    )
    medium_conf = planner_to_float(
        getattr(args, "diy_path_initial_medium_gate_confidence", 0.65), 0.65)
    medium_solver_quality_min = planner_to_float(
        getattr(args, "diy_path_initial_medium_gate_solver_quality", 0.80), 0.80)
    solver_status = str(flat.get("solver_status") or "complete").strip().lower()
    solver_quality = planner_to_float(
        flat.get("solver_quality", flat.get("pose_quality")), 0.0)
    medium_relaxable_failures = {
        "initial_quad_topology_not_valid",
        "initial_entry_edge_unreliable",
        "initial_quad_near_image_border",
        "initial_quad_shape_suspect",
        "initial_visible_ratio_too_low",
    }
    # H1 lattice/fast profiles: allow a high-confidence partial_usable
    # ground-pose lock.  The current tabletop mask can be locally clipped or
    # line-like at the entrance while the homography solver still returns a
    # stable, finite slot pose.  This relaxation is intentionally after the
    # base checks, so no detection/no mask/low confidence/line_risk/rejected
    # solver still fail closed.  Keep this *very* permissive for H1 because
    # the later loop is short-step STOP/observe/replan and does not depend on
    # perfect first-frame quad topology.
    partial_gate_value = getattr(args, "diy_path_initial_h1_partial_mask_relax_enable", None)
    partial_gate_enabled = (
        bool(diy_path_profile_is_h1_fast10(args)) if partial_gate_value is None
        else bool(partial_gate_value)
    )
    partial_conf = planner_to_float(
        getattr(args, "diy_path_initial_h1_partial_mask_relax_confidence", 0.70), 0.70)
    partial_solver_quality_min = planner_to_float(
        getattr(args, "diy_path_initial_h1_partial_mask_relax_solver_quality", 0.25), 0.25)
    partial_relaxable_failures = set(soft_quad_failures) | {
        "initial_line_like_or_pseudo_quad",
    }
    partial_gate_relax_ok = bool(
        partial_gate_enabled and
        float(confidence) >= float(partial_conf) and
        solver_status in ("complete", "usable", "ok", "partial_usable") and
        float(solver_quality) >= float(partial_solver_quality_min) and
        mask_point_count >= 4 and
        quad_fit_status not in ("", "rejected", "none") and
        trust_mask_pose_ok and
        not lateral_out and
        set(failed).issubset(partial_relaxable_failures)
    )
    medium_gate_relax_ok = bool(
        medium_gate_enabled and
        float(confidence) >= float(medium_conf) and
        solver_status in ("complete", "usable", "ok", "partial_usable") and
        float(solver_quality) >= float(medium_solver_quality_min) and
        mask_point_count >= 4 and
        quad_fit_status == "complete" and
        trust_mask_pose_ok and
        not line_like_combo and
        not lateral_out and
        set(failed).issubset(medium_relaxable_failures)
    )
    trust_mask_relax_ok = bool(
        trust_standard_mask and
        float(confidence) >= float(trust_conf) and
        mask_point_count >= 4 and
        quad_fit_status not in ("", "rejected", "none") and
        trust_mask_pose_ok and
        not line_like_combo and
        not lateral_out and
        set(failed).issubset(soft_quad_failures)
    )
    effective_failed = [] if (trust_mask_relax_ok or medium_gate_relax_ok or partial_gate_relax_ok) else list(failed)
    reject_reason = effective_failed[0] if effective_failed else "ok"
    lock_target_type = "true_box"
    if reject_reason == "initial_line_like_or_pseudo_quad":
        lock_target_type = "rejected_line_like"
    elif partial_gate_relax_ok and failed:
        lock_target_type = "h1_partial_mask_relaxed"
    elif medium_gate_relax_ok and failed:
        lock_target_type = "medium_solver_relaxed"
    elif trust_mask_relax_ok and failed:
        lock_target_type = "trusted_standard_mask_relaxed"
    elif effective_failed:
        lock_target_type = "rejected_pseudo_quad"
    return {
        "schema": "diy_path_initial_quad_truth_review.v1",
        "enabled": True,
        "pass": not effective_failed,
        "checks": checks,
        "failed_checks": failed,
        "effective_failed_checks": effective_failed,
        "reject_reason": reject_reason,
        "lock_target_type": lock_target_type,
        "standard_mask_relax": {
            "enabled": bool(trust_standard_mask),
            "used": bool(trust_mask_relax_ok and failed),
            "confidence": round(float(confidence), 4),
            "min_confidence": float(trust_conf),
            "mask_polygon_point_count": int(mask_point_count),
            "pose_ok": bool(trust_mask_pose_ok),
            "relaxable_failures": sorted(soft_quad_failures),
            "original_failed_checks": list(failed),
        },
        "medium_gate_relax": {
            "enabled": bool(medium_gate_enabled),
            "used": bool(medium_gate_relax_ok and failed),
            "confidence": round(float(confidence), 4),
            "min_confidence": float(medium_conf),
            "solver_status": solver_status,
            "solver_quality": round(float(solver_quality), 4),
            "min_solver_quality": float(medium_solver_quality_min),
            "mask_polygon_point_count": int(mask_point_count),
            "pose_ok": bool(trust_mask_pose_ok),
            "quad_fit_status": quad_fit_status or None,
            "relaxable_failures": sorted(medium_relaxable_failures),
            "original_failed_checks": list(failed),
        },
        "h1_partial_mask_relax": {
            "enabled": bool(partial_gate_enabled),
            "used": bool(partial_gate_relax_ok and failed),
            "confidence": round(float(confidence), 4),
            "min_confidence": float(partial_conf),
            "solver_status": solver_status,
            "solver_quality": round(float(solver_quality), 4),
            "min_solver_quality": float(partial_solver_quality_min),
            "mask_polygon_point_count": int(mask_point_count),
            "pose_ok": bool(trust_mask_pose_ok),
            "quad_fit_status": quad_fit_status or None,
            "relaxable_failures": sorted(partial_relaxable_failures),
            "original_failed_checks": list(failed),
        },
        "thresholds": {
            "max_abs_lateral_cm": float(max_lateral),
            "min_visible_ratio": float(min_visible),
            "visible_ratio_hard_gate_disabled": bool(visible_ratio_hard_gate_disabled),
            "visible_ratio_low_log_only": bool(visible_ratio_low),
        },
        "hard_shape_reasons": sorted(hard_shape_reasons),
        "soft_shape_reasons_log_only": sorted(reason_set.intersection(soft_shape_reasons)),
        "raw": raw,
    }


def diy_path_initial_lock_review(observation, args):
    flat = (observation or {}).get("flat") or {}
    pose = (observation or {}).get("pose")
    confidence = planner_to_float(flat.get("confidence"), 0.0)
    min_margin = planner_to_float(flat.get("min_margin_px"), None)
    y_dist = None if pose is None else pose.get("y_dist_cm")
    line_risk_review = diy_path_margin_line_risk_review(flat, args)
    raw_line_risk = planner_to_bool(flat.get("line_risk"))
    effective_line_risk = planner_to_bool(line_risk_review.get("effective_line_risk"))
    checks = {
        "fresh_visual": observation is not None,
        "detection_count": int(planner_to_float(flat.get("raw_detection_count"), 0)) >= 1,
        "mask_polygon": diy_fast_odom_has_mask(flat),
        "confidence": confidence >= args.diy_path_min_initial_confidence,
        "line_risk_clear": not effective_line_risk,
        "slot_pose_available": pose is not None,
        "slot_y_dist_reasonable": _diy_finite(y_dist) and 0.0 <= float(y_dist) <= 120.0,
        "ground_slot_solver_available": str(flat.get("solver_status") or "complete") != "rejected",
    }
    base_failed = [name for name, ok in checks.items() if not ok]
    quad_truth_review = diy_path_initial_quad_truth_review(flat, pose, args)
    failed = list(base_failed)
    quad_truth_reject_reason = quad_truth_review.get("reject_reason", "ok")
    if not base_failed and not quad_truth_review.get("pass", False):
        failed.extend(quad_truth_review.get("failed_checks") or [])
        reason = "blocked_initial_quad_truth_gate_" + str(quad_truth_reject_reason)
    else:
        reason = "ok" if not failed else "blocked_" + failed[0]
    return {
        "schema": "diy_path_initial_lock_review.v1",
        "pass": not failed,
        "reason": reason,
        "failed_checks": failed,
        "checks": checks,
        "initial_quad_truth_gate_enabled": bool(quad_truth_review.get("enabled")),
        "quad_truth_checks": quad_truth_review.get("checks", {}),
        "quad_truth_failed_checks": list(quad_truth_review.get("failed_checks") or []),
        "quad_truth_reject_reason": quad_truth_reject_reason,
        "quad_truth_review": quad_truth_review,
        "lock_target_type": quad_truth_review.get("lock_target_type"),
        "confidence": round(confidence, 4),
        "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
        "min_margin_used_for_lock": False,
        "min_margin_hard_stop_disabled": True,
        "raw_line_risk": bool(raw_line_risk),
        "effective_line_risk": bool(effective_line_risk),
        "line_risk_review": line_risk_review,
        "pose": pose,
        "visual_state": flat,
    }


def _diy_path_percentile(values, pct):
    vals = sorted(float(v) for v in values if _diy_finite(v))
    if not vals:
        return None
    if len(vals) == 1:
        return vals[0]
    pos = (len(vals) - 1) * max(0.0, min(100.0, float(pct))) / 100.0
    lo = int(math.floor(pos))
    hi = int(math.ceil(pos))
    if lo == hi:
        return vals[lo]
    frac = pos - lo
    return vals[lo] * (1.0 - frac) + vals[hi] * frac


def _diy_path_median(values):
    return _diy_path_percentile(values, 50.0)


def _diy_path_angle_median(values):
    vals = [float(v) for v in values if _diy_finite(v)]
    if not vals:
        return None
    sin_sum = sum(math.sin(math.radians(v)) for v in vals)
    cos_sum = sum(math.cos(math.radians(v)) for v in vals)
    ref = math.degrees(math.atan2(sin_sum, cos_sum)) if (sin_sum or cos_sum) else vals[0]
    deltas = sorted(angle_delta_deg(v - ref) for v in vals)
    mid = _diy_path_median(deltas)
    return angle_delta_deg(ref + (0.0 if mid is None else mid))


def _diy_path_angle_spread(values, center=None):
    vals = [float(v) for v in values if _diy_finite(v)]
    if not vals:
        return 0.0
    if center is None:
        center = _diy_path_angle_median(vals)
    deltas = [angle_delta_deg(v - center) for v in vals]
    return max(deltas) - min(deltas)


def _diy_path_lock_review_compact(review, frame_index=None):
    review = review or {}
    flat = review.get("visual_state") or {}
    pose = review.get("pose")
    return {
        "frame_index": frame_index,
        "pass": bool(review.get("pass")),
        "reason": review.get("reason"),
        "failed_checks": list(review.get("failed_checks") or []),
        "pose": _diy_round_pose(pose),
        "confidence": review.get("confidence"),
        "solver_status": flat.get("solver_status"),
        "solver_quality": _diy_path_round_float(
            flat.get("solver_quality", flat.get("pose_quality"))),
        "quad_fit_status": flat.get("quad_fit_status"),
        "slot_completeness_status": flat.get("slot_completeness_status"),
        "raw_detection_count": flat.get("raw_detection_count"),
        "mask_polygon_point_count": flat.get("mask_polygon_point_count"),
    }


def diy_path_initial_multiframe_summary(lock_reviews, args, frames_requested=None,
                                        source="median_h1_ground_pose"):
    reviews = list(lock_reviews or [])
    compact_reviews = [
        _diy_path_lock_review_compact(review, idx)
        for idx, review in enumerate(reviews)
    ]
    reason_counts = {}
    for item in compact_reviews:
        reason = item.get("reason") or "unknown"
        reason_counts[reason] = int(reason_counts.get(reason, 0)) + 1

    pass_reviews = [
        review for review in reviews
        if review and review.get("pass") and isinstance(review.get("pose"), dict)
    ]
    min_pass = max(1, int(planner_to_float(
        getattr(args, "diy_path_initial_lock_min_pass_frames", 5), 5)))
    frames_seen = len(reviews)
    if len(pass_reviews) < min_pass:
        return {
            "schema": "diy_path_initial_multiframe_lock.v1",
            "pass": False,
            "reason": "initial_multiframe_not_enough_pass_frames",
            "pose": None,
            "single_frame_reviews": compact_reviews,
            "summary": {
                "frames_requested": int(frames_requested or planner_to_float(
                    getattr(args, "diy_path_initial_lock_frames", 10), 10)),
                "frames_seen": int(frames_seen),
                "pass_frames": int(len(pass_reviews)),
                "min_pass_frames": int(min_pass),
                "rejected_reason_counts": reason_counts,
                "source": source,
            },
        }

    y_values = [planner_to_float(r["pose"].get("y_dist_cm"), None) for r in pass_reviews]
    lat_values = [planner_to_float(r["pose"].get("lateral_cm"), None) for r in pass_reviews]
    head_values = [planner_to_float(r["pose"].get("heading_deg"), None) for r in pass_reviews]
    y_values = [v for v in y_values if _diy_finite(v)]
    lat_values = [v for v in lat_values if _diy_finite(v)]
    head_values = [v for v in head_values if _diy_finite(v)]
    median_y = _diy_path_median(y_values)
    median_lat = _diy_path_median(lat_values)
    median_head = _diy_path_angle_median(head_values)
    if not (_diy_finite(median_y) and _diy_finite(median_lat) and _diy_finite(median_head)):
        return {
            "schema": "diy_path_initial_multiframe_lock.v1",
            "pass": False,
            "reason": "initial_multiframe_pose_missing",
            "pose": None,
            "single_frame_reviews": compact_reviews,
            "summary": {
                "frames_requested": int(frames_requested or 0),
                "frames_seen": int(frames_seen),
                "pass_frames": int(len(pass_reviews)),
                "rejected_reason_counts": reason_counts,
                "source": source,
            },
        }

    spread_y = max(y_values) - min(y_values) if y_values else 0.0
    spread_lat = max(lat_values) - min(lat_values) if lat_values else 0.0
    spread_head = _diy_path_angle_spread(head_values, median_head)
    max_lat_spread = planner_to_float(
        getattr(args, "diy_path_initial_lock_max_lateral_spread_cm", 6.0), 6.0)
    max_head_spread = planner_to_float(
        getattr(args, "diy_path_initial_lock_max_heading_spread_deg", 8.0), 8.0)
    max_y_spread = planner_to_float(
        getattr(args, "diy_path_initial_lock_max_y_spread_cm", 8.0), 8.0)

    median_pose = {
        "y_dist_cm": float(median_y),
        "lateral_cm": float(median_lat),
        "heading_deg": angle_delta_deg(float(median_head)),
    }
    representative_index = None
    representative_score = None
    for idx, review in enumerate(reviews):
        if not (review and review.get("pass") and isinstance(review.get("pose"), dict)):
            continue
        pose = review["pose"]
        score = (
            abs(planner_to_float(pose.get("y_dist_cm"), median_y) - median_y) +
            abs(planner_to_float(pose.get("lateral_cm"), median_lat) - median_lat) +
            abs(angle_delta_deg(planner_to_float(pose.get("heading_deg"), median_head) - median_head)) * 0.5
        )
        if representative_score is None or score < representative_score:
            representative_score = score
            representative_index = idx

    pass_flats = [(r.get("visual_state") or {}) for r in pass_reviews]
    confidence_values = [
        planner_to_float(f.get("confidence"), None) for f in pass_flats
        if _diy_finite(planner_to_float(f.get("confidence"), None))
    ]
    solver_quality_values = [
        planner_to_float(f.get("solver_quality", f.get("pose_quality")), None)
        for f in pass_flats
        if _diy_finite(planner_to_float(f.get("solver_quality", f.get("pose_quality")), None))
    ]

    failed = []
    if spread_lat > max_lat_spread:
        failed.append("lateral_spread")
    if spread_head > max_head_spread:
        failed.append("heading_spread")
    if spread_y > max_y_spread:
        failed.append("y_spread")
    summary = {
        "frames_requested": int(frames_requested or planner_to_float(
            getattr(args, "diy_path_initial_lock_frames", 10), 10)),
        "frames_seen": int(frames_seen),
        "pass_frames": int(len(pass_reviews)),
        "min_pass_frames": int(min_pass),
        "median_pose": _diy_round_pose(median_pose),
        "spread_lateral_cm": round(float(spread_lat), 3),
        "spread_heading_deg": round(float(spread_head), 3),
        "spread_y_cm": round(float(spread_y), 3),
        "max_lateral_spread_cm": round(float(max_lat_spread), 3),
        "max_heading_spread_deg": round(float(max_head_spread), 3),
        "max_y_spread_cm": round(float(max_y_spread), 3),
        "confidence_median": None if not confidence_values else round(float(_diy_path_median(confidence_values)), 4),
        "solver_quality_median": None if not solver_quality_values else round(float(_diy_path_median(solver_quality_values)), 4),
        "selected_representative_frame": representative_index,
        "rejected_reason_counts": reason_counts,
        "source": source,
    }
    return {
        "schema": "diy_path_initial_multiframe_lock.v1",
        "pass": not failed,
        "reason": "ok" if not failed else "initial_multiframe_pose_unstable",
        "failed_checks": failed,
        "pose": median_pose if not failed else None,
        "single_frame_reviews": compact_reviews,
        "summary": summary,
    }


def diy_path_static_recheck_review(primary_lock, recheck_lock, args):
    pose_a = (primary_lock or {}).get("pose") or {}
    pose_b = (recheck_lock or {}).get("pose") or {}
    if not (primary_lock and primary_lock.get("pass") and recheck_lock and recheck_lock.get("pass")):
        return {
            "schema": "diy_path_initial_static_recheck.v1",
            "pass": False,
            "reason": "initial_static_recheck_lock_failed",
            "primary_pass": bool((primary_lock or {}).get("pass")),
            "recheck_pass": bool((recheck_lock or {}).get("pass")),
        }
    delta_lat = planner_to_float(pose_b.get("lateral_cm"), 0.0) - planner_to_float(pose_a.get("lateral_cm"), 0.0)
    delta_y = planner_to_float(pose_b.get("y_dist_cm"), 0.0) - planner_to_float(pose_a.get("y_dist_cm"), 0.0)
    delta_head = angle_delta_deg(
        planner_to_float(pose_b.get("heading_deg"), 0.0) -
        planner_to_float(pose_a.get("heading_deg"), 0.0)
    )
    max_lat = planner_to_float(
        getattr(args, "diy_path_initial_lock_static_recheck_max_lateral_delta_cm", 4.0), 4.0)
    max_head = planner_to_float(
        getattr(args, "diy_path_initial_lock_static_recheck_max_heading_delta_deg", 5.0), 5.0)
    max_y = planner_to_float(
        getattr(args, "diy_path_initial_lock_static_recheck_max_y_delta_cm", 6.0), 6.0)
    failed = []
    if abs(delta_lat) > max_lat:
        failed.append("lateral_delta")
    if abs(delta_head) > max_head:
        failed.append("heading_delta")
    if abs(delta_y) > max_y:
        failed.append("y_delta")
    fused_pose = {
        "y_dist_cm": float(_diy_path_median([pose_a.get("y_dist_cm"), pose_b.get("y_dist_cm")])),
        "lateral_cm": float(_diy_path_median([pose_a.get("lateral_cm"), pose_b.get("lateral_cm")])),
        "heading_deg": float(_diy_path_angle_median([pose_a.get("heading_deg"), pose_b.get("heading_deg")])),
    }
    return {
        "schema": "diy_path_initial_static_recheck.v1",
        "pass": not failed,
        "reason": "ok" if not failed else "initial_static_recheck_mismatch",
        "failed_checks": failed,
        "pose_a": _diy_round_pose(pose_a),
        "pose_b": _diy_round_pose(pose_b),
        "fused_pose": _diy_round_pose(fused_pose),
        "delta_lateral_cm": round(float(delta_lat), 3),
        "delta_y_cm": round(float(delta_y), 3),
        "delta_heading_deg": round(float(delta_head), 3),
        "thresholds": {
            "max_lateral_delta_cm": round(float(max_lat), 3),
            "max_heading_delta_deg": round(float(max_head), 3),
            "max_y_delta_cm": round(float(max_y), 3),
        },
    }


def diy_path_collect_initial_lock_batch(sock, args, filt, deadline=None,
                                        frames_requested=None, timeout_sec=None,
                                        seed_observation=None):
    frames_requested = max(1, int(planner_to_float(
        frames_requested if frames_requested is not None else getattr(args, "diy_path_initial_lock_frames", 10),
        10,
    )))
    timeout_sec = max(0.05, planner_to_float(
        timeout_sec if timeout_sec is not None else getattr(args, "diy_path_initial_lock_timeout_sec", 2.0),
        2.0,
    ))
    end_time = time.time() + timeout_sec
    if deadline is not None:
        end_time = min(end_time, float(deadline))
    reviews = []
    if seed_observation is not None:
        reviews.append(diy_path_initial_lock_review(seed_observation, args))
    while len(reviews) < frames_requested and time.time() < end_time:
        wait_sec = max(0.0, min(
            planner_to_float(getattr(args, "target_wait_sec", 0.25), 0.25),
            end_time - time.time(),
        ))
        info = diy_fast_odom_acquire_info(sock, wait_sec, args)
        observation = diy_fast_odom_observation_from_info(info, args, filt) if info is not None else None
        reviews.append(diy_path_initial_lock_review(observation, args))
    return diy_path_initial_multiframe_summary(
        reviews, args, frames_requested=frames_requested)


def diy_path_initial_multiframe_lock(sock, args, filt, deadline=None,
                                     seed_observation=None):
    primary = diy_path_collect_initial_lock_batch(
        sock, args, filt, deadline=deadline, seed_observation=seed_observation)
    result = dict(primary)
    result["static_recheck_enabled"] = diy_path_initial_lock_static_recheck_enabled(args)
    if not primary.get("pass") or not result["static_recheck_enabled"]:
        return result

    delay = max(0.0, planner_to_float(
        getattr(args, "diy_path_initial_lock_static_recheck_delay_sec", 0.20), 0.20))
    if delay > 0.0:
        time.sleep(delay)
    recheck_frames = min(5, max(1, int(planner_to_float(
        getattr(args, "diy_path_initial_lock_frames", 10), 10))))
    recheck = diy_path_collect_initial_lock_batch(
        sock, args, filt, deadline=deadline,
        frames_requested=recheck_frames,
        timeout_sec=getattr(args, "diy_path_initial_lock_timeout_sec", 2.0),
        seed_observation=None,
    )
    recheck_review = diy_path_static_recheck_review(primary, recheck, args)
    result["static_recheck"] = recheck_review
    result["recheck_lock"] = {
        "pass": bool(recheck.get("pass")),
        "reason": recheck.get("reason"),
        "summary": recheck.get("summary"),
        "pose": _diy_round_pose(recheck.get("pose")),
    }
    if not recheck_review.get("pass"):
        result["pass"] = False
        result["reason"] = recheck_review.get("reason", "initial_static_recheck_mismatch")
        result["failed_checks"] = list(recheck_review.get("failed_checks") or [])
        result["pose"] = None
        return result
    result["pose"] = dict(recheck_review.get("fused_pose") or primary.get("pose"))
    result["summary"] = dict(result.get("summary") or {})
    result["summary"]["median_pose_before_static_recheck"] = _diy_round_pose(primary.get("pose"))
    result["summary"]["median_pose_after_static_recheck"] = _diy_round_pose(result["pose"])
    result["reason"] = "ok"
    result["pass"] = True
    return result


def diy_path_late_visual_safety_suppressed(current_pose, args):
    threshold = planner_to_float(
        getattr(args, "diy_path_ignore_late_visual_safety_after_y_cm", -1.0),
        -1.0,
    )
    if threshold < 0.0 or current_pose is None:
        return False
    y_dist = planner_to_float((current_pose or {}).get("y_dist_cm"), None)
    return _diy_finite(y_dist) and float(y_dist) <= float(threshold)


def diy_path_margin_line_risk_review(flat, args):
    """Classify DIY path line_risk and suppress margin-only pseudo risk.

    In this project the upstream ``line_risk`` bit is generated from corridor
    pixel margin once the slot is visually close.  After removing motion-stage
    min_margin hard stops, treating that same margin-derived bit as a hard
    line stop reintroduces the old failure mode under a different name.  The
    H1 fast profile therefore keeps the raw value in logs but does not let
    margin-only line_risk stop the odom/path loop.
    """
    flat = flat or {}
    raw_line_risk = planner_to_bool(flat.get("line_risk"))
    min_margin = planner_to_float(flat.get("min_margin_px"), None)
    configured_floor = planner_to_float(
        getattr(args, "corridor_min_line_margin_px", 60.0), 60.0)
    line_margin_ok_value = flat.get("line_margin_ok")
    line_margin_known_bad = (
        line_margin_ok_value is not None and
        not planner_to_bool(line_margin_ok_value)
    )
    phase_hint = str(flat.get("phase_hint") or "").strip().lower()
    min_margin_known_low = bool(
        _diy_finite(min_margin) and float(min_margin) < float(configured_floor)
    )
    margin_only = bool(
        raw_line_risk and (
            line_margin_known_bad or
            min_margin_known_low or
            phase_hint == "line_risk_stop"
        )
    )
    suppress_enabled = bool(
        getattr(args, "diy_path_suppress_margin_line_risk_stop", False) or
        diy_path_profile_is_h1_fast10(args)
    )
    suppressed = bool(suppress_enabled and margin_only)
    effective_line_risk = bool(raw_line_risk and not suppressed)
    return {
        "schema": "diy_path_margin_line_risk_review.v1",
        "raw_line_risk": bool(raw_line_risk),
        "effective_line_risk": bool(effective_line_risk),
        "suppress_enabled": bool(suppress_enabled),
        "suppressed": bool(suppressed),
        "suppressed_reason": (
            "margin_derived_line_risk_disabled" if suppressed else ""
        ),
        "margin_only_line_risk": bool(margin_only),
        "line_margin_ok": (
            None if line_margin_ok_value is None else planner_to_bool(line_margin_ok_value)
        ),
        "phase_hint": phase_hint,
        "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
        "corridor_min_line_margin_px": round(float(configured_floor), 3),
        "min_margin_known_low": bool(min_margin_known_low),
        "line_margin_known_bad": bool(line_margin_known_bad),
    }


def diy_path_visual_review(observation, current_pose, args):
    late_visual_safety_suppressed = diy_path_late_visual_safety_suppressed(current_pose, args)
    if observation is None:
        return {
            "schema": "diy_path_visual_review.v1",
            "tier": "none",
            "reason": "no_fresh_yolo",
            "visual_available": False,
            "correction_used": False,
            "late_visual_safety_suppressed": late_visual_safety_suppressed,
        }
    flat = observation.get("flat") or {}
    visual_pose = observation.get("pose")
    confidence = planner_to_float(flat.get("confidence"), 0.0)
    min_margin = planner_to_float(flat.get("min_margin_px"), None)
    has_mask = diy_fast_odom_has_mask(flat)
    trusted_for_safety = bool(has_mask and confidence >= args.diy_path_min_correction_confidence)
    line_risk_review = diy_path_margin_line_risk_review(flat, args)
    raw_line_risk = planner_to_bool(flat.get("line_risk"))
    line_risk = planner_to_bool(line_risk_review.get("effective_line_risk"))
    ignored_danger_reasons = []
    if line_risk_review.get("suppressed"):
        ignored_danger_reasons.append(line_risk_review.get("suppressed_reason"))
    if late_visual_safety_suppressed and trusted_for_safety and line_risk:
        ignored_danger_reasons.append("line_risk_true")
    if trusted_for_safety and line_risk and not late_visual_safety_suppressed:
        return {
            "schema": "diy_path_visual_review.v1",
            "tier": "danger",
            "reason": "line_risk_true",
            "visual_available": True,
            "trusted_for_safety": True,
            "late_visual_safety_suppressed": False,
            "line_risk_review": line_risk_review,
            "raw_line_risk": bool(raw_line_risk),
            "effective_line_risk": bool(line_risk),
            "confidence": round(confidence, 4),
            "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
            "min_margin_used_for_stop": False,
            "min_margin_hard_stop_disabled": True,
            "visual_state": flat,
            "visual_pose": visual_pose,
        }
    correction_checks = {
        "mask_polygon": has_mask,
        "confidence": confidence >= args.diy_path_min_correction_confidence,
        "line_risk_clear": not line_risk,
        "visual_pose": visual_pose is not None,
        "ground_slot_solver_available": str(flat.get("solver_status") or "complete") != "rejected",
    }
    pose_delta = None
    if current_pose is not None and visual_pose is not None:
        pose_delta = {
            "y_dist_cm": visual_pose["y_dist_cm"] - current_pose["y_dist_cm"],
            "lateral_cm": visual_pose["lateral_cm"] - current_pose["lateral_cm"],
            "heading_deg": angle_delta_deg(visual_pose["heading_deg"] - current_pose["heading_deg"]),
        }
        correction_checks["pose_delta_reasonable"] = (
            abs(pose_delta["y_dist_cm"]) <= 20.0 and
            abs(pose_delta["lateral_cm"]) <= 12.0 and
            abs(pose_delta["heading_deg"]) <= 20.0
        )
    failed = [name for name, ok in correction_checks.items() if not ok]
    if not failed:
        return {
            "schema": "diy_path_visual_review.v1",
            "tier": "correction",
            "reason": "low_weight_visual_correction",
            "visual_available": True,
            "trusted_for_safety": trusted_for_safety,
            "late_visual_safety_suppressed": late_visual_safety_suppressed,
            "ignored_danger_reasons": ignored_danger_reasons,
            "line_risk_review": line_risk_review,
            "raw_line_risk": bool(raw_line_risk),
            "effective_line_risk": bool(line_risk),
            "confidence": round(confidence, 4),
            "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
            "min_margin_used_for_stop": False,
            "min_margin_used_for_correction": False,
            "min_margin_hard_stop_disabled": True,
            "pose_delta": None if pose_delta is None else {
                "y_dist_cm": round(pose_delta["y_dist_cm"], 3),
                "lateral_cm": round(pose_delta["lateral_cm"], 3),
                "heading_deg": round(pose_delta["heading_deg"], 3),
            },
            "visual_state": flat,
            "visual_pose": visual_pose,
        }
    return {
        "schema": "diy_path_visual_review.v1",
        "tier": "ignore",
        "reason": "visual_not_reliable_for_correction",
        "failed_checks": failed,
        "checks": correction_checks,
        "visual_available": True,
        "trusted_for_safety": trusted_for_safety,
        "late_visual_safety_suppressed": late_visual_safety_suppressed,
        "ignored_danger_reasons": ignored_danger_reasons,
        "line_risk_review": line_risk_review,
        "raw_line_risk": bool(raw_line_risk),
        "effective_line_risk": bool(line_risk),
        "confidence": round(confidence, 4),
        "min_margin_px": None if min_margin is None else round(float(min_margin), 3),
        "min_margin_used_for_stop": False,
        "min_margin_used_for_correction": False,
        "min_margin_hard_stop_disabled": True,
        "pose_delta": None if pose_delta is None else {
            "y_dist_cm": round(pose_delta["y_dist_cm"], 3),
            "lateral_cm": round(pose_delta["lateral_cm"], 3),
            "heading_deg": round(pose_delta["heading_deg"], 3),
        },
        "visual_state": flat,
        "visual_pose": visual_pose,
    }


def _diy_path_observation_age_sec(observation):
    info = (observation or {}).get("info") or {}
    now = time.time()
    for key in ("time_unix", "timestamp_unix", "timestamp", "ts"):
        value = planner_to_float(info.get(key), None)
        if _diy_finite(value):
            # Ignore frame counters or monotonic-ish non-epoch numbers.  Most
            # board UDP messages have no wall-clock timestamp, and they are
            # acquired synchronously right after STOP, so age=0 is the safe
            # fallback for this weak correction.
            if float(value) > 1_000_000_000:
                return max(0.0, now - float(value))
    return 0.0


def diy_path_lateral_only_visual_correction_review(odom_pose, observation,
                                                   full_visual_review, args):
    enabled = diy_path_lateral_only_visual_correction_enabled(args)
    base = {
        "schema": "diy_path_lateral_only_visual_correction.v1",
        "enabled": bool(enabled),
        "applied": False,
        "reason": "disabled" if not enabled else "not_evaluated",
    }
    if not enabled:
        return base, odom_pose
    if observation is None:
        base["reason"] = "no_fresh_yolo"
        return base, odom_pose
    if (full_visual_review or {}).get("tier") == "danger":
        base["reason"] = (full_visual_review or {}).get("reason", "visual_danger")
        return base, odom_pose
    flat = observation.get("flat") or {}
    visual_pose = observation.get("pose")
    current_pose = dict(odom_pose or {})
    confidence = planner_to_float(flat.get("confidence"), 0.0)
    solver_quality = planner_to_float(flat.get("solver_quality", flat.get("pose_quality")), 0.0)
    solver_status = str(flat.get("solver_status") or "complete")
    line_risk_review = (full_visual_review or {}).get("line_risk_review") or diy_path_margin_line_risk_review(flat, args)
    effective_line_risk = planner_to_bool(line_risk_review.get("effective_line_risk"))
    raw_line_risk = planner_to_bool(flat.get("line_risk"))
    age_sec = _diy_path_observation_age_sec(observation)
    min_conf = planner_to_float(
        getattr(args, "diy_path_lateral_only_min_confidence", 0.65), 0.65)
    min_quality = planner_to_float(
        getattr(args, "diy_path_lateral_only_min_solver_quality", 0.65), 0.65)
    max_age = planner_to_float(
        getattr(args, "diy_path_lateral_only_max_visual_age_sec", 0.5), 0.5)
    allow_partial = bool(getattr(args, "diy_path_lateral_only_allow_partial_usable", True))
    solver_quality_ok = bool(solver_quality >= min_quality)
    partial_ok = bool(allow_partial and solver_status in ("partial_usable", "complete", "usable", "ok"))
    visual_lat = None if visual_pose is None else planner_to_float(visual_pose.get("lateral_cm"), None)
    odom_lat = planner_to_float(current_pose.get("lateral_cm"), None)
    checks = {
        # Use the effective line risk here.  Margin-derived pseudo line_risk is
        # already suppressed by diy_path_margin_line_risk_review for H1; do not
        # let the raw bit silently disable lateral-only correction.
        "line_risk_clear": not effective_line_risk,
        "mask_polygon": diy_fast_odom_has_mask(flat),
        "confidence": confidence >= min_conf,
        "visual_age": age_sec <= max_age,
        "visual_pose": visual_pose is not None,
        "visual_lateral": _diy_finite(visual_lat),
        "odom_lateral": _diy_finite(odom_lat),
        "ground_slot_solver_available": solver_status != "rejected",
        "solver_quality_or_partial": solver_quality_ok or partial_ok,
    }
    failed = [name for name, ok in checks.items() if not ok]
    review = dict(base)
    review.update({
        "reason": "checks_failed" if failed else "lateral_only_correction",
        "checks": checks,
        "failed_checks": failed,
        "odom_lateral_before": None if odom_lat is None else round(float(odom_lat), 3),
        "visual_lateral": None if visual_lat is None else round(float(visual_lat), 3),
        "visual_confidence": round(float(confidence), 4),
        "min_confidence": round(float(min_conf), 4),
        "solver_quality": round(float(solver_quality), 4),
        "min_solver_quality": round(float(min_quality), 4),
        "solver_status": solver_status,
        "allow_partial_usable": bool(allow_partial),
        "visual_age_sec": round(float(age_sec), 3),
        "max_visual_age_sec": round(float(max_age), 3),
        "raw_line_risk": bool(raw_line_risk),
        "effective_line_risk": bool(effective_line_risk),
        "line_risk_review": line_risk_review,
        "full_visual_correction_tier": (full_visual_review or {}).get("tier"),
        "full_visual_correction_reason": (full_visual_review or {}).get("reason"),
    })
    if failed:
        return review, odom_pose

    raw_delta = float(visual_lat) - float(odom_lat)
    max_cm = max(0.0, planner_to_float(
        getattr(args, "diy_path_lateral_only_correction_max_cm", 1.5), 1.5))
    alpha = max(0.0, min(1.0, planner_to_float(
        getattr(args, "diy_path_lateral_only_correction_alpha", 0.15), 0.15)))
    clamped_delta = max(-max_cm, min(max_cm, raw_delta))
    corrected = dict(current_pose)
    corrected["lateral_cm"] = float(odom_lat) + alpha * clamped_delta
    review.update({
        "applied": True,
        "reason": "lateral_only_correction",
        "raw_delta_lateral_cm": round(float(raw_delta), 3),
        "clamped_delta_lateral_cm": round(float(clamped_delta), 3),
        "max_correction_cm": round(float(max_cm), 3),
        "alpha": round(float(alpha), 3),
        "estimated_lateral_after": round(float(corrected["lateral_cm"]), 3),
        "pose_before": _diy_round_pose(current_pose),
        "pose_after": _diy_round_pose(corrected),
        "y_dist_changed": False,
        "heading_changed": False,
        "ignore_heading_delta": bool(getattr(args, "diy_path_lateral_only_ignore_heading_delta", True)),
        "ignore_y_delta": bool(getattr(args, "diy_path_lateral_only_ignore_y_delta", True)),
    })
    return review, corrected


def diy_path_action_from_ste(ste, command_abs_cm):
    return diy_fast_odom_action_from_ste(ste, command_abs_cm)


def diy_path_action_from_ste_signed(ste, signed_command_cm, reason="diy_path_signed_template"):
    signed_command_cm = planner_to_float(signed_command_cm, 0.0)
    cmd = _motion_command_with_signed_distance("ARC", signed_command_cm, ste, GEAR)
    fields = _parse_motion_command_fields(cmd)
    step = planner_to_float(fields.get("abs_d_cm"), abs(float(signed_command_cm)))
    servo = int(round(planner_to_float(fields.get("servo"), ste)))
    direction = "forward" if float(signed_command_cm) > 0.0 else "reverse"
    return {
        "state": "DIY_PATH_TERMINAL_SHUFFLE_STEP" if direction == "forward" else "DIY_FAST_ODOM_REVERSE_STEP",
        "action": "ARC",
        "cmd": cmd,
        "step": round(float(step), 3),
        "signed_distance_cm": round(float(signed_command_cm), 3),
        "direction": direction,
        "servo": servo,
        "steer_dir": 0.0 if servo == SERVO_CENTER else (1.0 if servo > SERVO_CENTER else -1.0),
        "reason": reason,
        "binding": {
            "distance_cm": round(float(step), 3),
            "signed_distance_cm": round(float(signed_command_cm), 3),
            "motion_direction": direction,
            "distance_reason": reason,
            "servo": servo,
            "gear": GEAR,
            "gear_reason": "diy_path_short_shuffle_step" if direction == "forward" else "diy_fast_odom_short_step",
        },
    }


def diy_path_action_signed_distance_cm(action):
    action = action or {}
    value = planner_to_float(action.get("signed_distance_cm"), None)
    if _diy_finite(value):
        return float(value)
    binding = action.get("binding") or {}
    value = planner_to_float(binding.get("signed_distance_cm"), None)
    if _diy_finite(value):
        return float(value)
    fields = _parse_motion_command_fields(action.get("cmd", ""))
    value = planner_to_float(fields.get("d_cm"), None)
    if _diy_finite(value) and abs(float(value)) > 1e-6:
        return float(value)
    # Existing path actions are reverse templates and historically carry only
    # an absolute step length.
    step = planner_to_float(action.get("step", binding.get("distance_cm")), 0.0)
    return -abs(float(step))


def diy_path_signed_progress_for_action(action, odom_progress_cm):
    progress = max(0.0, planner_to_float(odom_progress_cm, 0.0))
    signed_command = diy_path_action_signed_distance_cm(action)
    # Slot-frame convention: reverse progress decreases y_dist, so it is
    # positive in the existing integrator.  A forward command moves away from
    # the slot, so its signed progress is negative.
    return -progress if float(signed_command) > 0.0 else progress


def diy_path_sign_value(value, default=1.0):
    v = planner_to_float(value, default)
    return -1.0 if v < 0.0 else 1.0


def diy_path_yaw_sign(args):
    return diy_path_sign_value(getattr(args, "diy_path_yaw_sign", 1.0), 1.0)


def diy_path_lateral_sign(args):
    return diy_path_sign_value(getattr(args, "diy_path_lateral_sign", 1.0), 1.0)


def diy_path_signed_yaw_delta(raw_yaw_delta_deg, args):
    return angle_delta_deg(
        planner_to_float(raw_yaw_delta_deg, 0.0) * diy_path_yaw_sign(args)
    )


def diy_path_lateral_motion_gain_enabled(args):
    explicit = getattr(args, "diy_path_lateral_motion_gain_enable", None)
    if explicit is not None:
        return bool(explicit)
    return diy_path_profile_is_h1_fast10(args)


def diy_path_lateral_motion_gain_review(pose, raw_next_pose, args):
    """Conservatively scale odom-derived lateral motion for the H1 path.

    Recent real runs show the midpoint-yaw odom integrator is directionally
    useful but too optimistic for lateral convergence: the controller may think
    lateral dropped from ~6cm to ~3.5cm during a visionless tail while the car
    is still visibly off by ~7-10cm.  Keep heading/y/depth integration intact,
    but scale only the incremental lateral delta before planning/feedback uses
    it.  Visual correction can still pull the estimate when a fresh mask pose is
    available.
    """
    raw_delta = (
        planner_to_float((raw_next_pose or {}).get("lateral_cm"), 0.0) -
        planner_to_float((pose or {}).get("lateral_cm"), 0.0)
    )
    enabled = diy_path_lateral_motion_gain_enabled(args)
    gain = clamp(
        planner_to_float(getattr(args, "diy_path_lateral_motion_gain", 0.70), 0.70),
        0.0,
        1.5,
    )
    max_delta = planner_to_float(
        getattr(args, "diy_path_lateral_motion_max_delta_cm", 2.0), 2.0)
    scaled_delta = raw_delta
    clamped = False
    if enabled:
        scaled_delta = raw_delta * gain
        if _diy_finite(max_delta) and float(max_delta) > 0.0:
            before = scaled_delta
            scaled_delta = clamp(scaled_delta, -abs(float(max_delta)), abs(float(max_delta)))
            clamped = abs(float(before) - float(scaled_delta)) > 1e-6
    adjusted_pose = dict(raw_next_pose or {})
    adjusted_pose["lateral_cm"] = planner_to_float(
        (pose or {}).get("lateral_cm"), 0.0) + scaled_delta
    review = {
        "schema": "diy_path_lateral_motion_gain_review.v1",
        "enabled": bool(enabled),
        "reason": "h1_conservative_lateral_motion_model" if enabled else "disabled",
        "raw_lateral_delta_cm": round(float(raw_delta), 3),
        "gain": round(float(gain), 3),
        "max_delta_cm": None if not _diy_finite(max_delta) else round(float(max_delta), 3),
        "adjusted_lateral_delta_cm": round(float(scaled_delta), 3),
        "delta_clamped": bool(clamped),
    }
    return adjusted_pose, review


def diy_path_lateral_estimator_v2_enabled(args):
    explicit = getattr(args, "diy_path_lateral_estimator_v2_enable", None)
    if explicit is not None:
        return bool(explicit)
    return bool(diy_path_profile_is_h1_fast10(args))


def diy_path_lateral_estimator_conservative_planning_enabled(args):
    explicit = getattr(args, "diy_path_lateral_estimator_conservative_planning_enable", None)
    if explicit is not None:
        return bool(explicit)
    return bool(diy_path_profile_is_h1_lattice_mpc(args))


def _diy_path_lateral_estimator_max_uncertainty(args):
    return max(0.0, planner_to_float(
        getattr(args, "diy_path_lateral_estimator_max_uncertainty_cm", 8.0), 8.0))


def _diy_path_lateral_estimator_clamp_uncertainty(value, args):
    max_unc = _diy_path_lateral_estimator_max_uncertainty(args)
    return clamp(max(0.0, planner_to_float(value, 0.0)), 0.0, max_unc)


def diy_path_lateral_estimator_init(state, args, pose, source="initial_lock", visual_pose=None):
    enabled = diy_path_lateral_estimator_v2_enabled(args)
    base = {
        "schema": "diy_path_lateral_estimator_v2_review.v1",
        "enabled": bool(enabled),
        "stage": "init",
        "reason": "disabled" if not enabled else source,
    }
    if not enabled:
        return base
    pose = pose or {}
    lateral = planner_to_float(pose.get("lateral_cm"), 0.0)
    visual_lat = planner_to_float((visual_pose or pose).get("lateral_cm"), lateral)
    uncertainty = _diy_path_lateral_estimator_clamp_uncertainty(
        getattr(args, "diy_path_lateral_estimator_initial_uncertainty_cm", 1.0),
        args,
    )
    estimator = {
        "schema": "diy_path_lateral_estimator_v2_state.v1",
        "enabled": True,
        "fused_lateral_cm": float(lateral),
        "odom_lateral_cm": float(lateral),
        "visual_lateral_cm": float(visual_lat),
        "last_visual_lateral_cm": float(visual_lat),
        "last_visual_step": int(state.get("steps", 0)),
        "last_visual_source": source,
        "last_residual_cm": 0.0,
        "lateral_uncertainty_cm": float(uncertainty),
        "visionless_steps": int(state.get("visionless_steps", 0)),
        "last_update": source,
    }
    state["lateral_estimator"] = estimator
    base.update({
        "state": deepcopy_jsonable(estimator),
        "pose": _diy_round_pose(pose),
        "visual_pose": _diy_round_pose(visual_pose or pose),
    })
    return base


def diy_path_lateral_estimator_odom_update(state, args, pose_before, pose_after_odom,
                                           progress_cm, yaw_delta_deg, lateral_motion_review=None):
    enabled = diy_path_lateral_estimator_v2_enabled(args)
    base = {
        "schema": "diy_path_lateral_estimator_v2_review.v1",
        "enabled": bool(enabled),
        "stage": "odom_update",
        "reason": "disabled" if not enabled else "odom_propagated",
    }
    if not enabled:
        return base
    pose_before = pose_before or {}
    pose_after_odom = pose_after_odom or {}
    estimator = dict(state.get("lateral_estimator") or {})
    prev_unc = planner_to_float(estimator.get("lateral_uncertainty_cm"), None)
    if not _diy_finite(prev_unc):
        prev_unc = planner_to_float(
            getattr(args, "diy_path_lateral_estimator_initial_uncertainty_cm", 1.0), 1.0)
    step_unc = max(0.0, planner_to_float(
        getattr(args, "diy_path_lateral_estimator_odom_step_uncertainty_cm", 0.15), 0.15))
    progress_unc = max(0.0, planner_to_float(
        getattr(args, "diy_path_lateral_estimator_progress_uncertainty_per_cm", 0.03), 0.03))
    yaw_unc = max(0.0, planner_to_float(
        getattr(args, "diy_path_lateral_estimator_yaw_uncertainty_per_deg", 0.02), 0.02))
    added_unc = (
        float(step_unc) +
        abs(planner_to_float(progress_cm, 0.0)) * float(progress_unc) +
        abs(planner_to_float(yaw_delta_deg, 0.0)) * float(yaw_unc)
    )
    odom_lat = planner_to_float(pose_after_odom.get("lateral_cm"), None)
    before_lat = planner_to_float(pose_before.get("lateral_cm"), None)
    uncertainty = _diy_path_lateral_estimator_clamp_uncertainty(float(prev_unc) + added_unc, args)
    estimator.update({
        "schema": "diy_path_lateral_estimator_v2_state.v1",
        "enabled": True,
        "odom_lateral_cm": None if not _diy_finite(odom_lat) else float(odom_lat),
        "fused_lateral_cm": None if not _diy_finite(odom_lat) else float(odom_lat),
        "visual_lateral_cm": None,
        "lateral_uncertainty_cm": float(uncertainty),
        "visionless_steps": int(state.get("visionless_steps", 0)),
        "last_update": "odom_update",
    })
    state["lateral_estimator"] = estimator
    base.update({
        "pose_before": _diy_round_pose(pose_before),
        "pose_after_odom": _diy_round_pose(pose_after_odom),
        "lateral_before_cm": None if not _diy_finite(before_lat) else round(float(before_lat), 3),
        "odom_lateral_cm": None if not _diy_finite(odom_lat) else round(float(odom_lat), 3),
        "odom_lateral_delta_cm": (
            None if not (_diy_finite(before_lat) and _diy_finite(odom_lat))
            else round(float(odom_lat) - float(before_lat), 3)
        ),
        "added_uncertainty_cm": round(float(added_unc), 3),
        "lateral_uncertainty_cm": round(float(uncertainty), 3),
        "lateral_motion_review": lateral_motion_review,
    })
    return base


def diy_path_lateral_estimator_post_visual_update(state, args, estimated_pose_after_odom,
                                                  visual_observation, visual_review,
                                                  lateral_only_review, correction_used):
    enabled = diy_path_lateral_estimator_v2_enabled(args)
    base = {
        "schema": "diy_path_lateral_estimator_v2_review.v1",
        "enabled": bool(enabled),
        "stage": "post_visual_update",
        "reason": "disabled" if not enabled else "not_evaluated",
    }
    if not enabled:
        return base
    estimator = dict(state.get("lateral_estimator") or {})
    pose = state.get("pose") or {}
    odom_pose = estimated_pose_after_odom or {}
    odom_lat = planner_to_float(odom_pose.get("lateral_cm"), None)
    fused_lat = planner_to_float(pose.get("lateral_cm"), odom_lat)
    visual_pose = (visual_review or {}).get("visual_pose")
    if visual_pose is None and visual_observation is not None:
        visual_pose = (visual_observation or {}).get("pose")
    visual_lat = None if visual_pose is None else planner_to_float(visual_pose.get("lateral_cm"), None)
    prev_unc = planner_to_float(estimator.get("lateral_uncertainty_cm"), 0.0)
    reason = "no_fresh_yolo"
    residual = None
    correction_like = bool(correction_used and _diy_finite(visual_lat) and _diy_finite(odom_lat))
    if correction_like:
        residual = float(visual_lat) - float(odom_lat)
        floor_unc = max(0.0, planner_to_float(
            getattr(args, "diy_path_lateral_estimator_visual_floor_cm", 0.8), 0.8))
        residual_scale = max(0.0, planner_to_float(
            getattr(args, "diy_path_lateral_estimator_visual_residual_scale", 0.35), 0.35))
        uncertainty = _diy_path_lateral_estimator_clamp_uncertainty(
            max(float(floor_unc), abs(float(residual)) * float(residual_scale)),
            args,
        )
        estimator.update({
            "visual_lateral_cm": float(visual_lat),
            "last_visual_lateral_cm": float(visual_lat),
            "last_visual_step": int(state.get("steps", 0)),
            "last_visual_source": (visual_review or {}).get("reason", "visual_correction"),
            "last_residual_cm": float(residual),
            "lateral_uncertainty_cm": float(uncertainty),
            "visionless_steps": int(state.get("visionless_steps", 0)),
            "last_update": "visual_correction",
        })
        reason = "visual_correction_used"
    else:
        no_visual_unc = max(0.0, planner_to_float(
            getattr(args, "diy_path_lateral_estimator_visionless_step_uncertainty_cm", 0.55), 0.55))
        rejected_visual_unc = max(0.0, planner_to_float(
            getattr(args, "diy_path_lateral_estimator_rejected_visual_uncertainty_cm", 0.25), 0.25))
        added = no_visual_unc if visual_observation is None else rejected_visual_unc
        uncertainty = _diy_path_lateral_estimator_clamp_uncertainty(float(prev_unc) + float(added), args)
        reason = "no_fresh_yolo" if visual_observation is None else "visual_not_used_for_lateral"
        if _diy_finite(visual_lat) and _diy_finite(odom_lat):
            residual = float(visual_lat) - float(odom_lat)
        estimator.update({
            "visual_lateral_cm": None if not _diy_finite(visual_lat) else float(visual_lat),
            "lateral_uncertainty_cm": float(uncertainty),
            "visionless_steps": int(state.get("visionless_steps", 0)),
            "last_update": reason,
        })
    estimator["odom_lateral_cm"] = None if not _diy_finite(odom_lat) else float(odom_lat)
    estimator["fused_lateral_cm"] = None if not _diy_finite(fused_lat) else float(fused_lat)
    state["lateral_estimator"] = estimator
    base.update({
        "reason": reason,
        "odom_lateral_cm": None if not _diy_finite(odom_lat) else round(float(odom_lat), 3),
        "visual_lateral_cm": None if not _diy_finite(visual_lat) else round(float(visual_lat), 3),
        "fused_lateral_cm": None if not _diy_finite(fused_lat) else round(float(fused_lat), 3),
        "visual_minus_odom_lateral_cm": None if residual is None else round(float(residual), 3),
        "correction_used": bool(correction_used),
        "lateral_only_review": lateral_only_review,
        "visual_review_compact": {
            "tier": (visual_review or {}).get("tier"),
            "reason": (visual_review or {}).get("reason"),
            "confidence": (visual_review or {}).get("confidence"),
        },
        "lateral_uncertainty_cm": round(float(estimator.get("lateral_uncertainty_cm", 0.0)), 3),
        "visionless_steps": int(state.get("visionless_steps", 0)),
        "state": deepcopy_jsonable(estimator),
    })
    return base


def diy_path_lateral_estimator_apply_conservative_pose(state, args, target_lateral_cm=None):
    enabled = (
        diy_path_lateral_estimator_v2_enabled(args) and
        diy_path_lateral_estimator_conservative_planning_enabled(args)
    )
    review = {
        "schema": "diy_path_lateral_estimator_conservative_pose.v1",
        "enabled": bool(enabled),
        "applied": False,
        "reason": "disabled" if not enabled else "not_needed",
    }
    if not enabled:
        return review
    estimator = state.get("lateral_estimator") or {}
    pose = state.get("pose") or {}
    pose_lat = planner_to_float(pose.get("lateral_cm"), None)
    last_visual_lat = planner_to_float(estimator.get("last_visual_lateral_cm"), None)
    uncertainty = planner_to_float(estimator.get("lateral_uncertainty_cm"), 0.0)
    target_lateral = planner_to_float(
        target_lateral_cm, diy_path_success_target_lateral_cm(args))
    if not (_diy_finite(pose_lat) and _diy_finite(last_visual_lat) and _diy_finite(uncertainty)):
        review["reason"] = "missing_lateral_estimator_state"
        return review
    visionless_steps = int(state.get("visionless_steps", 0))
    if visionless_steps <= 0:
        review["reason"] = "fresh_visual_available"
        return review
    pose_err = float(pose_lat) - float(target_lateral)
    last_visual_err = float(last_visual_lat) - float(target_lateral)
    if pose_err == 0.0:
        sign = -1.0 if last_visual_err < 0.0 else 1.0
    else:
        sign = -1.0 if pose_err < 0.0 else 1.0
    if last_visual_err != 0.0 and pose_err != 0.0 and (last_visual_err * pose_err) < 0.0:
        review["reason"] = "lateral_crossed_target"
        return review
    if abs(float(pose_err)) >= abs(float(last_visual_err)):
        review["reason"] = "odom_not_more_optimistic_than_last_visual"
        return review
    scale = max(0.0, planner_to_float(
        getattr(args, "diy_path_lateral_estimator_conservative_scale", 0.75), 0.75))
    max_add = max(0.0, planner_to_float(
        getattr(args, "diy_path_lateral_estimator_conservative_max_cm", 5.0), 5.0))
    inflated_abs_err = min(
        abs(float(last_visual_err)),
        abs(float(pose_err)) + min(float(max_add), abs(float(uncertainty)) * float(scale)),
    )
    conservative_lat = float(target_lateral) + float(sign) * float(inflated_abs_err)
    if abs(conservative_lat - float(pose_lat)) <= 1e-6:
        review["reason"] = "no_effect"
        return review
    updated_pose = dict(pose)
    updated_pose["lateral_cm"] = float(conservative_lat)
    state["pose"] = updated_pose
    estimator = dict(estimator)
    estimator["fused_lateral_cm"] = float(conservative_lat)
    estimator["conservative_lateral_applied"] = True
    estimator["conservative_lateral_cm"] = float(conservative_lat)
    state["lateral_estimator"] = estimator
    review.update({
        "applied": True,
        "reason": "visionless_conservative_lateral",
        "pose_lateral_before_cm": round(float(pose_lat), 3),
        "pose_lateral_after_cm": round(float(conservative_lat), 3),
        "target_lateral_cm": round(float(target_lateral), 3),
        "last_visual_lateral_cm": round(float(last_visual_lat), 3),
        "lateral_uncertainty_cm": round(float(uncertainty), 3),
        "visionless_steps": int(visionless_steps),
        "scale": round(float(scale), 3),
        "max_add_cm": round(float(max_add), 3),
    })
    return review


def diy_path_lateral_estimator_success_review(state, args, target_lateral_cm=None,
                                              lateral_tol_cm=None):
    enabled = diy_path_lateral_estimator_v2_enabled(args)
    use_uncertainty = getattr(args, "diy_path_lateral_estimator_success_use_uncertainty", None)
    if use_uncertainty is None:
        use_uncertainty = bool(diy_path_profile_is_h1_lattice_mpc(args))
    target_lateral = planner_to_float(
        target_lateral_cm, diy_path_success_target_lateral_cm(args))
    lateral_tol = planner_to_float(
        lateral_tol_cm, diy_path_success_lateral_tol_cm(args))
    pose = (state or {}).get("pose") or {}
    lateral = planner_to_float(pose.get("lateral_cm"), None)
    estimator = (state or {}).get("lateral_estimator") or {}
    uncertainty = planner_to_float(estimator.get("lateral_uncertainty_cm"), 0.0)
    scale = max(0.0, planner_to_float(
        getattr(args, "diy_path_lateral_estimator_success_uncertainty_scale", 0.75), 0.75))
    raw_error = None if not _diy_finite(lateral) else abs(float(lateral) - float(target_lateral))
    effective_error = None
    if _diy_finite(raw_error):
        effective_error = float(raw_error) + (float(scale) * float(uncertainty) if enabled and use_uncertainty else 0.0)
    ok = bool(_diy_finite(effective_error) and float(effective_error) <= float(lateral_tol))
    return {
        "schema": "diy_path_lateral_estimator_success_review.v1",
        "enabled": bool(enabled),
        "use_uncertainty": bool(use_uncertainty),
        "ok": bool(ok),
        "reason": "ok" if ok else "lateral_uncertainty_or_error_too_large",
        "lateral_cm": None if not _diy_finite(lateral) else round(float(lateral), 3),
        "target_lateral_cm": round(float(target_lateral), 3),
        "raw_lateral_error_cm": None if raw_error is None else round(float(raw_error), 3),
        "lateral_uncertainty_cm": round(float(uncertainty), 3),
        "uncertainty_scale": round(float(scale), 3),
        "effective_lateral_error_cm": None if effective_error is None else round(float(effective_error), 3),
        "lateral_tol_cm": round(float(lateral_tol), 3),
        "visionless_steps": int((state or {}).get("visionless_steps", 0)),
        "estimator": deepcopy_jsonable(estimator),
    }


def diy_path_integrate_signed_pose(pose, signed_progress_cm, yaw_delta_deg):
    pose = pose or {}
    progress = planner_to_float(signed_progress_cm, 0.0)
    yaw_delta = angle_delta_deg(planner_to_float(yaw_delta_deg, 0.0))
    heading0 = angle_delta_deg(planner_to_float(pose.get("heading_deg"), 0.0))
    heading_mid = angle_delta_deg(heading0 + 0.5 * yaw_delta)
    theta = math.radians(heading_mid)
    return {
        "y_dist_cm": pose["y_dist_cm"] - progress * math.cos(theta),
        "lateral_cm": pose["lateral_cm"] + progress * math.sin(theta),
        "heading_deg": angle_delta_deg(heading0 + yaw_delta),
    }


def diy_path_integrate_pose_with_review(pose, progress_cm, raw_yaw_delta_deg, args):
    return diy_path_integrate_pose_signed_with_review(
        pose, progress_cm, raw_yaw_delta_deg, args, signed_progress_cm=progress_cm)


def diy_path_integrate_pose_signed_with_review(pose, progress_cm, raw_yaw_delta_deg,
                                               args, signed_progress_cm=None):
    signed_yaw_delta = diy_path_signed_yaw_delta(raw_yaw_delta_deg, args)
    signed_progress = planner_to_float(signed_progress_cm, progress_cm)
    next_pose = diy_path_integrate_signed_pose(pose, signed_progress, signed_yaw_delta)
    lat_sign = diy_path_lateral_sign(args)
    if lat_sign < 0.0:
        next_pose["lateral_cm"] = (
            pose["lateral_cm"] -
            (next_pose["lateral_cm"] - pose["lateral_cm"])
        )
    next_pose, lateral_motion_review = diy_path_lateral_motion_gain_review(
        pose, next_pose, args)
    lateral_motion_review["signed_progress_cm"] = round(float(signed_progress), 3)
    next_pose["heading_deg"] = angle_delta_deg(next_pose["heading_deg"])
    return next_pose, lateral_motion_review


def diy_path_integrate_pose(pose, progress_cm, raw_yaw_delta_deg, args):
    next_pose, _review = diy_path_integrate_pose_with_review(
        pose, progress_cm, raw_yaw_delta_deg, args)
    return next_pose


def diy_path_profile_name(args):
    return str(getattr(args, "diy_path_profile", "") or "").strip().lower()


def diy_path_profile_is_h1_heading_debt(args):
    return diy_path_profile_name(args) in (
        "h1_fast10_heading_debt",
        "h1_fast_10_heading_debt",
    )


def diy_path_profile_is_h1_lattice_mpc(args):
    return diy_path_profile_name(args) in (
        "h1_lattice_mpc",
        "h1_fast10_lattice_mpc",
        "h1_measured_lattice_mpc",
    )


def diy_path_profile_is_h1_structured_phase(args):
    return diy_path_profile_name(args) in (
        "h1_structured_phase_parking",
        "h1_structured_phase",
    )


def diy_path_profile_is_h1_fullset(args):
    return diy_path_profile_name(args) in (
        "h1_fast10_fullset_clearance",
        "h1_fast_10_fullset_clearance",
    ) or diy_path_profile_is_h1_heading_debt(args) or diy_path_profile_is_h1_lattice_mpc(args) or diy_path_profile_is_h1_structured_phase(args)


def diy_path_profile_is_h1_fast10(args):
    return diy_path_profile_name(args) in (
        "h1_fast_10_clearance",
        "h1_fast10_clearance",
        "h1_fast10_fullset_clearance",
        "h1_fast_10_fullset_clearance",
    ) or diy_path_profile_is_h1_heading_debt(args) or diy_path_profile_is_h1_lattice_mpc(args) or diy_path_profile_is_h1_structured_phase(args)


def diy_path_fullset_enabled(args):
    return bool(
        getattr(args, "diy_path_fullset_action_enable", False) or
        diy_path_profile_is_h1_fullset(args)
    )


def diy_path_fast10_enabled(args):
    return bool(getattr(args, "diy_path_fast10_enable", False) or diy_path_profile_is_h1_fast10(args))


def diy_path_smooth_enabled(args):
    return bool(getattr(args, "diy_path_smooth_enable", False) or diy_path_profile_is_h1_fast10(args))


def diy_path_clearance_enabled(args):
    return bool(getattr(args, "diy_path_clearance_enable", False) or diy_path_profile_is_h1_fast10(args))


