def diy_path_lock_near_side_from_pose(pose, args):
    pose = pose or {}
    lateral = planner_to_float(pose.get("lateral_cm"), 0.0)
    deadband = max(0.0, planner_to_float(
        getattr(args, "diy_path_near_side_auto_deadband_cm", 1.5), 1.5))
    if lateral < -deadband:
        near_side = "left"
    elif lateral > deadband:
        near_side = "right"
    else:
        near_side = "center"
    target_lateral = diy_path_near_side_target_lateral_cm(near_side, args)
    return {
        "schema": "diy_path_near_side_lock.v1",
        "enabled": bool(diy_path_near_side_clearance_enabled(args)),
        "near_side": near_side,
        "near_side_locked_from_lateral_cm": round(float(lateral), 3),
        "auto_deadband_cm": round(float(deadband), 3),
        "scoring_target_lateral_cm": round(float(target_lateral), 3),
        "success_target_lateral_cm": round(float(diy_path_success_target_lateral_cm(args)), 3),
        "reason": "locked_from_initial_lateral",
        "lateral_sign_convention": "lateral<0 means closer_to_left_line",
    }


def diy_path_near_side_target_lateral_cm(near_side, args):
    base_target = planner_to_float(getattr(args, "diy_path_target_lateral_cm", 0.0), 0.0)
    if not diy_path_near_side_clearance_enabled(args):
        return float(base_target)
    side = str(near_side or "center").strip().lower()
    bias = max(0.0, planner_to_float(
        getattr(args, "diy_path_near_side_bias_cm", 2.5), 2.5))
    if side == "left":
        return float(bias)
    if side == "right":
        return -float(bias)
    return float(base_target)


