def diy_path_effective_target_y_cm(args):
    explicit = planner_to_float(getattr(args, "diy_path_effective_target_y_cm", None), None)
    if _diy_finite(explicit):
        return float(explicit)
    return planner_to_float(getattr(args, "diy_path_target_y_dist_cm", 10.0), 10.0)


def diy_path_success_target_lateral_cm(args):
    explicit = planner_to_float(getattr(args, "diy_path_success_lateral_target_cm", None), None)
    if _diy_finite(explicit):
        return float(explicit)
