def _slot_pose_diag_svg_points(points):
    return " ".join(
        "%.1f,%.1f" % (float(p[0]), float(p[1]))
        for p in (points or [])
        if isinstance(p, (list, tuple)) and len(p) >= 2
    )


def _slot_pose_diag_svg_line(edge, color, width=3, extra=""):
    if not edge or len(edge) < 2:
        return ""
    return '<line x1="%.1f" y1="%.1f" x2="%.1f" y2="%.1f" stroke="%s" stroke-width="%s" %s />' % (
        float(edge[0][0]), float(edge[0][1]), float(edge[1][0]), float(edge[1][1]), color, width, extra
    )


def write_slot_pose_diag_svg(event, path):
    raw = event.get("raw_mask_polygon_px") or event.get("mask_polygon_px") or []
    active_poly = event.get("mask_polygon_px") or []
    cleaned = event.get("cleaned_polygon_px") or []
    quad = event.get("fitted_quad_corners_px") or []
    entry = event.get("selected_entry_edge_px") or []
    far = event.get("selected_far_edge_px") or []
    center = event.get("image_plane_slot_center_px") or [IMAGE_W * 0.5, IMAGE_H * 0.5]
    axis = event.get("image_plane_approach_axis_px") or []
    target_x = planner_to_float((event.get("sign_and_offset") or {}).get("pixel_target_x"), PIXEL_X_TARGET)
    svg = [
        '<svg xmlns="http://www.w3.org/2000/svg" width="640" height="640" viewBox="0 0 640 640">',
        '<rect x="0" y="0" width="640" height="640" fill="#111"/>',
        '<defs><marker id="arrow" markerWidth="8" markerHeight="8" refX="7" refY="3" orient="auto" markerUnits="strokeWidth"><path d="M0,0 L0,6 L7,3 z" fill="#4da3ff"/></marker></defs>',
        '<line x1="%.1f" y1="632" x2="%.1f" y2="500" stroke="#ffffff" stroke-width="2" stroke-dasharray="8 6"/>' % (target_x, target_x),
        '<text x="8" y="22" fill="#ddd" font-size="14">slot_pose_coord_diagnostic %s #%s</text>' % (
            str(event.get("label", "sample")),
            str(event.get("sample_index", "")),
        ),
    ]
    if len(raw) >= 3:
        svg.append('<polygon points="%s" fill="none" stroke="#666" stroke-width="2" stroke-dasharray="5 4"/>' % _slot_pose_diag_svg_points(raw))
    if len(active_poly) >= 3:
        svg.append('<polygon points="%s" fill="none" stroke="#4da3ff" stroke-width="2"/>' % _slot_pose_diag_svg_points(active_poly))
    if len(cleaned) >= 3:
        svg.append('<polygon points="%s" fill="none" stroke="#00e5ff" stroke-width="2" stroke-dasharray="6 4"/>' % _slot_pose_diag_svg_points(cleaned))
    if len(quad) >= 3:
        svg.append('<polygon points="%s" fill="none" stroke="#ffd54a" stroke-width="3"/>' % _slot_pose_diag_svg_points(quad))
    svg.append(_slot_pose_diag_svg_line(entry, "#00ff7f", 5))
    svg.append(_slot_pose_diag_svg_line(far, "#ff66cc", 5))
    if len(axis) >= 2:
        svg.append(_slot_pose_diag_svg_line(axis, "#4da3ff", 4, 'marker-end="url(#arrow)"'))
    try:
        svg.append('<circle cx="%.1f" cy="%.1f" r="5" fill="#ff4444"/>' % (float(center[0]), float(center[1])))
    except (TypeError, ValueError, IndexError):
        pass
    svg.append('<text x="8" y="608" fill="#ddd" font-size="13">legacy_head=%s ground_head=%s y=%s lat=%s</text>' % (
        str(event.get("legacy_reported_heading_deg")),
        str(event.get("ground_heading_err_deg")),
        str(event.get("ground_y_dist_cm")),
        str(event.get("ground_lateral_cm")),
    ))
    svg.append('</svg>')
    with open(path, "w", encoding="utf-8") as f:
        f.write("\n".join(item for item in svg if item))


