def _diag_numeric_values(values):
    vals = []
    for value in values:
        try:
            v = float(value)
        except (TypeError, ValueError):
            continue
        if math.isfinite(v):
            vals.append(v)
    return vals


def _diag_mean(values):
    vals = _diag_numeric_values(values)
    return None if not vals else sum(vals) / len(vals)


def _diag_std(values):
    vals = _diag_numeric_values(values)
    if len(vals) < 2:
        return 0.0 if vals else None
    m = sum(vals) / len(vals)
    return math.sqrt(sum((v - m) * (v - m) for v in vals) / (len(vals) - 1))


def write_slot_pose_diag_report(report_path, label, samples, raw_path, csv_path, image_dir):
    def metric(name):
        vals = [sample.get(name) for sample in samples]
        return _diag_round(_diag_mean(vals)), _diag_round(_diag_std(vals))

    lines = [
        "# Slot Pose Coordinate Diagnostic Report",
        "",
        "- label: `%s`" % label,
        "- samples: `%d`" % len(samples),
        "- raw: `%s`" % raw_path,
        "- summary: `%s`" % csv_path,
        "- images: `%s`" % image_dir,
        "",
        "## Key Metrics",
        "",
        "| field | mean | std |",
        "|---|---:|---:|",
    ]
    for name in (
        "reported_y_dist_cm",
        "reported_lateral_cm",
        "reported_heading_deg",
        "ground_y_dist_cm",
        "ground_lateral_cm",
        "ground_heading_err_deg",
    ):
        m, s = metric(name)
        lines.append("| `%s` | %s | %s |" % (name, "" if m is None else m, "" if s is None else s))
    delta_mean, delta_std = metric("image_vs_ground_heading_delta_deg")
    center_mean, center_std = metric("legacy_center_delta_cm")
    lines += [
        "",
        "## Diagnostic Conclusions",
        "",
        "- `reported_heading_deg` 是当前 DIY 主线使用的地面坐标 heading。",
        "- `ground_heading_err_deg` 是本轮候选 solver 在地面坐标中计算的 heading。",
        "- `homography_input_domain=undistorted_px` 表示流程为 raw YOLO mask 点 -> undistortPoints(P=K) -> homography；`raw_yolo_px` 表示未找到/未启用相机内参而走原始像素。",
        "- image-vs-ground heading delta mean/std: `%s / %s deg`" % (delta_mean, delta_std),
        "- legacy-vs-ground center delta mean/std: `%s / %s cm`" % (center_mean, center_std),
        "- 若 A 姿态下 `ground_heading_err_deg` 仍不接近 0，优先复核 homography/相机安装。",
        "- 若 `reported_heading_deg` 与 `ground_heading_err_deg` 系统性不一致，说明旧 heading 零点来自图像平面角度定义，不能继续作为泊车主状态。",
        "",
        "## Next Manual Labels",
        "",
        "- A: centered_parallel",
        "- B: left_parallel",
        "- C: right_parallel",
        "- D: clockwise_10deg",
        "- E: counterclockwise_10deg",
    ]
    with open(report_path, "w", encoding="utf-8") as f:
        f.write("\n".join(lines) + "\n")


def run_slot_pose_coord_diagnostic(args, sock, filt, deadline):
    label = str(getattr(args, "slot_pose_diag_label", "sample") or "sample")
    frames_target = max(1, int(getattr(args, "slot_pose_diag_frames", 10)))
    ts = time.strftime("%Y%m%d_%H%M%S")
    out_dir = str(getattr(args, "slot_pose_diag_output_dir", "") or "").strip()
    if not out_dir:
        out_dir = os.path.join("artifacts", "slot_pose_coord_diagnostic", "%s_%s" % (ts, label))
    image_dir = os.path.join(out_dir, "sample_images")
    os.makedirs(image_dir, exist_ok=True)
    raw_path = os.path.join(out_dir, "raw_slot_pose_samples.jsonl")
    csv_path = os.path.join(out_dir, "slot_pose_summary.csv")
    report_path = os.path.join(out_dir, "slot_pose_coord_diagnostic_report.md")
    run_config_path = os.path.join(out_dir, "run_config.json")
    with open(run_config_path, "w", encoding="utf-8") as f:
        json.dump({
            "strategy": "slot_pose_coord_diagnostic",
            "label": label,
            "frames": frames_target,
            "listen_host": args.listen_host,
            "listen_port": args.listen_port,
            "pixel_target_x": args.pixel_target_x,
            "pixel_target_angle_deg": args.pixel_target_angle_deg,
            "camera_undistort_mask_polygon": bool(getattr(args, "camera_undistort_mask_polygon", False)),
            "camera_calibration_json": getattr(args, "camera_calibration_json", ""),
            "camera_undistort_iterations": getattr(args, "camera_undistort_iterations", 5),
            "read_stat": bool(getattr(args, "slot_pose_diag_read_stat", True)),
            "save_svg": bool(getattr(args, "slot_pose_diag_save_svg", True)),
            "created_unix": time.time(),
        }, f, ensure_ascii=False, indent=2)

    stat_ready = False
    stat_error = ""
    if bool(getattr(args, "slot_pose_diag_read_stat", True)):
        try:
            serial_setup()
            stat_ready = True
        except Exception as exc:
            stat_error = str(exc)

    print("SLOT_POSE_DIAG output=%s label=%s frames=%d" % (out_dir, label, frames_target), flush=True)
    print("SLOT_POSE_DIAG waiting for YOLO mask_polygon frames; no motion commands will be sent.", flush=True)
    samples = []
    csv_fields = list(_slot_pose_diag_csv_row({"stm32_stat": {}}).keys())
    with open(raw_path, "a", encoding="utf-8") as raw_f, open(csv_path, "w", newline="", encoding="utf-8") as csv_f:
        writer = csv.DictWriter(csv_f, fieldnames=csv_fields)
        writer.writeheader()
        while len(samples) < frames_target:
            if deadline is not None and time.time() >= deadline:
                break
            raw = recv_latest(sock)
            if raw is None:
                time.sleep(0.05)
                continue
            infos = slot_infos_from_udp(raw, args.slot_class_names, completeness_args=args)
            if not infos:
                continue
            info = max(infos, key=lambda item: float(item.get("confidence", 0.0)))
            stable = False
            metrics = {}
            if filt is not None:
                try:
                    stable, metrics = filt.add(info, observing_static=True)
                except Exception as exc:
                    metrics = {"stable": False, "error": str(exc)}
            stat = {
                "raw": "",
                "yaw": None,
                "imu": None,
                "error": stat_error,
                "read_enabled": bool(getattr(args, "slot_pose_diag_read_stat", True)),
            }
            if stat_ready:
                try:
                    stat = read_stat()
                except Exception as exc:
                    stat = {
                        "raw": "",
                        "yaw": None,
                        "imu": None,
                        "error": str(exc),
                        "read_enabled": True,
                    }
            event = slot_pose_coord_diagnostic_event(
                info,
                args,
                stat,
                sample_index=len(samples) + 1,
                label=label,
                stability=metrics,
            )
            event["stable"] = bool(stable)
            event["stability"] = deepcopy_jsonable(metrics)
            if bool(getattr(args, "slot_pose_diag_save_svg", True)):
                svg_path = os.path.join(image_dir, "%s_%03d.svg" % (label, len(samples) + 1))
                try:
                    write_slot_pose_diag_svg(event, svg_path)
                    event["diagnostic_image"] = svg_path
                except Exception as exc:
                    event["diagnostic_image_error"] = str(exc)
            raw_f.write(json.dumps(event, ensure_ascii=False, separators=(",", ":")) + "\n")
            raw_f.flush()
            writer.writerow(_slot_pose_diag_csv_row(event))
            csv_f.flush()
            log_event(args.log_jsonl, event)
            samples.append(event)
            print(
                "SLOT_POSE_DIAG_FRAME %d/%d conf=%s legacy_head=%s ground_head=%s y=%s lat=%s imu=%s" % (
                    len(samples),
                    frames_target,
                    event.get("confidence"),
                    event.get("legacy_reported_heading_deg"),
                    event.get("ground_heading_err_deg"),
                    event.get("ground_y_dist_cm"),
                    event.get("ground_lateral_cm"),
                    (event.get("stm32_stat") or {}).get("imu"),
                ),
                flush=True,
            )

    write_slot_pose_diag_report(report_path, label, samples, raw_path, csv_path, image_dir)
    print("SLOT_POSE_DIAG_DONE samples=%d report=%s" % (len(samples), report_path), flush=True)
    return 0


def final_pose_report_from_token(token, stat_before_text, stat_after_text, args):
    token = token or {}
    pre_state = token.get("pre_state") or {}
    motion = token.get("motion") or {}
    heading_token = planner_to_float(pre_state.get("slot_heading_err_deg"))
    yaw_token = planner_to_float(token.get("yaw_token"), None)
    if yaw_token is None:
        yaw_token = stat_yaw_from_text((token.get("motion") or {}).get("stat_after", ""))
    if yaw_token is None:
        yaw_token = stat_yaw_from_text(stat_before_text)
    yaw_final = stat_yaw_from_text(stat_after_text)
    y_dist_token = planner_to_float(pre_state.get("slot_y_dist_cm"))
    prior_progress = planner_to_float(motion.get("odom_progress_cm"), 0.0)
    current_progress = stat_d_from_text(stat_after_text)
    if current_progress is None:
        current_progress = 0.0
    depth_est = max(0.0, y_dist_token - prior_progress - current_progress)
    max_depth = planner_to_float(
        getattr(args, "final_pose_max_depth_cm", args.final_blind_target_y_dist_cm + 2.0),
        args.final_blind_target_y_dist_cm + 2.0,
    )
    report = {
        "schema": "parking_final_pose_report.v1",
        "heading_vision_token_deg": round(heading_token, 3),
        "yaw_token_deg": None if yaw_token is None else round(yaw_token, 3),
        "yaw_final_deg": None if yaw_final is None else round(yaw_final, 3),
        "yaw_delta_deg": None,
        "final_heading_deg": None,
        "final_lateral_est_cm": planner_to_float(pre_state.get("slot_lateral_cm")),
        "depth_est_cm": round(depth_est, 3),
        "depth_token_cm": round(y_dist_token, 3),
        "depth_prior_progress_cm": round(prior_progress, 3),
        "depth_current_progress_cm": round(current_progress, 3),
        "verdict": "unknown",
        "thresholds": {
            "straight_heading_abs_deg": args.final_pose_straight_heading_deg,
            "lateral_abs_cm": args.final_pose_lateral_cm,
            "max_depth_cm": max_depth,
        },
    }
    if yaw_token is None or yaw_final is None:
        report["verdict"] = "unknown_missing_yaw"
        return report
    yaw_delta = angle_delta_deg(yaw_final - yaw_token)
    if getattr(args, "_fusion_signs", None) is not None:
        yaw_delta *= args._fusion_signs.yaw_to_cw_sign
    final_heading = heading_token + yaw_delta
    report["yaw_delta_deg"] = round(yaw_delta, 3)
    report["final_heading_deg"] = round(final_heading, 3)
    depth_ok = depth_est <= max_depth
    if not depth_ok:
        report["verdict"] = "incomplete_depth"
    elif abs(final_heading) <= args.final_pose_straight_heading_deg:
        report["verdict"] = "parked_straight"
    else:
        report["verdict"] = "parked_crooked"
    if report["verdict"] != "incomplete_depth" and abs(report["final_lateral_est_cm"]) > args.final_pose_lateral_cm:
        report["verdict"] = "not_in" if report["verdict"] == "parked_crooked" else "parked_lateral_offset"
    return report


def counter_steer_result_from_motion(decision, stat_before_text, stat_after_text, args):
    yaw_before = stat_yaw_from_text(stat_before_text)
    yaw_after = stat_yaw_from_text(stat_after_text)
    result = {
        "schema": "parking_counter_steer_result.v1",
        "decision": decision,
        "yaw_before_deg": None if yaw_before is None else round(yaw_before, 3),
        "yaw_after_deg": None if yaw_after is None else round(yaw_after, 3),
        "measured_delta_heading_deg": None,
        "predicted_delta_heading_deg": decision.get("predicted_delta_heading_deg"),
        "pre_heading_deg": decision.get("slot_heading_err_deg"),
        "post_heading_est_deg": None,
        "verdict": "unknown_missing_yaw",
    }
    if yaw_before is None or yaw_after is None:
        return result
    yaw_delta = angle_delta_deg(yaw_after - yaw_before)
    if getattr(args, "_fusion_signs", None) is not None:
        yaw_delta *= args._fusion_signs.yaw_to_cw_sign
    pre_heading = planner_to_float(decision.get("slot_heading_err_deg"))
    post_heading = pre_heading + yaw_delta
    result["measured_delta_heading_deg"] = round(yaw_delta, 3)
    result["post_heading_est_deg"] = round(post_heading, 3)
    if abs(post_heading) <= args.counter_steer_heading_enter_deg:
        result["verdict"] = "straightened"
    elif abs(post_heading) < abs(pre_heading):
        result["verdict"] = "improved"
    else:
        result["verdict"] = "worse"
    return result


def counter_steer_decision_from_state(pre_state, args, kinematics):
    state = pre_state or {}
    heading = planner_to_float(state.get("slot_heading_err_deg"))
    lateral = planner_to_float(state.get("slot_lateral_cm"))
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    phase = state.get("phase_hint")
    phase_ok = (
        phase == "straighten_or_enter"
        or phase == "final_stop_zone"
        or (
            phase == "align_in_corridor"
            and y_dist <= args.counter_steer_align_phase_max_y_dist_cm
        )
    )
    terminal_recovery_zone = (
        y_dist <= args.counter_steer_align_phase_max_y_dist_cm
        and abs(lateral) <= args.counter_steer_max_lateral_cm
        and phase_ok
    )
    base_heading_cap = planner_to_float(args.counter_steer_heading_stop_deg)
    terminal_heading_cap = planner_to_float(
        getattr(args, "counter_steer_terminal_heading_stop_deg", base_heading_cap),
        base_heading_cap,
    )
    heading_cap_limit = max(base_heading_cap, terminal_heading_cap) if terminal_recovery_zone else base_heading_cap
    checks = {
        "enabled": bool(args.counter_steer_enable),
        "phase_ok": phase_ok,
        "lateral_ok": abs(lateral) <= args.counter_steer_max_lateral_cm,
        "heading_need": abs(heading) > args.counter_steer_heading_enter_deg,
        "heading_cap": abs(heading) <= heading_cap_limit,
    }
    decision = {
        "schema": "parking_counter_steer_decision.v1",
        "enabled": bool(args.counter_steer_enable),
        "phase_hint": phase,
        "slot_heading_err_deg": round(heading, 3),
        "slot_lateral_cm": round(lateral, 3),
        "slot_y_dist_cm": round(y_dist, 3),
        "checks": checks,
        "heading_cap_limit_deg": round(heading_cap_limit, 3),
        "terminal_recovery_zone": bool(terminal_recovery_zone),
        "verdict": "not_applicable",
        "candidate_cmd": "WAIT",
        "predicted_delta_heading_deg": 0.0,
    }
    if not all(checks.values()):
        decision["verdict"] = "gate_closed"
        return decision
    desired_delta = -heading
    hard = abs(heading) >= args.counter_steer_hard_heading_deg
    if desired_delta < 0.0:
        ste = args.counter_steer_left_hard_ste if hard else args.counter_steer_left_soft_ste
    else:
        ste = args.counter_steer_right_hard_ste if hard else args.counter_steer_right_soft_ste
    row = kinematics_row_for_ste(kinematics, ste)
    deg_per_cm = planner_to_float((row or {}).get("deg_per_cm"), 0.0)
    if deg_per_cm == 0.0:
        decision.update({
            "verdict": "missing_kinematics",
            "selected_ste": ste,
            "kinematics_row": row,
        })
        return decision
    if desired_delta * deg_per_cm <= 0.0:
        decision.update({
            "verdict": "wrong_curvature_sign",
            "selected_ste": ste,
            "deg_per_cm": round(deg_per_cm, 6),
            "desired_delta_heading_deg": round(desired_delta, 3),
        })
        return decision
    arc_deadband = planner_to_float((kinematics or {}).get("arc_deadband_cm"), args.counter_steer_arc_deadband_cm)
    min_cmd = planner_to_float((kinematics or {}).get("arc_min_effective_cmd_cm"), None)
    if min_cmd is None:
        min_cmd = args.counter_steer_min_command_cm
    actual_needed = abs(desired_delta) / abs(deg_per_cm)
    command_cm = clamp(actual_needed + arc_deadband, min_cmd, args.counter_steer_max_command_cm)
    predicted_delta = math.copysign(max(0.0, command_cm - arc_deadband) * abs(deg_per_cm), desired_delta)
    cmd = "ARC D=-%.1f STE=%d V=%d" % (round(command_cm, 1), int(round(ste)), GEAR)
    decision.update({
        "verdict": "counter_steer",
        "candidate_cmd": cmd,
        "action": "ARC",
        "selected_ste": int(round(ste)),
        "hard_arc": bool(hard),
        "deg_per_cm": round(deg_per_cm, 6),
        "arc_deadband_cm": round(arc_deadband, 3),
        "actual_needed_cm": round(actual_needed, 3),
        "command_cm": round(command_cm, 3),
        "predicted_delta_heading_deg": round(predicted_delta, 3),
        "predicted_final_heading_deg": round(heading + predicted_delta, 3),
        "kinematics_row": row,
    })
    return decision


def action_from_counter_steer(decision):
    try:
        kind, step, servo = _parse_motion_command_for_action(decision.get("candidate_cmd", ""))
    except (ValueError, IndexError):
        kind, step, servo = "WAIT", 0.0, int(SERVO_CENTER)
    return {
        "state": "COUNTER_STEER",
        "action": kind,
        "cmd": decision.get("candidate_cmd", "WAIT"),
        "step": round(step, 1),
        "servo": servo,
        "steer_dir": 0.0 if servo == SERVO_CENTER else (1.0 if servo > SERVO_CENTER else -1.0),
        "reason": "terminal_heading_counter_steer",
        "binding": {
            "action_id": "counter_steer_dynamic",
            "score": None,
            "origin": "chassis_kinematics",
            "confidence": None,
        },
        "counter_steer": decision,
    }


def final_blind_pre_state_review(pre_state, args):
    """Return gate details for allowing one terminal blind reverse token."""
    state = pre_state or {}
    heading_abs = abs(planner_to_float(state.get("slot_heading_err_deg")))
    lateral_abs = abs(planner_to_float(state.get("slot_lateral_cm")))
    slot_x_abs = abs(planner_to_float(state.get("slot_x_err_px")))
    min_margin = planner_to_float(state.get("min_margin_px"))
    vision_review = terminal_unreliable_vision_review(state, args)
    ignore_slot_x = bool(vision_review.get("ignored_terminal_slot_x_err_px"))
    max_lateral = args.final_blind_max_lateral_cm
    max_terminal_lateral = args.final_blind_max_terminal_lateral_cm
    max_heading = (
        args.final_blind_arc_max_heading_err_deg
        if args.final_blind_allow_heading_arc else args.final_blind_max_heading_err_deg)
    min_margin_gate = args.final_blind_min_margin_px
    if ignore_slot_x:
        max_lateral = planner_to_float(
            getattr(args, "terminal_unreliable_vision_max_lateral_cm", 5.0), 5.0)
        max_terminal_lateral = max_lateral
        max_heading = planner_to_float(
            getattr(args, "terminal_unreliable_vision_max_heading_deg", 4.0), 4.0)
        min_margin_gate = planner_to_float(
            getattr(args, "terminal_unreliable_vision_min_margin_px", 120.0), 120.0)
    desired_actual_cm = final_blind_desired_actual_cm_from_state(state, None, args)
    terminal_lateral_abs = lateral_abs + desired_actual_cm * math.sin(math.radians(heading_abs))
    heading_ok = heading_abs <= max_heading
    checks = {
        "stable_enough": bool(state.get("stable_enough")),
        "line_margin_ok": bool(state.get("line_margin_ok")),
        "line_risk_clear": not bool(state.get("line_risk")),
        "phase_ok": state.get("phase_hint") in ("straighten_or_enter", "final_stop_zone"),
        "x_err_ok": True if ignore_slot_x else slot_x_abs <= args.final_blind_max_x_err_px,
        "lateral_ok": lateral_abs <= max_lateral,
        "heading_ok": heading_ok,
        "margin_ok": min_margin >= min_margin_gate,
        "distance_ok": planner_to_float(state.get("slot_y_dist_cm")) <= args.final_blind_max_y_dist_cm,
        "predicted_terminal_lateral_ok": terminal_lateral_abs <= max_terminal_lateral,
    }
    if lateral_abs > max_lateral:
        mode = "reject_lateral_visible_correction_required"
    elif heading_abs <= args.final_blind_straight_heading_err_deg:
        mode = "straight"
    elif args.final_blind_allow_heading_arc and heading_abs <= max_heading:
        mode = "heading_cancel_arc"
    else:
        mode = "reject_heading"
    return {
        "pass": all(checks.values()),
        "mode": mode,
        "checks": checks,
        "thresholds": {
            "max_x_err_px": args.final_blind_max_x_err_px,
            "max_lateral_cm": max_lateral,
            "straight_heading_err_deg": args.final_blind_straight_heading_err_deg,
            "max_heading_err_deg": max_heading,
            "arc_max_heading_err_deg": args.final_blind_arc_max_heading_err_deg,
            "min_margin_px": min_margin_gate,
            "max_y_dist_cm": args.final_blind_max_y_dist_cm,
            "max_terminal_lateral_cm": max_terminal_lateral,
        },
        "metrics": {
            "slot_x_err_abs_px": round(slot_x_abs, 3),
            "raw_slot_x_err_px_abs": round(slot_x_abs, 3),
            "slot_lateral_abs_cm": round(lateral_abs, 3),
            "slot_heading_abs_deg": round(heading_abs, 3),
            "slot_y_dist_cm": round(planner_to_float(state.get("slot_y_dist_cm")), 3),
            "min_margin_px": round(min_margin, 3),
            "terminal_vision_reliable": bool(vision_review.get("terminal_vision_reliable")),
            "ignored_terminal_slot_x_err_px": ignore_slot_x,
            "x_ok_source": vision_review.get("x_ok_source"),
        },
        "predicted": {
            "desired_actual_cm": round(desired_actual_cm, 3),
            "terminal_lateral_abs_cm": round(terminal_lateral_abs, 3),
        },
        "terminal_vision": vision_review,
    }


def final_blind_precomputed_state_from_replanner(replanner):
    replanner = replanner or {}
    chosen = replanner.get("chosen") or {}
    ranking = replanner.get("ranking") or []
    pre_state = replanner.get("pre_state") or {}
    selected = None
    action_id = chosen.get("action_id")
    for item in ranking:
        if item.get("action_id") == action_id:
            selected = item
            break
    predicted = (selected or {}).get("predicted") or {}
    if not selected or not predicted:
        return None, {
            "active": False,
            "reason": "missing_selected_prediction",
            "chosen": chosen,
        }
    state = dict(pre_state)
    for key in [
        "slot_y_dist_cm",
        "slot_x_err_px",
        "slot_lateral_cm",
        "slot_heading_err_deg",
        "min_margin_px",
        "line_risk",
    ]:
        if key in predicted:
            state[key] = predicted.get(key)
    state["precomputed_from_action_id"] = action_id
    state["precomputed_from_command"] = chosen.get("command")
    state["precomputed_origin"] = selected.get("origin")
    state["precomputed_confidence"] = selected.get("confidence")
    state["precomputed_score"] = selected.get("score")
    state["precomputed_block_reasons"] = list(selected.get("block_reasons") or [])
    state["precomputed_visible_lateral_recovery"] = selected.get("visible_lateral_recovery")
    state["precomputed_prior_lateral_recovery"] = selected.get("prior_lateral_recovery")
    return state, {
        "active": True,
        "reason": "selected_action_predicted_state",
        "selected": selected,
        "chosen": chosen,
    }


def final_blind_precomputed_state_review(pre_state, chosen, args):
    state = pre_state or {}
    chosen = chosen or {}
    enabled = bool(getattr(args, "final_blind_precomputed_token_enable", True))
    heading_abs = abs(planner_to_float(state.get("slot_heading_err_deg")))
    lateral_abs = abs(planner_to_float(state.get("slot_lateral_cm")))
    slot_x_abs = abs(planner_to_float(state.get("slot_x_err_px")))
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    min_margin = planner_to_float(state.get("min_margin_px"))
    confidence = planner_to_float(state.get("precomputed_confidence"), 0.0)
    max_heading = planner_to_float(
        getattr(args, "final_blind_precomputed_max_heading_deg", 24.0), 24.0)
    max_x_err = planner_to_float(
        getattr(args, "final_blind_precomputed_max_x_err_px", 40.0), 40.0)
    min_confidence = planner_to_float(
        getattr(args, "final_blind_precomputed_min_confidence", 0.1), 0.1)
    max_y_dist = planner_to_float(
        getattr(args, "final_blind_precomputed_max_y_dist_cm", args.final_blind_max_y_dist_cm),
        args.final_blind_max_y_dist_cm,
    )
    terminal_lateral_cap = planner_to_float(args.final_blind_max_terminal_lateral_cm)
    vision_review = terminal_unreliable_vision_review(
        state, args, source=("predicted_post_action" if state.get("precomputed_from_action_id") else None))
    ignore_slot_x = bool(vision_review.get("ignored_terminal_slot_x_err_px"))
    min_margin_gate = args.final_blind_min_margin_px
    if ignore_slot_x:
        terminal_lateral_cap = planner_to_float(
            getattr(args, "terminal_unreliable_vision_max_lateral_cm", 5.0), 5.0)
        max_heading = planner_to_float(
            getattr(args, "terminal_unreliable_vision_max_heading_deg", 4.0), 4.0)
        min_margin_gate = planner_to_float(
            getattr(args, "terminal_unreliable_vision_min_margin_px", 120.0), 120.0)
    checks = {
        "enabled": enabled,
        "stable_enough": bool(state.get("stable_enough")),
        "line_margin_ok": bool(state.get("line_margin_ok")),
        "line_risk_clear": not bool(state.get("line_risk")),
        "chosen_action_ok": chosen.get("action") in ("MOVE", "ARC"),
        "chosen_not_stop_wait": chosen.get("action_id") not in ("WAIT", "STOP", None),
        "predicted_not_blocked": not bool(chosen.get("hard_blocked")),
        "x_err_ok": True if ignore_slot_x else slot_x_abs <= max_x_err,
        "terminal_lateral_ok": lateral_abs <= terminal_lateral_cap,
        "heading_ok": heading_abs <= max_heading,
        "margin_ok": min_margin >= min_margin_gate,
        "distance_ok": y_dist <= max_y_dist,
        "confidence_ok": confidence >= min_confidence,
    }
    if heading_abs <= args.final_blind_straight_heading_err_deg:
        mode = "straight"
    elif heading_abs <= max_heading:
        mode = "heading_cancel_arc"
    else:
        mode = "reject_heading"
    return {
        "schema": "parking_final_blind_precomputed_review.v1",
        "pass": all(checks.values()),
        "mode": mode,
        "allow_heading_arc": bool(getattr(args, "final_blind_precomputed_allow_heading_arc", True)),
        "checks": checks,
        "thresholds": {
            "max_x_err_px": max_x_err,
            "max_terminal_lateral_cm": terminal_lateral_cap,
            "max_heading_deg": max_heading,
            "min_margin_px": min_margin_gate,
            "max_y_dist_cm": max_y_dist,
            "min_confidence": min_confidence,
        },
        "metrics": {
            "slot_x_err_abs_px": round(slot_x_abs, 3),
            "raw_slot_x_err_px_abs": round(slot_x_abs, 3),
            "slot_lateral_abs_cm": round(lateral_abs, 3),
            "slot_heading_abs_deg": round(heading_abs, 3),
            "slot_y_dist_cm": round(y_dist, 3),
            "min_margin_px": round(min_margin, 3),
            "confidence": round(confidence, 3),
            "terminal_vision_reliable": bool(vision_review.get("terminal_vision_reliable")),
            "ignored_terminal_slot_x_err_px": ignore_slot_x,
            "x_ok_source": vision_review.get("x_ok_source"),
        },
        "terminal_vision": vision_review,
    }


def final_blind_desired_actual_cm_from_state(pre_state, token, args):
    configured = max(0.0, planner_to_float(args.final_blind_reverse_cm))
    if args.final_blind_distance_mode == "fixed":
        return configured
    state = pre_state or {}
    source = token or {}
    motion = source.get("motion") or {}
    y_dist = planner_to_float(state.get("slot_y_dist_cm"))
    progress = planner_to_float(motion.get("odom_progress_cm"))
    remaining = max(0.0, y_dist - progress - args.final_blind_target_y_dist_cm)
    if configured > 0.0:
        remaining = min(remaining, configured)
    return remaining


def final_blind_command_distance_cm(desired_actual_cm, args):
    if desired_actual_cm <= 0.0:
        return 0.0
    if not args.final_blind_compensate_deadband:
        return desired_actual_cm
    command_cm = desired_actual_cm + args.final_blind_deadband_cm - args.final_blind_coast_cm
    return max(desired_actual_cm, command_cm)


def final_blind_plan_from_token(token, args, remaining_total_cm):
    pre_state = (token or {}).get("pre_state") or {}
    review = (token or {}).get("pre_state_review") or {}
    mode = review.get("mode") or "straight"
    heading = planner_to_float(pre_state.get("slot_heading_err_deg"))
    desired_actual = final_blind_desired_actual_cm_from_state(pre_state, token, args)
    desired_actual = min(desired_actual, args.final_blind_max_actual_cm, max(0.0, remaining_total_cm))
    command_cm = final_blind_command_distance_cm(desired_actual, args)
    command_cm = round(min(command_cm, args.final_blind_max_command_cm, max(0.0, remaining_total_cm)), 1)
    allow_heading_arc = bool(args.final_blind_allow_heading_arc or review.get("allow_heading_arc"))
    if mode == "heading_cancel_arc" and allow_heading_arc:
        arc_actual = math.radians(abs(heading)) * max(1.0, args.final_blind_arc_reff_cm)
        arc_actual = min(arc_actual, desired_actual)
        arc_command_cm = final_blind_command_distance_cm(arc_actual, args)
        command_cm = round(min(arc_command_cm, args.final_blind_max_command_cm, max(0.0, remaining_total_cm)), 1)
        servo = args.final_blind_arc_left_servo if heading > 0 else args.final_blind_arc_right_servo
        return {
            "action": "ARC",
            "cmd": "ARC D=%.1f STE=%d V=%d" % (-command_cm, int(round(servo)), GEAR),
            "command_cm": command_cm,
            "desired_actual_cm": round(desired_actual, 3),
            "arc_actual_cm": round(arc_actual, 3),
            "servo": int(round(servo)),
            "mode": mode,
            "heading_err_deg": round(heading, 3),
        }
    return {
        "action": "ARC",
        "cmd": center_arc_command(-command_cm, GEAR),
        "command_cm": command_cm,
        "desired_actual_cm": round(desired_actual, 3),
        "servo": int(round(SERVO_CENTER)),
        "mode": "straight_center_arc",
        "heading_err_deg": round(heading, 3),
    }


def write_final_blind_token(path, payload):
    tmp_path = path + ".tmp"
    with open(tmp_path, "w", encoding="utf-8") as f:
        json.dump(payload, f, ensure_ascii=False, separators=(",", ":"))
        f.write("\n")
    os.replace(tmp_path, path)


def read_final_blind_token(path):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except (OSError, ValueError):
        return None


def invalidate_final_blind_token(path, token, reason, extra=None):
    if not token:
        return None
    updated = dict(token)
    updated["consumed"] = True
    updated["invalidated"] = True
    updated["invalidated_reason"] = reason
    updated["invalidated_time_unix"] = time.time()
    if extra:
        updated["invalidated_extra"] = extra
    try:
        write_final_blind_token(path, updated)
    except OSError:
        return None
    return updated


def final_blind_token_is_precomputed(token):
    review = (token or {}).get("pre_state_review") or {}
    return review.get("schema") == "parking_final_blind_precomputed_review.v1"


def final_blind_precomputed_keep_on_visible_gate_fail(args, token, pre_state_review):
    if not getattr(args, "final_blind_precomputed_keep_on_visible_gate_fail", True):
        return False
    if not final_blind_token_is_precomputed(token):
        return False
    checks = (pre_state_review or {}).get("checks") or {}
    return bool(
        checks.get("line_margin_ok", True) and
        checks.get("line_risk_clear", True) and
        checks.get("margin_ok", True)
    )


def final_blind_token_progress_since_ledger(token, total_cm):
    if total_cm is None or not final_blind_token_is_precomputed(token):
        return 0.0
    totals = (token or {}).get("totals_after_action") or {}
    token_total = planner_to_float(totals.get("total_cm"), None)
    if token_total is None:
        return 0.0
    return max(0.0, float(total_cm) - float(token_total))


def final_blind_token_for_runtime(token, total_cm):
    if not token or not final_blind_token_is_precomputed(token):
        return token
    post_token_progress = final_blind_token_progress_since_ledger(token, total_cm)
    if post_token_progress <= 0.0:
        return token
    adjusted = deepcopy_jsonable(token)
    motion = dict(adjusted.get("motion") or {})
    base_progress = planner_to_float(motion.get("odom_progress_cm"), 0.0)
    motion["odom_progress_cm"] = round(base_progress + post_token_progress, 3)
    motion["post_token_progress_cm"] = round(post_token_progress, 3)
    adjusted["motion"] = motion
    adjusted["runtime_progress_since_token_cm"] = round(post_token_progress, 3)
    return adjusted


def final_blind_token_review(token, args, steps=None, total_cm=None):
    computed_pre_state_review = None
    if token:
        token_review = token.get("pre_state_review") or {}
        if token_review.get("schema") == "parking_final_blind_precomputed_review.v1":
            computed_pre_state_review = final_blind_precomputed_state_review(
                token.get("pre_state") or {}, token.get("chosen") or {}, args)
        else:
            computed_pre_state_review = final_blind_pre_state_review(token.get("pre_state") or {}, args)
    totals = (token or {}).get("totals_after_action") or {}
    token_steps = planner_to_float(totals.get("steps_done"), None)
    token_total = planner_to_float(totals.get("total_cm"), None)
    total_tol = planner_to_float(
        getattr(args, "final_blind_token_total_tolerance_cm", 0.5), 0.5)
    precomputed = final_blind_token_is_precomputed(token)
    max_carry = planner_to_float(
        getattr(args, "final_blind_precomputed_max_carry_cm", 24.0), 24.0)
    progress_since_token = final_blind_token_progress_since_ledger(token, total_cm)
    ledger_steps_ok = True
    ledger_total_ok = True
    if steps is not None and token_steps is not None:
        if precomputed:
            ledger_steps_ok = int(steps) >= int(token_steps)
        else:
            ledger_steps_ok = int(token_steps) == int(steps)
    if total_cm is not None and token_total is not None:
        if precomputed:
            ledger_total_ok = (
                float(total_cm) + total_tol >= float(token_total) and
                progress_since_token <= max_carry + total_tol
            )
        else:
            ledger_total_ok = abs(float(token_total) - float(total_cm)) <= total_tol
    checks = {
        "exists": token is not None,
        "schema_ok": bool(token and token.get("schema") == "parking_final_blind_token.v1"),
        "not_consumed": bool(token and not token.get("consumed")),
        "fresh": bool(token and (time.time() - planner_to_float(token.get("time_unix"))) <= args.final_blind_token_max_age_sec),
        "ledger_steps_ok": bool(ledger_steps_ok),
        "ledger_total_ok": bool(ledger_total_ok),
    }
    if token:
        checks["pre_state_ok"] = bool((token.get("pre_state_review") or {}).get("pass"))
        chosen = token.get("chosen") or {}
        checks["chosen_action_ok"] = chosen.get("action") in ("MOVE", "ARC")
        checks["chosen_not_stop_wait"] = chosen.get("action_id") not in ("WAIT", "STOP")
    else:
        checks["pre_state_ok"] = False
        checks["chosen_action_ok"] = False
        checks["chosen_not_stop_wait"] = False
    if computed_pre_state_review is not None:
        checks["pre_state_ok"] = bool(computed_pre_state_review.get("pass"))
    return {
        "pass": all(checks.values()),
        "checks": checks,
        "computed_pre_state_review": computed_pre_state_review,
        "ledger": {
            "current_steps": steps,
            "token_steps": None if token_steps is None else int(token_steps),
            "current_total_cm": None if total_cm is None else round(float(total_cm), 3),
            "token_total_cm": None if token_total is None else round(float(token_total), 3),
            "total_tolerance_cm": total_tol,
            "precomputed_carry_forward": bool(precomputed),
            "progress_since_token_cm": round(progress_since_token, 3),
            "max_carry_cm": max_carry,
        },
    }


def invalidate_final_blind_token_for_visible_state(args, pre_state_review, steps, total_cm, context=None):
    event = {
        "enabled": bool(getattr(args, "allow_final_blind_reverse", False)),
        "path": getattr(args, "final_blind_token", ""),
        "pre_state_review": pre_state_review,
        "invalidated": False,
    }
    if not event["enabled"] or pre_state_review.get("pass") or not event["path"]:
        return event
    old_token = read_final_blind_token(event["path"])
    old_review = final_blind_token_review(old_token, args, steps=steps, total_cm=total_cm)
    event["token_review_before_invalidate"] = old_review
    if old_token and final_blind_precomputed_keep_on_visible_gate_fail(args, old_token, pre_state_review):
        event["kept_precomputed_token"] = True
        event["keep_reason"] = "precomputed_token_visible_gate_fail_without_line_risk"
        return event
    if old_token and old_review.get("checks", {}).get("not_consumed"):
        invalidated = invalidate_final_blind_token(
            event["path"],
            old_token,
            "latest_visible_state_failed_final_blind_gate",
            {
                "current_steps": steps,
                "current_total_cm": round(total_cm, 3),
                "pre_state_review": pre_state_review,
                "token_review_before_invalidate": old_review,
                "context": context or {},
            },
        )
        event["invalidated"] = bool(invalidated)
        event["invalidate_reason"] = "latest_visible_state_failed_final_blind_gate"
    return event


def final_blind_degraded_visibility_review(rel_state, parking_criteria, token_review, args):
    """Gate final blind use when terminal polygon geometry is too degraded to trust."""
    state = rel_state or {}
    visibility = state.get("visibility") or {}
    vision = state.get("vision") or {}
    image = state.get("image") or {}
    ground = state.get("ground_estimate") or {}
    visible_ratio = planner_to_float(
        visibility.get("slot_visible_ratio", vision.get("slot_visible_ratio")))
    near_ratio_y = planner_to_float(image.get("near_ratio_y"))
    near_ratio_h = planner_to_float(image.get("near_ratio_h"))
    slot_y_dist_cm = planner_to_float(ground.get("slot_y_dist_cm"))
    checks = {
        "criteria_min_margin_abort": (
            parking_criteria.get("verdict") == "aborted"
            and parking_criteria.get("reason") == "min_margin_below_floor"
        ),
        "token_ok": bool((token_review or {}).get("pass")),
        "visible_ratio_positive": visible_ratio > 0.0,
        "visible_ratio_low": visible_ratio <= args.final_blind_degraded_visible_ratio_max,
        "terminal_near": (
            near_ratio_y >= args.final_blind_degraded_near_ratio_min
            or near_ratio_h >= args.final_blind_degraded_quad_h_ratio_min
        ),
        "distance_ok": slot_y_dist_cm <= args.final_blind_max_y_dist_cm,
        "entry_edge_visible": bool(visibility.get("entry_edge_visible", vision.get("entry_edge_visible"))),
    }
    return {
        "pass": all(checks.values()),
        "checks": checks,
        "metrics": {
            "slot_visible_ratio": round(visible_ratio, 6),
            "near_ratio_y": round(near_ratio_y, 3),
            "near_ratio_h": round(near_ratio_h, 3),
            "slot_y_dist_cm": round(slot_y_dist_cm, 3),
        },
        "thresholds": {
            "visible_ratio_max": args.final_blind_degraded_visible_ratio_max,
            "near_ratio_min": args.final_blind_degraded_near_ratio_min,
            "quad_h_ratio_min": args.final_blind_degraded_quad_h_ratio_min,
            "max_y_dist_cm": args.final_blind_max_y_dist_cm,
        },
    }


def consume_final_blind_token(path, token, result):
    if not token:
        return
    updated = dict(token)
    updated["consumed"] = True
    updated["consumed_time_unix"] = time.time()
    updated["consume_result"] = result
    try:
        write_final_blind_token(path, updated)
    except OSError:
        pass


def _cmd_from_plan_with_policy(p, step_cm, steer_deg, lateral_sign, max_abs_d_cm=None):
    lat = p["lat"]
    head = p["head"]
    step = min(step_cm, max(1.0, p["lon"])) if p["lon"] > 0 else step_cm
    abs_d = round(step, 1) + DEADBAND_CM
    if max_abs_d_cm is not None:
        abs_d = min(abs_d, max_abs_d_cm)
    cmd_d = -abs_d
    if abs(lat) >= DEFAULT_LAT_TEMPLATE_THRESHOLD_CM:
        raw_dir = 1.0 if lat > 0 else -1.0
        steer_dir = lateral_sign * raw_dir
        servo = int(round(clamp(SERVO_CENTER + steer_dir * steer_deg * STEERING_SIGN,
                                SERVO_MIN, SERVO_MAX)))
        return {
            "state": "FEEDBACK_ALIGN_LATERAL",
            "cmd": "ARC D=%.1f STE=%d V=%d" % (cmd_d, servo, GEAR),
            "step": step,
            "servo": servo,
            "steer_dir": steer_dir,
            "reason": "feedback_lateral",
        }
    if abs(head) >= DEFAULT_HEAD_TEMPLATE_THRESHOLD_DEG:
        raw_dir = 1.0 if head > 0 else -1.0
        steer_dir = raw_dir
        servo = int(round(clamp(SERVO_CENTER + steer_dir * steer_deg * 0.5 * STEERING_SIGN,
                                SERVO_MIN, SERVO_MAX)))
        return {
            "state": "FEEDBACK_STRAIGHTEN",
            "cmd": "ARC D=%.1f STE=%d V=%d" % (cmd_d, servo, GEAR),
            "step": step,
            "servo": servo,
            "steer_dir": steer_dir,
            "reason": "feedback_heading",
        }
    return {
        "state": "FEEDBACK_FINAL_REVERSE",
        "cmd": center_arc_command(cmd_d, GEAR),
        "step": step,
        "servo": SERVO_CENTER,
        "steer_dir": 0.0,
        "reason": "feedback_centered_center_arc",
    }


def collect_stable_plan(sock, args, timeout_sec):
    filt = SlotStabilityFilter(args.stable_frames, args.max_center_shift_cm, args.max_axis_yaw_shift_deg)
    end = time.time() + timeout_sec
    last = None
    while time.time() < end:
        info = acquire_info(sock, max(0.2, min(args.target_wait_sec, end - time.time())))
        if info is None:
            continue
        stable, metrics = filt.add(info)
        fused = filt.fused() if stable else info
        last = (stable, fused, metrics)
        if stable:
            return last
    return last


def _read_feedback_token(path, timeout_sec):
    print("  feedback: write '+', '-', '0', 'r', or 'q' to %s" % path, flush=True)
    deadline = time.time() + timeout_sec if timeout_sec > 0 else None
    while deadline is None or time.time() < deadline:
        try:
            with open(path, "r", encoding="utf-8") as f:
                token = f.read().strip().lower()
        except OSError:
            token = ""
        if token:
            try:
                with open(path, "w", encoding="utf-8") as f:
                    f.write("")
            except OSError:
                pass
            if token[0] in ["+", "-", "0", "r", "q"]:
                return token[0]
        time.sleep(0.2)
    return ""


def _auto_feedback(pre_p, post_p, min_lat_improve_cm):
    lat_delta = abs(pre_p["lat"]) - abs(post_p["lat"])
    lon_delta = pre_p["lon"] - post_p["lon"]
    heading_penalty = max(0.0, abs(post_p["head"]) - abs(pre_p["head"]))
    score = lat_delta + 0.25 * lon_delta - 0.12 * heading_penalty
    reward = 1 if lat_delta >= min_lat_improve_cm and lon_delta >= -1.0 else -1
    return reward, {
        "lat_delta_abs_cm": round(lat_delta, 3),
        "lon_delta_cm": round(lon_delta, 3),
        "heading_penalty_deg": round(heading_penalty, 3),
        "score": round(score, 3),
    }


def _bucket(value, cuts, labels):
    for cut, label in zip(cuts, labels):
        if value < cut:
            return label
    return labels[-1]


def policy_state_key(p):
    lon_b = _bucket(p["lon"], [12.0, 25.0, 45.0], ["near", "mid", "far", "very_far"])
    alat = abs(p["lat"])
    if alat < 2.5:
        lat_b = "center"
    elif alat < 6.0:
        lat_b = "left_small" if p["lat"] > 0 else "right_small"
    else:
        lat_b = "left_large" if p["lat"] > 0 else "right_large"
    ahead = abs(p["head"])
    if ahead < 2.0:
        head_b = "straight"
    elif ahead < 6.0:
        head_b = "yaw_pos_small" if p["head"] > 0 else "yaw_neg_small"
    else:
        head_b = "yaw_pos_large" if p["head"] > 0 else "yaw_neg_large"
    return "%s|%s|%s" % (lon_b, lat_b, head_b)


def parse_policy_actions(text, max_abs_d_cm):
    actions = []
    for raw in text.split("|"):
        cmd = raw.strip()
        if not cmd:
            continue
        if cmd == "STOP":
            actions.append(cmd)
            continue
        parts = cmd.split()
        kind = parts[0] if parts else ""
        kv = {}
        for part in parts[1:]:
            if "=" in part:
                k, v = part.split("=", 1)
                kv[k.upper()] = v
        if kind not in ["MOVE", "ARC"]:
            raise ValueError("unsupported action kind: %s" % cmd)
        d = float(kv.get("D", "0"))
        if d >= 0 or abs(d) > max_abs_d_cm:
            raise ValueError("unsafe action distance: %s" % cmd)
        if int(kv.get("V", str(GEAR))) > GEAR:
            raise ValueError("unsafe gear: %s" % cmd)
        if kind == "ARC":
            ste = int(float(kv.get("STE", str(SERVO_CENTER))))
            if ste < SERVO_MIN or ste > SERVO_MAX:
                raise ValueError("unsafe servo: %s" % cmd)
        actions.append(cmd)
    if not actions:
        raise ValueError("empty policy action list")
    return actions


def load_policy(path, actions):
    try:
        with open(path, "r", encoding="utf-8") as f:
            policy = json.load(f)
    except OSError:
        policy = {}
    policy.setdefault("schema_version", 1)
    policy.setdefault("actions", actions)
    policy.setdefault("q", {})
    policy.setdefault("counts", {})
    policy.setdefault("episodes", 0)
    return policy


def save_policy(path, policy):
    tmp = path + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(policy, f, ensure_ascii=False, indent=2, sort_keys=True)
        f.write("\n")
    os.replace(tmp, path)


def choose_policy_action(policy, state_key, actions, epsilon):
    q_state = policy.setdefault("q", {}).setdefault(state_key, {})
    for action in actions:
        q_state.setdefault(action, 0.0)
    if random.random() < epsilon:
        return random.choice(actions), "explore"
    best_q = max(q_state.get(a, 0.0) for a in actions)
    tied = [a for a in actions if abs(q_state.get(a, 0.0) - best_q) < 1e-9]
    return random.choice(tied), "exploit"


def update_policy(policy, state_key, action, reward, alpha):
    q_state = policy.setdefault("q", {}).setdefault(state_key, {})
    old = float(q_state.get(action, 0.0))
    new = old + alpha * (reward - old)
    q_state[action] = round(new, 4)
    count_key = "%s||%s" % (state_key, action)
    counts = policy.setdefault("counts", {})
    counts[count_key] = int(counts.get(count_key, 0)) + 1
    return old, new, counts[count_key]


def reward_from_token(token, auto_reward):
    if token == "+":
        return 1.0, "manual_positive"
    if token == "-":
        return -1.0, "manual_negative"
    if token == "0":
        return 0.0, "manual_neutral"
    return float(auto_reward), "auto"


def wait_restart_or_quit(args, policy, reason, episode):
    log_event(args.log_jsonl, {
        "event": "learn_hold",
        "reason": reason,
        "episode": episode,
        "send_to_stm32": False,
        "motion_enabled": False,
        "actuator_control_allowed": False,
    })
    if not args.feedback_manual:
        return "quit"
    print("HOLD=%s; press SPACE for new round or q to quit." % reason, flush=True)
    while True:
        token = _read_feedback_token(args.feedback_file, 0)
        if token == "q":
            save_policy(args.learn_policy_file, policy)
            return "quit"
        if token == "r":
            return "restart"
        if token in ["+", "-", "0"]:
            print("  ignored feedback '%s' while holding; use SPACE or q." % token, flush=True)


def run_learn_policy(args):
    armed = args.arm and (args.dry_run or os.path.exists(args.arm_file))
    actions = parse_policy_actions(args.learn_actions, args.learn_max_command_abs_d_cm)
    policy = load_policy(args.learn_policy_file, actions)
    if not args.dry_run:
        serial_setup()
        st = read_stat()
        print("  STM32: %s" % st["raw"], flush=True)

    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.setblocking(False)
    sock.bind((args.listen_host, args.listen_port))
    print("=== PARKING POLICY LEARNER ===", flush=True)
    print("  dry_run=%s arm=%s arm_file=%s(%s)" % (
        args.dry_run, args.arm, args.arm_file, os.path.exists(args.arm_file)), flush=True)
    print("  actions=%d epsilon=%.2f alpha=%.2f policy=%s" % (
        len(actions), args.learn_epsilon, args.learn_alpha, args.learn_policy_file), flush=True)
    print("  feedback: right=+ left=- space=restart q=quit via %s" % args.feedback_file, flush=True)

    total_cm = 0.0
    bad_streak = 0
    rollout = int(policy.get("rollouts", 0)) + 1
    episode = 1
    try:
        while args.learn_episodes <= 0 or episode <= args.learn_episodes:
            pre = collect_stable_plan(sock, args, args.feedback_vision_timeout_sec)
            if pre is None or not pre[0]:
                print("STOP=NO_STABLE_PRE_VISION episode=%d" % episode, flush=True)
                log_event(args.log_jsonl, {"event": "learn_stop", "reason": "no_stable_pre_vision",
                                           "episode": episode})
                if not args.dry_run:
                    stop()
                action = wait_restart_or_quit(args, policy, "NO_STABLE_PRE_VISION", episode)
                if action == "restart":
                    total_cm = 0.0
                    bad_streak = 0
                    rollout += 1
                    policy["rollouts"] = rollout
                    save_policy(args.learn_policy_file, policy)
                    continue
                return 6
            _stable, pre_fused, pre_metrics = pre
            pre_p = pre_fused["plan"]
            state_key = policy_state_key(pre_p)
            cmd, choose_reason = choose_policy_action(policy, state_key, actions, args.learn_epsilon)

            print("R%03d EP%04d %s PRE lon=%.2f lat=%.2f head=%.2f -> %s (%s)" % (
                rollout, episode, state_key, pre_p["lon"], pre_p["lat"], pre_p["head"], cmd, choose_reason), flush=True)
            log_event(args.log_jsonl, {
                "event": "learn_pre",
                "rollout": rollout,
                "episode": episode,
                "state_key": state_key,
                "choice": choose_reason,
                "dry_run": args.dry_run,
                "stability": pre_metrics,
                "confidence": round(pre_fused["confidence"], 4),
                "lon": round(pre_p["lon"], 3),
                "lat": round(pre_p["lat"], 3),
                "head": round(pre_p["head"], 3),
                "candidate_cmd": cmd,
                "send_to_stm32": False if args.dry_run else bool(armed and cmd != "STOP"),
                "motion_enabled": False if args.dry_run else bool(armed and cmd != "STOP"),
                "actuator_control_allowed": False if args.dry_run else bool(armed and cmd != "STOP"),
            })

            if cmd == "STOP":
                if not args.dry_run:
                    stop()
            elif args.dry_run:
                print("  [dry-run] would send: %s" % cmd, flush=True)
            else:
                if not armed:
                    print("REFUSING MOTION: learn-policy needs --arm and arm file.", flush=True)
                    stop()
                    return 4
                send_motion(cmd, args, read_sec=args.move_read_sec, reason="learn_policy_step")
                stop()
                # Use commanded distance as the conservative training cap.
                for part in cmd.split():
                    if part.startswith("D="):
                        total_cm += abs(float(part.split("=", 1)[1]))
                        break

            time.sleep(args.feedback_post_settle_sec)
            post = collect_stable_plan(sock, args, args.feedback_vision_timeout_sec)
            if post is None or not post[0]:
                print("STOP=NO_STABLE_POST_VISION episode=%d" % episode, flush=True)
                log_event(args.log_jsonl, {"event": "learn_stop", "reason": "no_stable_post_vision",
                                           "episode": episode})
                if not args.dry_run:
                    stop()
                action = wait_restart_or_quit(args, policy, "NO_STABLE_POST_VISION", episode)
                if action == "restart":
                    total_cm = 0.0
                    bad_streak = 0
                    rollout += 1
                    policy["rollouts"] = rollout
                    save_policy(args.learn_policy_file, policy)
                    continue
                return 7
            _stable, post_fused, post_metrics = post
            post_p = post_fused["plan"]
            auto_reward, auto_metrics = _auto_feedback(pre_p, post_p, args.feedback_min_lat_improve_cm)

            token = ""
            if args.feedback_manual:
                token = _read_feedback_token(args.feedback_file, args.feedback_timeout_sec)
            if token == "q":
                print("STOP=USER_QUIT", flush=True)
                if not args.dry_run:
                    stop()
                save_policy(args.learn_policy_file, policy)
                return 0
            if token == "r":
                policy["episodes"] = int(policy.get("episodes", 0)) + 1
                policy["rollouts"] = rollout + 1
                save_policy(args.learn_policy_file, policy)
                print("RESTART=NEW_ROUND requested", flush=True)
                total_cm = 0.0
                bad_streak = 0
                rollout += 1
                episode += 1
                continue

            reward, reward_source = reward_from_token(token, auto_reward if args.feedback_auto else 0.0)
            if reward < 0:
                bad_streak += 1
            else:
                bad_streak = 0
            old_q, new_q, count = update_policy(policy, state_key, cmd, reward, args.learn_alpha)
            policy["episodes"] = int(policy.get("episodes", 0)) + 1
            save_policy(args.learn_policy_file, policy)

            print("EP%03d POST lon=%.2f lat=%.2f head=%.2f reward=%.1f %s q %.2f->%.2f delta=%s" % (
                episode, post_p["lon"], post_p["lat"], post_p["head"], reward, reward_source,
                old_q, new_q, json.dumps(auto_metrics, separators=(",", ":"))), flush=True)
            log_event(args.log_jsonl, {
                "event": "learn_post",
                "rollout": rollout,
                "episode": episode,
                "state_key": state_key,
                "dry_run": args.dry_run,
                "stability": post_metrics,
                "confidence": round(post_fused["confidence"], 4),
                "lon": round(post_p["lon"], 3),
                "lat": round(post_p["lat"], 3),
                "head": round(post_p["head"], 3),
                "candidate_cmd": cmd,
                "reward": reward,
                "reward_source": reward_source,
                "auto_metrics": auto_metrics,
                "q_old": round(old_q, 4),
                "q_new": round(new_q, 4),
                "count": count,
                "send_to_stm32": False,
                "motion_enabled": False if args.dry_run else bool(armed),
                "actuator_control_allowed": False if args.dry_run else bool(armed),
            })

            if args.learn_stop_after_bad > 0 and bad_streak >= args.learn_stop_after_bad:
                print("STOP=NEGATIVE_STREAK %d" % bad_streak, flush=True)
                if not args.dry_run:
                    stop()
                action = wait_restart_or_quit(args, policy, "NEGATIVE_STREAK", episode)
                if action == "restart":
                    total_cm = 0.0
                    bad_streak = 0
                    rollout += 1
                    policy["rollouts"] = rollout
                    save_policy(args.learn_policy_file, policy)
                    episode += 1
                    continue
                return 8
            if args.learn_max_total_cm > 0 and total_cm >= args.learn_max_total_cm:
                print("STOP=LEARN_TOTAL_CAP total_cm=%.1f" % total_cm, flush=True)
                if not args.dry_run:
                    stop()
                action = wait_restart_or_quit(args, policy, "LEARN_TOTAL_CAP", episode)
                if action == "restart":
                    total_cm = 0.0
                    bad_streak = 0
                    rollout += 1
                    policy["rollouts"] = rollout
                    save_policy(args.learn_policy_file, policy)
                    episode += 1
                    continue
                return 0
            if abs(post_p["lat"]) <= args.feedback_success_lat_cm and post_p["lon"] <= args.feedback_success_lon_cm:
                print("STOP=LEARN_SUCCESS lon=%.2f lat=%.2f" % (post_p["lon"], post_p["lat"]), flush=True)
                if not args.dry_run:
                    stop()
                action = wait_restart_or_quit(args, policy, "LEARN_SUCCESS", episode)
                if action == "restart":
                    total_cm = 0.0
                    bad_streak = 0
                    rollout += 1
                    policy["rollouts"] = rollout
                    save_policy(args.learn_policy_file, policy)
                    episode += 1
                    continue
                return 0
            episode += 1

        print("STOP=LEARN_EPISODES_DONE", flush=True)
        if not args.dry_run:
            stop()
        return 0
    except KeyboardInterrupt:
        print("\nABORT (Ctrl-C) -> STOP", flush=True)
        if not args.dry_run:
            stop()
        save_policy(args.learn_policy_file, policy)
        return 130


def run_feedback_tune(args):
    armed = args.arm and (args.dry_run or os.path.exists(args.arm_file))
    if not args.dry_run:
        serial_setup()
        st = read_stat()
        print("  STM32: %s" % st["raw"], flush=True)

    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.setblocking(False)
    sock.bind((args.listen_host, args.listen_port))
    print("=== PARKING FEEDBACK TUNER ===", flush=True)
    print("  dry_run=%s arm=%s arm_file=%s(%s)" % (
        args.dry_run, args.arm, args.arm_file, os.path.exists(args.arm_file)), flush=True)
    print("  episodes=%d step_cm=%.1f steer_deg=%.1f lateral_sign=%.1f" % (
        args.feedback_episodes, args.feedback_step_cm, args.feedback_steer_deg,
        args.feedback_lateral_sign), flush=True)
    print("  safety: per-step STOP=%s max_step_cm=%.1f" % (True, args.feedback_max_step_cm), flush=True)

    step_cm = min(args.feedback_step_cm, args.feedback_max_step_cm)
    steer_deg = args.feedback_steer_deg
    lateral_sign = args.feedback_lateral_sign
    bad_streak = 0
    total_cm = 0.0

    try:
        for episode in range(1, args.feedback_episodes + 1):
            pre = collect_stable_plan(sock, args, args.feedback_vision_timeout_sec)
            if pre is None or not pre[0]:
                print("STOP=NO_STABLE_PRE_VISION episode=%d" % episode, flush=True)
                log_event(args.log_jsonl, {"event": "feedback_stop", "reason": "no_stable_pre_vision",
                                           "episode": episode})
                if not args.dry_run:
                    stop()
                return 6

            _stable, pre_fused, pre_metrics = pre
            pre_p = pre_fused["plan"]
            action = _cmd_from_plan_with_policy(
                pre_p, step_cm, steer_deg, lateral_sign, args.feedback_max_command_abs_d_cm)
            cmd = action["cmd"]
            print("EP%02d PRE lon=%.2f lat=%.2f head=%.2f -> %s" % (
                episode, pre_p["lon"], pre_p["lat"], pre_p["head"], cmd), flush=True)

            log_event(args.log_jsonl, {
                "event": "feedback_pre",
                "episode": episode,
                "dry_run": args.dry_run,
                "stable": True,
                "stability": pre_metrics,
                "confidence": round(pre_fused["confidence"], 4),
                "lon": round(pre_p["lon"], 3),
                "lat": round(pre_p["lat"], 3),
                "head": round(pre_p["head"], 3),
                "candidate_cmd": cmd,
                "step_cm": round(step_cm, 3),
                "steer_deg": round(steer_deg, 3),
                "lateral_sign": lateral_sign,
                "send_to_stm32": False if args.dry_run else bool(armed),
                "motion_enabled": False if args.dry_run else bool(armed),
                "actuator_control_allowed": False if args.dry_run else bool(armed),
            })

            if args.dry_run:
                print("  [dry-run] would send: %s" % cmd, flush=True)
            else:
                if not armed:
                    print("REFUSING MOTION: feedback tuner needs --arm and arm file.", flush=True)
                    stop()
                    return 4
                send_motion(cmd, args, read_sec=args.move_read_sec, reason="feedback_tune_step")
                stop()
                total_cm += action["step"]

            time.sleep(args.feedback_post_settle_sec)
            post = collect_stable_plan(sock, args, args.feedback_vision_timeout_sec)
            if post is None or not post[0]:
                print("STOP=NO_STABLE_POST_VISION episode=%d" % episode, flush=True)
                log_event(args.log_jsonl, {"event": "feedback_stop", "reason": "no_stable_post_vision",
                                           "episode": episode})
                if not args.dry_run:
                    stop()
                return 7

            _stable, post_fused, post_metrics = post
            post_p = post_fused["plan"]
            auto_reward, auto_metrics = _auto_feedback(pre_p, post_p, args.feedback_min_lat_improve_cm)
            token = ""
            if args.feedback_manual and not args.dry_run:
                token = _read_feedback_token(args.feedback_file, args.feedback_timeout_sec)
            if token == "q":
                print("STOP=USER_QUIT", flush=True)
                if not args.dry_run:
                    stop()
                return 0
            if token == "+":
                reward = 1
                source = "manual_positive"
            elif token == "-":
                reward = -1
                source = "manual_negative"
            elif token == "0":
                reward = 0
                source = "manual_neutral"
            else:
                reward = auto_reward if args.feedback_auto else 0
                source = "auto" if args.feedback_auto else "none"

            print("EP%02d POST lon=%.2f lat=%.2f head=%.2f reward=%s source=%s delta=%s" % (
                episode, post_p["lon"], post_p["lat"], post_p["head"], reward, source,
                json.dumps(auto_metrics, separators=(",", ":"))), flush=True)

            if reward > 0:
                bad_streak = 0
                step_cm = min(args.feedback_max_step_cm, step_cm + args.feedback_step_increment_cm)
                if abs(post_p["lat"]) < abs(pre_p["lat"]):
                    steer_deg = max(args.feedback_min_steer_deg, steer_deg - args.feedback_steer_increment_deg)
            elif reward < 0:
                bad_streak += 1
                step_cm = max(args.feedback_min_step_cm, step_cm * 0.6)
                steer_deg = min(args.feedback_max_steer_deg, steer_deg + args.feedback_steer_increment_deg)
                if bad_streak >= args.feedback_flip_after_bad:
                    lateral_sign *= -1.0
                    bad_streak = 0

            log_event(args.log_jsonl, {
                "event": "feedback_post",
                "episode": episode,
                "dry_run": args.dry_run,
                "stable": True,
                "stability": post_metrics,
                "confidence": round(post_fused["confidence"], 4),
                "lon": round(post_p["lon"], 3),
                "lat": round(post_p["lat"], 3),
                "head": round(post_p["head"], 3),
                "reward": reward,
                "reward_source": source,
                "auto_metrics": auto_metrics,
                "next_step_cm": round(step_cm, 3),
                "next_steer_deg": round(steer_deg, 3),
                "next_lateral_sign": lateral_sign,
                "send_to_stm32": False,
                "motion_enabled": False if args.dry_run else bool(armed),
                "actuator_control_allowed": False if args.dry_run else bool(armed),
            })

            if abs(post_p["lat"]) <= args.feedback_success_lat_cm and post_p["lon"] <= args.feedback_success_lon_cm:
                print("STOP=FEEDBACK_SUCCESS lon=%.2f lat=%.2f" % (post_p["lon"], post_p["lat"]), flush=True)
                if not args.dry_run:
                    stop()
                return 0
            if total_cm >= args.feedback_max_total_cm:
                print("STOP=FEEDBACK_TOTAL_CAP total_cm=%.1f" % total_cm, flush=True)
                if not args.dry_run:
                    stop()
                return 0

        print("STOP=FEEDBACK_EPISODES_DONE", flush=True)
        if not args.dry_run:
            stop()
        return 0
    except KeyboardInterrupt:
        print("\nABORT (Ctrl-C) -> STOP", flush=True)
        if not args.dry_run:
            stop()
        return 130


# ============================ control loop ============================

def acquire(sock, wait_sec):
    """Poll UDP up to wait_sec for a slot; tolerate dropouts. Returns (center_cm,axis_cm)|None."""
    end = time.time() + wait_sec
    while True:
        raw = recv_latest(sock)
        if raw is not None:
            slot = best_slot_from_udp(raw)
            if slot is not None:
                return slot
        if time.time() >= end:
            return None
        time.sleep(0.1)


def acquire_info(sock, wait_sec, selector=None):
    """Poll UDP up to wait_sec for structured slot info."""
    end = time.time() + wait_sec
    last_selection = None
    while True:
        raw = recv_latest(sock)
        if raw is not None:
            if selector is not None:
                info, selection = selector.select(raw)
                last_selection = selection
            else:
                info = best_slot_info_from_udp(raw, DEFAULT_SLOT_CLASS_NAMES)
                selection = None
            if info is not None:
                if selection is not None:
                    info["target_selection"] = selection
                return info
        if time.time() >= end:
            if last_selection is not None:
                if last_selection.get("status") == "no_candidates":
                    return None
                return {"target_selection_wait": last_selection}
            return None
        time.sleep(0.1)


def drain_udp_frames_for(sock, duration_sec):
    """Drop queued/peri-motion UDP frames and return a small drain summary."""
    deadline = time.time() + max(0.0, float(duration_sec))
    latest = None
    batches = 0
    while time.time() < deadline:
        raw = recv_latest(sock)
        if raw is not None:
            latest = raw
            batches += 1
        else:
            time.sleep(0.02)
    return {
        "duration_sec": round(max(0.0, float(duration_sec)), 3),
        "batches": batches,
        "had_frame": latest is not None,
    }


def post_motion_perception_reset(sock, filt, target_selector, args, reason):
    """Force the next decision to be based on fresh stable post-motion vision."""
    settle = args.post_motion_observe_settle_sec
    if settle < 0.0:
        settle = args.settle_sec
    if settle > 0.0:
        time.sleep(settle)
    drain = drain_udp_frames_for(sock, args.post_motion_frame_flush_sec)
    filt.reset(preserve_post_motion_guard=True)
    target_selector_reset = False
    if target_selector is not None:
        target_selector.reset()
        target_selector_reset = True
    event = {
        "event": "post_motion_perception_reset",
        "reason": reason,
        "settle_sec": round(settle, 3),
        "drain": drain,
        "stability_filter_reset": True,
        "post_motion_guard_preserved": True,
        "target_selector_reset": target_selector_reset,
        "send_to_stm32": False,
        "motion_enabled": False,
        "actuator_control_allowed": False,
    }
    log_event(args.log_jsonl, event)
    return event


def _line_accum_safe_fields(event):
    event = dict(event)
    event.setdefault("send_to_stm32", False)
    event.setdefault("motion_enabled", False)
    event.setdefault("actuator_control_allowed", False)
    return event


def _line_accum_log(args, event):
    log_event(getattr(args, "log_jsonl", ""), _line_accum_safe_fields(event))


def _line_accum_effective_config(args, perception_filter):
    raw = perception_filter.get("line_accumulator") or {}
    if merged_line_accumulator_config is not None:
        cfg = merged_line_accumulator_config(raw)
    else:
        cfg = dict(raw)
    cfg["enabled"] = bool(cfg.get("enabled", False) or getattr(args, "slot_line_accum_enable", False))
    cfg["use_for_planning"] = bool(
        cfg.get("use_for_planning", False) or getattr(args, "slot_line_accum_use_for_planning", False))
    cfg["motion_capture"] = bool(
        cfg.get("motion_capture", False) or getattr(args, "slot_line_accum_motion_capture", False))
    if LINE_ACCUMULATOR_DISABLED_BY_POLICY:
        cfg["requested_enabled"] = bool(cfg.get("enabled"))
        cfg["requested_use_for_planning"] = bool(cfg.get("use_for_planning"))
        cfg["requested_motion_capture"] = bool(cfg.get("motion_capture"))
        cfg["enabled"] = False
        cfg["use_for_planning"] = False
        cfg["motion_capture"] = False
        cfg["disabled_by_policy"] = True
        cfg["disable_reason"] = "slot_line_accumulator_algorithms_disabled"
    return cfg


def _make_line_accumulator(args, perception_filter):
    cfg = _line_accum_effective_config(args, perception_filter)
    args._slot_line_accum_config = cfg
    args._slot_line_accum_enabled = bool(cfg.get("enabled"))
    args._slot_line_accum_use_for_planning = bool(cfg.get("enabled") and cfg.get("use_for_planning"))
    args._slot_line_accum_motion_capture = bool(cfg.get("enabled") and cfg.get("motion_capture"))
    if not args._slot_line_accum_enabled:
        if cfg.get("disabled_by_policy"):
            print("  slot_line_accumulator=DISABLED_BY_POLICY requested_enabled=%s "
                  "requested_use_for_planning=%s requested_motion_capture=%s" % (
                      cfg.get("requested_enabled"),
                      cfg.get("requested_use_for_planning"),
                      cfg.get("requested_motion_capture"),
                  ), flush=True)
            _line_accum_log(args, {
                "event": "line_accumulator_disabled_by_policy",
                "config": cfg,
                "reason": cfg.get("disable_reason"),
            })
        return None, None
    if MotionCompensatedSlotLineAccumulator is None or LineAccumulatorPoseTracker is None:
        print("WARN: slot line accumulator requested but parking_line_accumulator.py is unavailable.",
              file=sys.stderr, flush=True)
        args._slot_line_accum_enabled = False
        args._slot_line_accum_use_for_planning = False
        args._slot_line_accum_motion_capture = False
        return None, None
    accum = MotionCompensatedSlotLineAccumulator(cfg, pixel_to_ground_h=H)
    pose_tracker = LineAccumulatorPoseTracker.from_chassis_signs(getattr(args, "_fusion_signs", None))
    return accum, pose_tracker


def apply_lattice_safety_profile_runtime_defaults(args):
    """Apply small-car fast-loop defaults after argparse parsing."""
    profile = str(getattr(args, "lattice_safety_profile", "standard") or "standard").strip().lower()
    if profile not in FAST_LATTICE_PROFILES:
        return
    if getattr(args, "replanner_vision_lost_stop_sec", 3.0) == 3.0:
        args.replanner_vision_lost_stop_sec = 0.4
    if getattr(args, "vision_reacquire_recovery_max_attempts", 1) == 1:
        args.vision_reacquire_recovery_max_attempts = 2
    if getattr(args, "vision_reacquire_recovery_command_cm", 3.0) == 3.0:
        args.vision_reacquire_recovery_command_cm = 2.0
    if getattr(args, "vision_reacquire_recovery_max_last_step_cm", 3.5) == 3.5:
        args.vision_reacquire_recovery_max_last_step_cm = 2.5
    if getattr(args, "vision_reacquire_recovery_max_age_sec", 20.0) == 20.0:
        args.vision_reacquire_recovery_max_age_sec = 1800.0
    if getattr(args, "vision_reacquire_recovery_min_margin_px", 120.0) == 120.0:
        args.vision_reacquire_recovery_min_margin_px = 90.0
    if getattr(args, "vision_reacquire_recovery_min_confidence", 0.40) == 0.40:
        args.vision_reacquire_recovery_min_confidence = 0.35
    if getattr(args, "vision_reacquire_recovery_min_visible_ratio", 0.05) == 0.05:
        args.vision_reacquire_recovery_min_visible_ratio = 0.035
    if getattr(args, "vision_reacquire_recovery_min_pose_quality", 0.60) == 0.60:
        args.vision_reacquire_recovery_min_pose_quality = 0.40


def apply_diy_path_profile_runtime_defaults(args):
    """Apply opt-in DIY path profile defaults without changing baseline mode.

    The H1 fast10/clearance profiles are intentionally overlays on top of the
    existing H1 homography + sign + kinematics chain.  It only enables planner
    scoring/candidate-generation knobs that are safe to roll back by omitting
    ``--diy-path-profile h1_fast_10_clearance`` or the newer fullset profile.
    """
    profile = diy_path_profile_name(args)
    if profile not in (
        "h1_fast_10_clearance",
        "h1_fast10_clearance",
        "h1_fast10_fullset_clearance",
        "h1_fast_10_fullset_clearance",
        "h1_fast10_heading_debt",
        "h1_fast_10_heading_debt",
        "h1_lattice_mpc",
        "h1_fast10_lattice_mpc",
        "h1_measured_lattice_mpc",
        "h1_structured_phase_parking",
        "h1_structured_phase",
    ):
        return

    args.diy_path_fast10_enable = True
    args.diy_path_smooth_enable = True
    args.diy_path_clearance_enable = True
    if getattr(args, "diy_path_near_side_clearance_enable", None) is None:
        args.diy_path_near_side_clearance_enable = True
    args.diy_path_visual_correction_clamp_enable = True
    args.diy_path_suppress_margin_line_risk_stop = True
    # H1 uses the ground-plane slot pose solver and a high-quality dedicated
    # mask model.  The old quad-topology/entry-edge diagnostics are still
    # useful in logs, but should not hard-block a standard high-confidence
    # mask at initial lock.
    args.diy_path_initial_trust_standard_mask = True
    # Medium gate profile: keep the first lock robust, but avoid waiting
    # forever on legacy quad-topology/completeness diagnostics when the H1
    # ground solver is complete and stable.
    if getattr(args, "diy_path_initial_medium_gate_enable", None) is None:
        args.diy_path_initial_medium_gate_enable = True
    if getattr(args, "diy_path_initial_lock_frames", 10) == 10:
        args.diy_path_initial_lock_frames = 5
    if getattr(args, "diy_path_initial_lock_min_pass_frames", 5) in (5, 2):
        args.diy_path_initial_lock_min_pass_frames = 1
    if getattr(args, "diy_path_initial_lock_max_lateral_spread_cm", 6.0) == 6.0:
        args.diy_path_initial_lock_max_lateral_spread_cm = 25.0
    if getattr(args, "diy_path_initial_lock_max_heading_spread_deg", 8.0) == 8.0:
        args.diy_path_initial_lock_max_heading_spread_deg = 30.0
    if getattr(args, "diy_path_initial_lock_max_y_spread_cm", 8.0) == 8.0:
        args.diy_path_initial_lock_max_y_spread_cm = 30.0
    if getattr(args, "diy_path_initial_lock_static_recheck_max_lateral_delta_cm", 4.0) == 4.0:
        args.diy_path_initial_lock_static_recheck_max_lateral_delta_cm = 25.0
    if getattr(args, "diy_path_initial_lock_static_recheck_max_heading_delta_deg", 5.0) == 5.0:
        args.diy_path_initial_lock_static_recheck_max_heading_delta_deg = 30.0
    if getattr(args, "diy_path_initial_lock_static_recheck_max_y_delta_cm", 6.0) == 6.0:
        args.diy_path_initial_lock_static_recheck_max_y_delta_cm = 30.0
    if getattr(args, "diy_path_initial_h1_partial_mask_relax_confidence", 0.70) == 0.70:
        args.diy_path_initial_h1_partial_mask_relax_confidence = 0.35
    if getattr(args, "diy_path_initial_h1_partial_mask_relax_solver_quality", 0.55) == 0.55:
        args.diy_path_initial_h1_partial_mask_relax_solver_quality = 0.25
    if getattr(args, "diy_path_initial_max_abs_lateral_cm", 25.0) == 25.0:
        args.diy_path_initial_max_abs_lateral_cm = 35.0
    if getattr(args, "diy_path_lateral_only_min_confidence", 0.65) == 0.65:
        args.diy_path_lateral_only_min_confidence = 0.55
    if getattr(args, "diy_path_lateral_only_min_solver_quality", 0.65) == 0.65:
        args.diy_path_lateral_only_min_solver_quality = 0.55
    if getattr(args, "diy_path_lateral_only_max_visual_age_sec", 0.5) == 0.5:
        args.diy_path_lateral_only_max_visual_age_sec = 0.8
    if getattr(args, "diy_path_near_side_bias_cm", 2.5) == 2.5:
        args.diy_path_near_side_bias_cm = 2.5
    if getattr(args, "diy_path_near_side_min_clearance_cm", 2.5) == 2.5:
        args.diy_path_near_side_min_clearance_cm = 2.5
    if getattr(args, "diy_path_near_side_clearance_weight", 10.0) == 10.0:
        args.diy_path_near_side_clearance_weight = 10.0
    if getattr(args, "diy_path_near_side_early_scale", 1.5) == 1.5:
        args.diy_path_near_side_early_scale = 1.5
    if getattr(args, "diy_path_near_side_early_y_cm", 25.0) == 25.0:
        args.diy_path_near_side_early_y_cm = 25.0

    fast_stop_value = getattr(args, "diy_path_fast_stop_response_enable", None)
    fast_stop_enabled = (
        bool(diy_path_profile_is_h1_fast10(args)) if fast_stop_value is None
        else bool(fast_stop_value)
    )
    if fast_stop_enabled:
        # This only trims idle STOP/STAT/post-motion-observe waits.  It does
        # not change the chosen action, motion duration, odom/yaw integration,
        # safety guards, or candidate scoring.  Fresh perception is still
        # enforced by filter reset + post-motion guard; if a frame is not ready
        # the H1 path continues from odom instead of blocking on display waits.
        fast_post_settle = max(0.0, planner_to_float(
            getattr(args, "diy_path_fast_stop_post_motion_settle_sec", 0.05), 0.05))
        fast_flush = max(0.0, planner_to_float(
            getattr(args, "diy_path_fast_stop_frame_flush_sec", 0.15), 0.15))
        fast_target_wait = max(0.05, planner_to_float(
            getattr(args, "diy_path_fast_stop_target_wait_sec", 0.20), 0.20))
        fast_stat = max(0.05, planner_to_float(
            getattr(args, "diy_path_fast_stop_stat_read_sec", 0.25), 0.25))
        fast_stop_read = max(0.05, planner_to_float(
            getattr(args, "diy_path_fast_stop_stop_read_sec", 0.25), 0.25))
        fast_stop_idle = max(0.0, planner_to_float(
            getattr(args, "diy_path_fast_stop_stop_ack_idle_sec", 0.03), 0.03))
        current_post_settle = planner_to_float(
            getattr(args, "post_motion_observe_settle_sec", -1.0), -1.0)
        if current_post_settle < 0.0 or current_post_settle > fast_post_settle:
            args.post_motion_observe_settle_sec = fast_post_settle
        if planner_to_float(getattr(args, "post_motion_frame_flush_sec", 0.8), 0.8) > fast_flush:
            args.post_motion_frame_flush_sec = fast_flush
        if planner_to_float(getattr(args, "target_wait_sec", 6.0), 6.0) > fast_target_wait:
            args.target_wait_sec = fast_target_wait
        if planner_to_float(getattr(args, "stm32_stat_read_sec", 0.50), 0.50) > fast_stat:
            args.stm32_stat_read_sec = fast_stat
        if planner_to_float(getattr(args, "stm32_stop_read_sec", 0.50), 0.50) > fast_stop_read:
            args.stm32_stop_read_sec = fast_stop_read
        if planner_to_float(getattr(args, "stm32_stop_ack_idle_sec", 0.08), 0.08) > fast_stop_idle:
            args.stm32_stop_ack_idle_sec = fast_stop_idle

    if getattr(args, "diy_path_effective_target_y_cm", None) is None:
        # H1 lattice MPC 实车观测表明 y≈2.4cm 的深度更符合目标泊入
        # 位置；原 5cm 会过早认为深度已到位。只调整 H1 lattice 主线，
        # 其它 H1/baseline profile 保持原有深度目标。
        args.diy_path_effective_target_y_cm = (
            2.5 if diy_path_profile_is_h1_lattice_mpc(args) else 5.0
        )
    if getattr(args, "diy_path_success_lateral_tol_cm", None) is None:
        # H1 lattice 的 lateral 估计仍有少量系统误差；现场观测
        # raw lateral≈4.7cm 可接受，因此默认成功容差放到 5cm。
        args.diy_path_success_lateral_tol_cm = (
            5.0 if diy_path_profile_is_h1_lattice_mpc(args) else 3.5
        )
    if getattr(args, "diy_path_success_heading_tol_deg", None) is None:
        args.diy_path_success_heading_tol_deg = 6.0
    if getattr(args, "diy_path_bottom_depth_success_relax_enable", None) is None:
        args.diy_path_bottom_depth_success_relax_enable = True
    if getattr(args, "diy_path_bottom_depth_success_y_cm", 3.0) == 3.0:
        args.diy_path_bottom_depth_success_y_cm = 3.0
    if getattr(args, "diy_path_bottom_depth_success_heading_tol_deg", 10.0) == 10.0:
        args.diy_path_bottom_depth_success_heading_tol_deg = 10.0
    if getattr(args, "diy_path_success_max_visionless_steps", None) is None:
        args.diy_path_success_max_visionless_steps = 2
    if getattr(args, "diy_path_success_max_visual_odom_lateral_delta_cm", None) is None:
        args.diy_path_success_max_visual_odom_lateral_delta_cm = 6.0
    if getattr(args, "diy_path_success_max_visual_odom_y_delta_cm", None) is None:
        args.diy_path_success_max_visual_odom_y_delta_cm = 12.0

    # Keep the user-provided value if it was already tightened/expanded.  The
    # default 24-step horizon is unnecessarily wide for the fast10 profile and
    # makes logs harder to inspect, so reduce only the untouched default.
    if int(getattr(args, "diy_path_max_steps", 24)) == 24:
        args.diy_path_max_steps = 16 if diy_path_profile_is_h1_fullset(args) else 14

    # Replan slightly earlier under longer candidate distances, but do not
    # override explicit operator tuning.
    if getattr(args, "diy_path_replan_y_threshold_cm", 12.0) == 12.0:
        args.diy_path_replan_y_threshold_cm = 16.0

    if diy_path_profile_is_h1_fullset(args):
        args.diy_path_fullset_action_enable = True
        args.diy_path_runtime_kinematics_enable = True
        # The fullset profile is intended to keep moving and correcting rather
        # than stopping on the approximate body-envelope clearance model.  Keep
        # clearance as a soft scoring term, but make the hard block very loose:
        # the H1 visual/ground pose can carry large lateral bias during entry,
        # and a hard side-clearance gate at y≈35cm was prematurely stopping
        # otherwise recoverable runs.
        if getattr(args, "diy_path_side_clearance_target_cm", 2.5) == 2.5:
            args.diy_path_side_clearance_target_cm = 0.5
        if getattr(args, "diy_path_side_clearance_min_cm", 1.5) == 1.5:
            args.diy_path_side_clearance_min_cm = -8.0
        if getattr(args, "diy_path_side_clearance_weight", 8.0) == 8.0:
            args.diy_path_side_clearance_weight = 0.6
        if getattr(args, "diy_path_side_clearance_hard_block_cm", -0.5) == -0.5:
            args.diy_path_side_clearance_hard_block_cm = -18.0
        if getattr(args, "diy_path_clearance_hard_active_y_cm", 35.0) == 35.0:
            args.diy_path_clearance_hard_active_y_cm = 8.0
        if getattr(args, "diy_path_clearance_late_weight_scale", 1.5) == 1.5:
            args.diy_path_clearance_late_weight_scale = 1.0
        if getattr(args, "diy_path_clearance_long_step_weight_scale", 1.5) == 1.5:
            args.diy_path_clearance_long_step_weight_scale = 1.0
        if getattr(args, "diy_path_fast10_mid_y_threshold_cm", 20.0) == 20.0:
            args.diy_path_fast10_mid_y_threshold_cm = 15.0
        if getattr(args, "diy_path_fast10_final_y_window_cm", 7.0) == 7.0:
            # target_y defaults to 5cm, so a 10cm window makes final_stage
            # start at y<=15cm as requested for the fullset profile.
            args.diy_path_fast10_final_y_window_cm = 10.0
        if getattr(args, "diy_path_late_y_threshold_cm", 25.0) == 25.0:
            args.diy_path_late_y_threshold_cm = 15.0
        if getattr(args, "diy_path_distance_candidates_cm", DIY_PATH_DISTANCE_CANDIDATES_CM_DEFAULT) == DIY_PATH_DISTANCE_CANDIDATES_CM_DEFAULT:
            args.diy_path_distance_candidates_cm = "4.0,6.0,8.0"
        if getattr(args, "diy_path_late_distance_candidates_cm", DIY_PATH_LATE_DISTANCE_CANDIDATES_CM_DEFAULT) == DIY_PATH_LATE_DISTANCE_CANDIDATES_CM_DEFAULT:
            args.diy_path_late_distance_candidates_cm = "4.0,5.0"
        # Fullset replans after every executed short action.  Keep each
        # search shallow and compact so the board spends time moving/observing
        # instead of serializing a huge multi-step candidate tree.
        if int(getattr(args, "diy_path_fullset_plan_horizon", 5)) == 5:
            args.diy_path_fullset_plan_horizon = 5
        if int(getattr(args, "diy_path_fullset_beam_width", 10)) == 10:
            args.diy_path_fullset_beam_width = 10
        if int(getattr(args, "diy_path_fullset_log_layer_candidates", 4)) == 4:
            args.diy_path_fullset_log_layer_candidates = 4
        if getattr(args, "diy_path_fullset_heading_reward", 5.0) == 5.0:
            args.diy_path_fullset_heading_reward = 9.0
        if getattr(args, "diy_path_fullset_large_heading_weight_scale", 2.0) == 2.0:
            args.diy_path_fullset_large_heading_weight_scale = 2.5
        if getattr(args, "diy_path_fullset_large_heading_reward_scale", 2.0) == 2.0:
            args.diy_path_fullset_large_heading_reward_scale = 2.5
        if getattr(args, "diy_path_fullset_wrong_direction_penalty", 12.0) == 12.0:
            args.diy_path_fullset_wrong_direction_penalty = 24.0
        if getattr(args, "diy_path_correction_boost_bonus", 18.0) == 18.0:
            args.diy_path_correction_boost_bonus = 30.0
    if diy_path_profile_is_h1_structured_phase(args):
        # Structured phase profile: keep the proven H1 perception /
        # homography / odom-yaw execution stack, but make decision selection a
        # single explicit FSM stage at a time.  These defaults disable old
        # stacked decision-makers as active controllers for this profile.
        args.diy_path_fullset_action_enable = True
        args.diy_path_runtime_kinematics_enable = True
        args.diy_path_once_path_enable = False
        args.diy_path_s_curve_enable = False
        args.diy_path_lattice_mpc_enable = False
        args.diy_path_strong_heading_enable = False
        args.diy_path_final_strong_turn_enable = False
        args.diy_path_fast_eval_enable = False
        args.diy_path_compact_log = True
        args.diy_path_lateral_estimator_conservative_planning_enable = False
        if getattr(args, "diy_path_effective_target_y_cm", None) in (None, 5.0, 2.5):
            args.diy_path_effective_target_y_cm = 1.5
        if getattr(args, "diy_path_success_lateral_tol_cm", None) in (None, 3.5):
            args.diy_path_success_lateral_tol_cm = 4.0
        if getattr(args, "diy_path_success_heading_tol_deg", None) in (None, 6.0):
            args.diy_path_success_heading_tol_deg = 3.0
        if getattr(args, "diy_path_bottom_depth_success_y_cm", None) in (None, 3.0):
            args.diy_path_bottom_depth_success_y_cm = 2.0
        if getattr(args, "diy_path_terminal_shuffle_heading_trigger_deg", 8.0) == 8.0:
            args.diy_path_terminal_shuffle_heading_trigger_deg = 3.0
        if getattr(args, "diy_path_bottom_depth_success_heading_relax_cap_deg", None) is None:
            # line_follow 主链路的目标是“入库且车身基本摆正”。
            # 旧的底部阶段会把最终成功角度放宽到 10°，实车可出现
            # y/lateral 已到位但车身明显偏斜仍报成功。结构化 line_follow
            # 默认最多按基础成功角度 6° 判成功，超过则继续尝试摆正或由
            # 步数/里程保护收口。
            args.diy_path_bottom_depth_success_heading_relax_cap_deg = (
                args.diy_path_success_heading_tol_deg
            )
        if int(getattr(args, "diy_path_max_steps", 24)) in (14, 16, 24):
            args.diy_path_max_steps = 24
        if getattr(args, "diy_path_max_total_cm", 70.0) == 70.0:
            args.diy_path_max_total_cm = 90.0
        if getattr(args, "diy_path_fullset_main_ste_candidates", DIY_PATH_FULLSET_MAIN_STE_DEFAULT) == DIY_PATH_FULLSET_MAIN_STE_DEFAULT:
            args.diy_path_fullset_main_ste_candidates = "60,75,80,85,90,100,105,110,120,140"
        if getattr(args, "diy_path_fullset_extended_ste_candidates", DIY_PATH_FULLSET_EXTENDED_STE_DEFAULT) == DIY_PATH_FULLSET_EXTENDED_STE_DEFAULT:
            args.diy_path_fullset_extended_ste_candidates = "60,75,80,85,90,100,105,110,120,130,140"
        if getattr(args, "diy_path_lateral_motion_max_delta_cm", 2.0) == 2.0:
            # Do not let the old conservative 2cm clamp hide the difference
            # between strong and weak phase candidates.  The gain remains
            # active; only the hard per-step cap is removed for this profile.
            args.diy_path_lateral_motion_max_delta_cm = 0.0
        if getattr(args, "diy_path_fast_stop_response_enable", None) is None:
            args.diy_path_fast_stop_response_enable = True
        if str(getattr(args, "diy_path_structured_decision", "")).strip().lower() == "rollout_optimizer":
            if getattr(args, "diy_path_effective_target_y_cm", None) in (None, 5.0, 2.5):
                args.diy_path_effective_target_y_cm = 1.5
            if getattr(args, "diy_path_success_lateral_tol_cm", None) in (None, 3.5, 4.0):
                args.diy_path_success_lateral_tol_cm = 2.0
            if getattr(args, "diy_path_success_heading_tol_deg", None) in (None, 6.0, 3.0):
                args.diy_path_success_heading_tol_deg = 3.0
            if getattr(args, "diy_path_side_clearance_target_cm", 2.5) == 2.5:
                args.diy_path_side_clearance_target_cm = 3.0
            if getattr(args, "diy_path_side_clearance_min_cm", 1.5) == 1.5:
                args.diy_path_side_clearance_min_cm = 2.0
            if getattr(args, "diy_path_side_clearance_hard_block_cm", -0.5) == -0.5:
                args.diy_path_side_clearance_hard_block_cm = 1.0
            if getattr(args, "diy_path_side_clearance_weight", 8.0) == 8.0:
                args.diy_path_side_clearance_weight = 16.0
            if getattr(args, "diy_path_clearance_late_weight_scale", 1.5) == 1.5:
                args.diy_path_clearance_late_weight_scale = 1.6
            if getattr(args, "diy_path_clearance_long_step_weight_scale", 1.5) == 1.5:
                args.diy_path_clearance_long_step_weight_scale = 1.25
            if getattr(args, "diy_path_near_side_min_clearance_cm", 2.5) == 2.5:
                args.diy_path_near_side_min_clearance_cm = 3.0
            if getattr(args, "diy_path_near_side_clearance_weight", 10.0) == 10.0:
                args.diy_path_near_side_clearance_weight = 22.0
            if getattr(args, "diy_path_near_side_early_scale", 1.5) == 1.5:
                args.diy_path_near_side_early_scale = 1.3
            if getattr(args, "diy_path_rollout_optimizer_config_json", "") in ("", None):
                args.diy_path_rollout_optimizer_config_json = (
                    "/opt/parking/autopark/parking_rollout_optimizer_h1.json"
                )

    if diy_path_profile_is_h1_heading_debt(args):
        args.diy_path_strong_heading_enable = True
        args.diy_path_final_strong_turn_enable = True
        args.diy_path_fast_eval_enable = True
        args.diy_path_compact_log = True
        args.diy_path_visual_depth_floor_enable = True
        if int(getattr(args, "diy_path_max_steps", 24)) == 16:
            args.diy_path_max_steps = 24
        if getattr(args, "diy_path_visual_depth_floor_max_gap_cm", 6.0) == 6.0:
            args.diy_path_visual_depth_floor_max_gap_cm = 6.0
        if getattr(args, "diy_path_visual_depth_floor_min_confidence", 0.50) == 0.50:
            args.diy_path_visual_depth_floor_min_confidence = 0.50
        if getattr(args, "diy_path_fullset_plan_horizon", 5) == 5:
            args.diy_path_fullset_plan_horizon = 5
        if getattr(args, "diy_path_fullset_beam_width", 10) == 10:
            args.diy_path_fullset_beam_width = 10
        if getattr(args, "diy_path_strong_heading_enter_deg", 15.0) == 15.0:
            args.diy_path_strong_heading_enter_deg = 15.0
        if getattr(args, "diy_path_strong_heading_exit_deg", 12.0) == 12.0:
            args.diy_path_strong_heading_exit_deg = 12.0
        if getattr(args, "diy_path_strong_heading_hard_deg", 22.0) == 22.0:
            args.diy_path_strong_heading_hard_deg = 22.0
        if getattr(args, "diy_path_final_strong_turn_max_lateral_cm", 8.0) == 8.0:
            args.diy_path_final_strong_turn_max_lateral_cm = 25.0
        if getattr(args, "diy_path_heading_debt_weight_scale", 3.0) == 3.0:
            args.diy_path_heading_debt_weight_scale = 3.0
        if getattr(args, "diy_path_heading_debt_depth_scale", 0.3) == 0.3:
            args.diy_path_heading_debt_depth_scale = 0.3
        if getattr(args, "diy_path_heading_debt_progress_scale", 0.3) == 0.3:
            args.diy_path_heading_debt_progress_scale = 0.3
        if getattr(args, "diy_path_strong_heading_min_improve_deg", 3.0) == 3.0:
            args.diy_path_strong_heading_min_improve_deg = 3.0
        if getattr(args, "diy_path_strong_heading_window_steps", 2) == 2:
            args.diy_path_strong_heading_window_steps = 2

    if diy_path_profile_is_h1_lattice_mpc(args):
        # New mainline experiment: direct measured-action lattice MPC.  Keep
        # H1 safety, visual lock and short-action semantics, but remove the
        # once-path reference/deviation stop and avoid strong-heading filters
        # dominating action availability.
        args.diy_path_fullset_action_enable = True
        args.diy_path_runtime_kinematics_enable = True
        args.diy_path_once_path_enable = False
        args.diy_path_s_curve_enable = False
        args.diy_path_strong_heading_enable = False
        args.diy_path_final_strong_turn_enable = False
        args.diy_path_fast_eval_enable = True
        args.diy_path_compact_log = True
